const API = window.location.hostname === "localhost" ? "http://localhost:8000" : "";
const GITHUB_REPO = "CBL-AICM/MD.Piece";

// 本地時區的 YYYY-MM-DD — 解所有「今日比對」用 UTC slice 造成台灣早上 8 點前
// 打的卡會被歸到前一天 UTC、導致 UI 看不到的 bug（藥物 / KPI / sidebar 今日 badge）。
// timestamp 寫入 DB 仍走 toISOString()，UTC 才是正確的儲存格式。
// 純 'YYYY-MM-DD' 字串（後端純日期欄位、自選日期）原樣返回，不做時區轉換。
function _localDay(input) {
  var d;
  if (arguments.length === 0) {
    d = new Date();
  } else {
    if (input == null || input === "") return "";
    if (typeof input === "string") {
      if (/^\d{4}-\d{2}-\d{2}$/.test(input)) return input;
      d = new Date(input);
    } else if (input instanceof Date) {
      d = input;
    } else {
      return "";
    }
  }
  if (!d || isNaN(d.getTime())) return "";
  return d.getFullYear() + "-"
    + String(d.getMonth() + 1).padStart(2, "0") + "-"
    + String(d.getDate()).padStart(2, "0");
}

// ─── iOS / PWA 安裝偵測 ─────────────────────────────────────
// iOS Safari 在「語音輸入、Web Push、安裝流程」上的能力與其他瀏覽器差很多，
// 多處要分流；集中成兩個 helper 共用，避免各處各寫一套判斷（鐵則 7）。
function isIOS() {
  var ua = navigator.userAgent || "";
  // iPadOS 13+ 會自報成 Mac，靠觸控點數補判
  return /iPad|iPhone|iPod/.test(ua)
    || (navigator.platform === "MacIntel" && navigator.maxTouchPoints > 1);
}
function isStandalonePWA() {
  return window.navigator.standalone === true
    || (window.matchMedia && window.matchMedia("(display-mode: standalone)").matches);
}

// ─── 顯示模式（年長版 / 普通版）─────────────────────────────
// 'senior' = 大字體、寬按鈕、高對比；'standard' = 原本的精緻 UI
//
// 與 elder-mode.css 對齊：
//   html[data-mode="senior"] === html.elder-mode
//   localStorage 'mdpiece_mode' 與 'md.elderMode' 雙向同步
//   ?elder=1 query 強制開啟一次（不會覆寫使用者偏好除非顯式設定）

const ELDER_LS_KEY = 'md.elderMode';
const LEGACY_MODE_KEY = 'mdpiece_mode';

function _readElderPref() {
  // 新 key 優先；舊 key 作為 fallback
  const v = localStorage.getItem(ELDER_LS_KEY);
  if (v === '1' || v === 'true') return true;
  if (v === '0' || v === 'false') return false;
  return localStorage.getItem(LEGACY_MODE_KEY) === 'senior';
}

function _detectInitialElderMode() {
  // 啟動順序：?elder=1 > localStorage 偏好 > 預設 false
  try {
    const qs = new URLSearchParams(window.location.search);
    if (qs.get('elder') === '1') return true;
    if (qs.get('elder') === '0') return false;
  } catch (e) { /* ignore */ }
  return _readElderPref();
}

function getMode() {
  return _readElderPref() ? 'senior' : 'standard';
}

function setMode(mode) {
  const isElder = mode === 'senior';
  const m = isElder ? 'senior' : 'standard';
  // 雙向同步：新 key 與舊 key 都寫，方便其他既有程式碼讀取
  localStorage.setItem(ELDER_LS_KEY, isElder ? '1' : '0');
  localStorage.setItem(LEGACY_MODE_KEY, m);
  // 同時掛 data-mode（既有 CSS）與 .elder-mode（新 CSS）
  document.documentElement.setAttribute('data-mode', m);
  document.documentElement.classList.toggle('elder-mode', isElder);
  // 同步切換按鈕顯示（i18n 化：透過字典決定中/英文標籤）
  const t = (window.MDPiece_i18n && window.MDPiece_i18n.t) || ((k) => k);
  const labelKey = isElder ? 'mode.toNormal' : 'mode.toSenior';
  const fallback = isElder ? _T('app.c1.switchToNormal') : _T('app.c1.switchToSenior');
  document.querySelectorAll('[data-mode-toggle]').forEach(function (el) {
    // 新版按鈕（topbar 那顆 A+）自帶 icon DOM，不能把 textContent 整個寫掉，
    // 否則 icon 會消失；認 .ael-icon 來判定是不是自管 DOM 的按鈕。
    var ownsLabel = el.querySelector('.ael-icon');
    if (!ownsLabel) {
      el.textContent = window.MDPiece_i18n ? t(labelKey) : fallback;
    }
    el.setAttribute('aria-pressed', isElder ? 'true' : 'false');
  });
  // 廣播事件給其他元件（例如時間軸 Bento 需依模式調整 grid）
  try {
    window.dispatchEvent(new CustomEvent('mdpiece-elder-mode-change', {
      detail: { elder: isElder },
    }));
  } catch (e) { /* ignore on old browsers */ }
}

function toggleMode() {
  setMode(getMode() === 'senior' ? 'standard' : 'senior');
}

// alias — 比較直觀的英文名
function isElderMode() { return getMode() === 'senior'; }
function toggleElderMode() {
  toggleMode();
  // 第一次切換時顯示一個 toast，讓使用者知道「字真的變大了」
  _showElderModeHint(isElderMode());
}

function _showElderModeHint(turnedOn) {
  var prior = document.querySelector('.elder-mode-hint');
  if (prior) prior.remove();
  var hint = document.createElement('div');
  hint.className = 'elder-mode-hint';
  hint.textContent = turnedOn ? _T('app.c1.fontEnlarged') : _T('app.c1.fontRestored');
  document.body.appendChild(hint);
  setTimeout(function() { if (hint.parentNode) hint.remove(); }, 3000);
}

// ─── 照護模式（門診 / 住院）─────────────────────────────────
// 跟 'senior/standard' 是兩個正交的維度：
//   senior/standard = UI 大小（字級、按鈕）
//   outpatient/inpatient = 功能範圍（門診相關 / 住院相關）
// 住院模式會把 sidebar 收成只剩住院期間真正會用到的項目。

const INPATIENT_NAV_PAGES = [
  'admissions', 'medications', 'vitals', 'memo', 'reminders',
  'inpatientEdu', 'handover', 'medRecon', 'bedside', 'dischargePlan',
  'menstrual', 'sleep', 'settings', 'account'
];

function getCareMode() {
  return localStorage.getItem('mdpiece_care_mode') === 'inpatient' ? 'inpatient' : 'outpatient';
}

function setCareMode(mode) {
  const m = mode === 'inpatient' ? 'inpatient' : 'outpatient';
  localStorage.setItem('mdpiece_care_mode', m);
  applyCareMode();
  // 切到住院時若當前頁面在門診專屬清單裡，回首頁避免使用者卡在「看不到 nav 又出不來」
  if (m === 'inpatient' && _currentPageKey
      && _currentPageKey !== 'home'
      && INPATIENT_NAV_PAGES.indexOf(_currentPageKey) === -1) {
    if (typeof navigateTo === 'function') navigateTo('home', null);
  }
  // 重畫首頁好讓 chip 的 active 狀態跟著變
  if (_currentPageKey === 'home' && typeof showPage === 'function') showPage('home');
}

function applyCareMode() {
  document.documentElement.setAttribute('data-care-mode', getCareMode());
  // 底部 nav 隨 care mode 換一組 tabs（住院模式換成住院相關）
  if (typeof renderMobileTabbar === 'function') renderMobileTabbar();
}
applyCareMode();

// ─── 設計憲法 條 3 (客製化提醒語氣) ──────────────────────────────────────
// 「嚴肅」直白指令、「溫柔」鼓勵帶溫度、「極簡」省略所有修飾。
// 任何給病人看的 system message (todo / SOS / reminder) 都該過 reminderToneify()。
function getReminderTone() {
  try { return localStorage.getItem('mdpiece_reminder_tone') || 'warm'; } catch (e) { return 'warm'; }
}
function setReminderTone(tone) {
  if (['strict','warm','short'].indexOf(tone) === -1) tone = 'warm';
  try { localStorage.setItem('mdpiece_reminder_tone', tone); } catch (e) {}
  document.documentElement.setAttribute('data-reminder-tone', tone);
}
// 把短句依語氣改寫。傳入物件 { strict, warm, short }，分別是 3 種版本；
// 也支援單一字串 (各語氣套對應規則)。
function reminderToneify(input) {
  var tone = getReminderTone();
  if (input && typeof input === 'object' && !Array.isArray(input)) {
    return input[tone] || input.warm || input.strict || input.short || '';
  }
  var s = String(input || '');
  if (tone === 'strict') return s; // 原句通常已是直白指令
  if (tone === 'warm') {
    // 暖色修飾 — 加結尾語
    if (/[。！？]$/.test(s)) return s + ' ❤️';
    return s + '，慢慢來。';
  }
  // short — 砍掉「請」「記得」這類客氣詞，留動詞 + 名詞
  return s.replace(/^(請|記得|別忘了|趕快|麻煩|快點)/, '').replace(/[，。！]/g, '').trim();
}
// 啟動時就套用到 <html>，方便 CSS 依語氣調 chip 顏色等視覺
setReminderTone(getReminderTone());

// ─── 設計憲法 條 6 (家屬代理視角) ─────────────────────────────────────────
// 切到「我幫家人」時，所有新紀錄帶 proxy_for 標籤 + 頁首 banner 提醒目前是代理模式。
function getProxyFor() {
  try { return JSON.parse(localStorage.getItem('mdpiece_proxy_for') || 'null'); }
  catch (e) { return null; }
}
function setProxyFor(p) {
  if (!p) localStorage.removeItem('mdpiece_proxy_for');
  else localStorage.setItem('mdpiece_proxy_for', JSON.stringify(p));
  refreshProxyBanner();
}
function isProxyMode() { return !!getProxyFor(); }
function renderProxyToggle() {
  var p = getProxyFor();
  if (p && p.name) {
    return ''
      + '<div class="set-proxy-active">'
      +   '<span>' + _T('app.c1.helpingFor') + ' <strong>' + escapeHtml(p.name) + '</strong>' + (p.relation ? '（' + escapeHtml(p.relation) + '）' : '') + _T('app.c1.recordSuffix') + '</span>'
      +   '<button type="button" class="set-btn" onclick="onProxySwitch()">' + _T('app.c1.switchOrCancel') + '</button>'
      + '</div>';
  }
  return '<button type="button" class="set-btn" onclick="onProxySwitch()"><i data-lucide="user-plus" style="width:14px;height:14px"></i> ' + _T('app.c1.switchToProxy') + '</button>';
}
function onProxySwitch() {
  var cur = getProxyFor();
  if (cur) {
    if (confirm(_T('app.c1.confirmCancelProxy'))) {
      setProxyFor(null);
      if (typeof showToast === 'function') showToast(_T('app.c1.switchedBackToSelf'), 'success');
      if (typeof showPage === 'function') showPage('settings');
    }
    return;
  }
  var name = prompt(_T('app.c1.promptFamilyName'), '');
  if (!name || !name.trim()) return;
  var relation = prompt(_T('app.c1.promptRelation'), '');
  setProxyFor({ name: name.trim(), relation: (relation || '').trim() });
  if (typeof showToast === 'function') showToast(_Tf('app.c1.switchedToProxyMode', { name: name.trim() }), 'success');
  if (typeof showPage === 'function') showPage('settings');
}
function renderProxyBanner() {
  // 全 app 共用 — 永遠掛在 #app 上方，由 refreshProxyBanner 寫入內容
  return '<div class="proxy-banner" id="proxy-banner" hidden></div>';
}
function refreshProxyBanner() {
  var el = document.getElementById('proxy-banner');
  if (!el) return;
  var p = getProxyFor();
  if (!p) { el.hidden = true; el.innerHTML = ''; return; }
  el.hidden = false;
  el.innerHTML = ''
    + '<i data-lucide="users" style="width:14px;height:14px"></i>'
    + '<span>' + _T('app.c1.helpingFor') + ' <strong>' + escapeHtml(p.name) + '</strong>' + (p.relation ? '（' + escapeHtml(p.relation) + '）' : '') + _T('app.c1.proxyBannerNote') + '</span>'
    + '<button type="button" class="proxy-banner-switch" onclick="onProxySwitch()" aria-label="' + _T('app.d1.switchProxyTarget') + '">'
    +   '<i data-lucide="repeat" style="width:12px;height:12px"></i>'
    + '</button>';
  if (typeof lucide !== 'undefined') lucide.createIcons();
}

