// 手機版 demo 雙視角切換（給自己看 / 給醫師看）
function _mobilePvSwitchAud(which) {
  document.querySelectorAll('.aud-view').forEach(function(v) {
    v.classList.toggle('active', v.classList.contains('aud-' + which));
  });
  document.querySelectorAll('.audience-btn').forEach(function(b) {
    b.classList.toggle('active', b.dataset.aud === which);
  });
}

// ─── 診前報告 (Pre-consultation Report) ──────────────────────

var _previsitData = { checklist: null, report: null };

// 報告內容同步寫進桌機 pv-report-body 與手機「給醫師看」分頁。
// 沒這層 mirror，手機版點「立即產生診前報告」後醫師分頁不會更新（內容只長在
// desktop-only 的隱藏區塊），看起來像毫無反應。
function _pvSetReportHtml(html) {
  var bodyEl = document.getElementById('pv-report-body');
  var mobEl = document.getElementById('mobile-pv-doctor');
  if (bodyEl) bodyEl.innerHTML = html;
  if (mobEl) mobEl.innerHTML = html;
}

function loadPrevisitPage() {
  if (typeof lucide !== 'undefined') lucide.createIcons();
  var pid = (typeof getStablePatientId === 'function') ? getStablePatientId() : null;
  if (!pid) return;

  _previsitData = { checklist: null, report: null };

  // 載入 Timeline（本地症狀 + 雲端情緒，合併時序）
  refreshPvTimeline(pid);

  fetch(API + '/reports/' + encodeURIComponent(pid) + '/checklist')
    .then(function(r) { return r.json(); })
    .then(function(data) {
      _previsitData.checklist = data;
      previsitRenderChecklist(data);
    })
    .catch(function() {
      previsitRenderChecklistError();
    });

  var days = (typeof getReportDays === 'function') ? getReportDays() : 30;
  previsitStreamReport(pid, days);
}

// 用 SSE 串流接整合摘要 — 一個字一個字長出來，回答「到底有沒有內容」的疑問。
// 串流接不通（HTTP 錯誤、瀏覽器不支援 ReadableStream）就退回 /monthly 非串流端點。
function previsitStreamReport(pid, days) {
  var statsEl = document.getElementById('pv-stats');
  var srcEl = document.getElementById('pv-report-source');

  var url = API + '/reports/' + encodeURIComponent(pid) + '/integrated-summary/stream?days=' + days;

  // 初始 loading 文字 — 等收到第一個 chunk 才換成實際內容
  _pvSetReportHtml('<p class="pv-loading"><i data-lucide="loader" class="pv-spin"></i> ' + _T("app.c3.writingDetail") + '</p>');
  if (srcEl) srcEl.textContent = _T("app.c3.connecting");
  if (typeof lucide !== 'undefined') lucide.createIcons();

  // 串流期間累積的內容 — 也同時寫進 _previsitData.report，PDF 下載走另一條路不受影響
  var buffer = '';
  var meta = null;
  var gotAny = false;

  if (!window.fetch || !window.ReadableStream) {
    previsitFallbackToMonthly(pid, days);
    return;
  }

  fetch(url, { headers: { 'Accept': 'text/event-stream' } })
    .then(function(resp) {
      if (!resp.ok || !resp.body) throw new Error('stream not available: HTTP ' + resp.status);
      var reader = resp.body.getReader();
      var decoder = new TextDecoder('utf-8');
      var sseBuffer = '';

      function handleEvent(line) {
        if (!line.startsWith('data:')) return;
        var payload;
        try { payload = JSON.parse(line.slice(line.indexOf(':') + 1).trim()); }
        catch (e) { return; }

        if (payload.type === 'meta') {
          meta = payload;
          _previsitData.report = {
            patient_id: pid,
            report: '',
            raw_data: payload.raw_data || {},
            raw_records: payload.raw_records || {},
            period_label: payload.period_label || '',
            days: payload.days || days,
            source: 'streaming',
            generated_at: new Date().toISOString(),
          };
          previsitRenderStats(statsEl, payload.raw_data || {});
          if (srcEl) srcEl.textContent = _T("app.c3.writingShort");
        } else if (payload.type === 'chunk') {
          gotAny = true;
          buffer += String(payload.text || '');
          if (_previsitData.report) _previsitData.report.report = buffer;
          _pvSetReportHtml(markdownToHtml(buffer));
        } else if (payload.type === 'done') {
          if (_previsitData.report) {
            _previsitData.report.source = payload.source || 'ai';
            _previsitData.report.generated_at = new Date().toISOString();
          }
          if (srcEl) srcEl.textContent = previsitSourceLabel(_previsitData.report);
          if (typeof lucide !== 'undefined') lucide.createIcons();
        } else if (payload.type === 'error') {
          var prefix = gotAny ? markdownToHtml(buffer) + '<hr>' : '';
          _pvSetReportHtml(prefix +
            '<p class="pv-error"><i data-lucide="alert-triangle"></i> ' + _T("app.c3.writeError") +
            escapeHtml(String(payload.detail || _T("app.c3.tryAgainLater"))) + '</p>');
          if (srcEl) srcEl.textContent = _T("app.c3.writeFailed");
          if (typeof lucide !== 'undefined') lucide.createIcons();
        }
      }

      function pump() {
        return reader.read().then(function(result) {
          if (result.done) {
            // 串到結尾還沒收到任何 chunk → 視為失敗，退回非串流
            if (!gotAny) previsitFallbackToMonthly(pid, days);
            return;
          }
          sseBuffer += decoder.decode(result.value, { stream: true });
          // SSE 用空行分隔事件；可能跨 chunk，保留最後不完整那段在 buffer 中
          var parts = sseBuffer.split('\n\n');
          sseBuffer = parts.pop() || '';
          parts.forEach(function(ev) {
            // 一個 event 可能含多行（例如 event: name + data: …）— 這支 backend 只送 data:
            ev.split('\n').forEach(handleEvent);
          });
          return pump();
        });
      }
      return pump();
    })
    .catch(function(err) {
      console.warn('previsit stream failed, falling back to /monthly:', err);
      previsitFallbackToMonthly(pid, days);
    });
}

function previsitRenderStats(statsEl, raw) {
  if (!statsEl) return;
  statsEl.innerHTML = ''
    + previsitStatCard('scan-search', _T("app.c3.symptom"), raw.symptom_count, _T("app.c3.unitEntries"))
    + previsitStatCard('smile', _T("app.c3.emotion"), raw.emotion_count, _T("app.c3.unitTimes"))
    + previsitStatCard('pill', _T("app.c3.medication"), raw.medication_count, _T("app.c3.unitKinds"))
    + previsitStatCard('stethoscope', _T("app.c3.visit"), raw.visit_count, _T("app.c3.unitTimes"));
  if (typeof lucide !== 'undefined') lucide.createIcons();
}

function previsitFallbackToMonthly(pid, days) {
  fetch(API + '/reports/' + encodeURIComponent(pid) + '/monthly?days=' + days)
    .then(function(r) { return r.json(); })
    .then(function(data) {
      _previsitData.report = data;
      previsitRenderReport(data);
    })
    .catch(function() {
      previsitRenderReportError();
    });
}

// 合併本地症狀 + 雲端情緒 → 編年事件列。
// 取最近 14 天、排序時間倒序、最多 6 筆，避免讓 previsit 頁面太長。
async function refreshPvTimeline(pid) {
  var el = document.getElementById('pv-timeline');
  if (!el) return;
  var events = [];
  var now = Date.now();
  var cutoff = now - 14 * 86400000;

  // 1. 本地症狀
  try {
    var syms = (typeof getSymptomEntries === 'function') ? getSymptomEntries() : [];
    syms.forEach(function(e) {
      var t = new Date(e.recordedAt).getTime();
      if (!t || t < cutoff) return;
      var cat = (typeof findSymptomCat === 'function') ? findSymptomCat(e.categoryId) : null;
      var catName = cat ? (cat.zh || cat.name || cat.id) : (e.categoryId || _T("app.c3.symptom"));
      var intensity = e.intensity ? (' · ' + e.intensity + '/10') : '';
      events.push({
        when: t,
        type: 'symptom',
        title: catName + intensity,
        desc: (e.notes || e.note || e.description || '').slice(0, 80) || _T("app.c3.noNote"),
        icon: 'scan-search',
      });
    });
  } catch (e) {}

  // 2. 雲端情緒（每日聚合）
  try {
    var em = await fetch(API + '/emotions/daily?patient_id=' + pid + '&days=14').then(function(r){return r.json();});
    (em.daily || []).forEach(function(d) {
      if (!d || !d.date) return;
      var t = new Date(d.date + 'T12:00:00').getTime();
      if (t < cutoff) return;
      var pct = (typeof _moodPercent === 'function') ? _moodPercent(d.average_score) : Math.round(d.average_score * 20);
      events.push({
        when: t,
        type: 'mood',
        title: _T("app.c3.moodBattery") + pct + '%',
        desc: _Tf("app.c3.dailyRecords", { n: (d.count || 1) }) + (d.note ? '：' + String(d.note).slice(0, 50) : ''),
        icon: 'battery-charging',
      });
    });
  } catch (e) {}

  // 3. 服藥（取最近一筆當代表，不要把每次打卡都列出來 — 太雜）
  //    只統計「實際吃了」的（taken !== false），跳過 / 沒吃不算在 N 次內，
  //    否則回診報告會把「只是漏掉」的日子當成「完成 N 次」呈現
  try {
    var ml = await apiFetch(API + '/medications/logs?patient_id=' + pid + '&days=14').then(function(r){return r.json();});
    var byDay = {};
    (ml.logs || []).forEach(function(l) {
      if (!l || !l.taken_at) return;
      if (l.taken === false) return;
      var dayKey = String(l.taken_at).slice(0, 10);
      byDay[dayKey] = (byDay[dayKey] || 0) + 1;
    });
    Object.keys(byDay).forEach(function(day) {
      var t = new Date(day + 'T08:00:00').getTime();
      if (t < cutoff) return;
      events.push({
        when: t,
        type: 'med',
        title: _Tf("app.c3.medRecords", { n: byDay[day] }),
        desc: _T("app.c3.checkinsBySlot"),
        icon: 'pill',
      });
    });
  } catch (e) {}

  events.sort(function(a, b) { return b.when - a.when; });
  events = events.slice(0, 8);

  if (!events.length) {
    el.innerHTML = '<p class="pv-empty">' + _T("app.c3.noRecords14d") + '</p>';
    return;
  }

  el.innerHTML = events.map(function(e) {
    var d = new Date(e.when);
    var pretty = (d.getMonth() + 1) + '/' + d.getDate();
    var hh = String(d.getHours()).padStart(2, '0');
    var mm = String(d.getMinutes()).padStart(2, '0');
    var wd = _T("app.c3.weekdays").split(',')[d.getDay()];
    return ''
      + '<article class="pv-tl-card" data-type="' + e.type + '">'
      +   '<div class="pv-tl-dot"></div>'
      +   '<div class="pv-tl-body">'
      +     '<div class="pv-tl-time">' + pretty + '（' + wd + '）' + hh + ':' + mm + '</div>'
      +     '<div class="pv-tl-title"><i data-lucide="' + e.icon + '" style="width:14px;height:14px"></i> ' + escapeHtml(e.title) + '</div>'
      +     '<div class="pv-tl-desc">' + escapeHtml(e.desc) + '</div>'
      +   '</div>'
      + '</article>';
  }).join('');
  if (typeof lucide !== 'undefined') lucide.createIcons();
}

function previsitRenderChecklist(data) {
  var listEl = document.getElementById('pv-checklist-list');
  var srcEl = document.getElementById('pv-checklist-source');
  if (!listEl) return;
  var items = (data && Array.isArray(data.checklist)) ? data.checklist : [];
  if (!items.length) {
    listEl.innerHTML = '<li class="pv-empty">' + _T("app.c3.notEnoughForChecklist") + '</li>';
  } else {
    listEl.innerHTML = items.map(function(text, i) {
      return '<li class="pv-check-item">'
        + '<span class="pv-check-num">' + (i + 1) + '</span>'
        + '<span class="pv-check-text">' + escapeHtml(text) + '</span>'
        + '</li>';
    }).join('');
  }
  if (srcEl) srcEl.textContent = previsitSourceLabel(data);

  // 同步注入手機版 demo 3 件事
  var mob = document.getElementById('mobile-pv-talk-3');
  if (mob) {
    if (!items.length) {
      mob.innerHTML = '<div class="pv-talk-row"><div class="pv-talk-num n1">·</div><div><div class="name">' + _T("app.c3.notEnoughRecords") + '</div><div class="sub">' + _T("app.c3.leaveRecordsHint") + '</div></div></div>';
    } else {
      mob.innerHTML = items.slice(0, 3).map(function(text, i) {
        var nCls = ['n1','n2','n3'][i] || 'n1';
        var short = (text || '').slice(0, 40);
        var rest = (text || '').slice(40);
        return '<div class="pv-talk-row">'
          + '<div class="pv-talk-num ' + nCls + '">' + (i+1) + '</div>'
          + '<div>'
          +   '<div class="name">「' + escapeHtml(short) + (rest ? '…' : '') + '」</div>'
          +   (rest ? '<div class="sub">' + escapeHtml(rest) + '</div>' : '')
          + '</div>'
          + '</div>';
      }).join('');
    }
  }
  if (typeof lucide !== 'undefined') lucide.createIcons();
}

function previsitRenderChecklistError() {
  var msg = _T("app.c4.backendUnavailable");
  var listEl = document.getElementById('pv-checklist-list');
  if (listEl) listEl.innerHTML = '<li class="pv-error"><i data-lucide="alert-triangle"></i> ' + msg + '</li>';
  // 手機患者分頁也要收尾，否則 previsitReload 設的 loading spinner 會一直轉（看似毫無反應）
  var mob = document.getElementById('mobile-pv-talk-3');
  if (mob) mob.innerHTML = '<div class="pv-talk-row"><div class="pv-talk-num n1"><i data-lucide="alert-triangle"></i></div><div><div class="name">' + msg + '</div></div></div>';
  if (typeof lucide !== 'undefined') lucide.createIcons();
}

function previsitRenderReport(data) {
  var bodyEl = document.getElementById('pv-report-body');
  var statsEl = document.getElementById('pv-stats');
  var srcEl = document.getElementById('pv-report-source');
  if (!bodyEl) return;

  var raw = (data && data.raw_data) || {};
  if (statsEl) {
    statsEl.innerHTML = ''
      + previsitStatCard('scan-search', _T("app.c4.statSymptom"), raw.symptom_count, _T("app.c4.unitEntries"))
      + previsitStatCard('smile', _T("app.c4.statEmotion"), raw.emotion_count, _T("app.c4.unitTimes"))
      + previsitStatCard('pill', _T("app.c4.statMedication"), raw.medication_count, _T("app.c4.unitKinds"))
      + previsitStatCard('stethoscope', _T("app.c4.statVisit"), raw.visit_count, _T("app.c4.unitTimes"));
  }

  var report = (data && data.report) || '';
  if (!report) {
    _pvSetReportHtml('<p class="pv-empty">' + _T("app.c4.noReportContent") + '</p>');
  } else {
    _pvSetReportHtml(markdownToHtml(report));
  }

  if (srcEl) srcEl.textContent = previsitSourceLabel(data);
  if (typeof lucide !== 'undefined') lucide.createIcons();
}

function previsitRenderReportError() {
  _pvSetReportHtml('<p class="pv-error"><i data-lucide="alert-triangle"></i> ' + _T("app.c4.backendUnavailable") + '</p>');
  if (typeof lucide !== 'undefined') lucide.createIcons();
}

function previsitStatCard(icon, label, value, unit) {
  var n = (value === undefined || value === null) ? 0 : value;
  return '<div class="pv-stat">'
    + '<span class="pv-stat-icon"><i data-lucide="' + icon + '"></i></span>'
    + '<div class="pv-stat-body">'
    +   '<div class="pv-stat-num">' + n + ' <small>' + unit + '</small></div>'
    +   '<div class="pv-stat-label">' + label + '</div>'
    + '</div>'
    + '</div>';
}

function previsitSourceLabel(data) {
  if (!data) return '';
  var src = data.source || '';
  var when = data.generated_at ? new Date(data.generated_at).toLocaleString() : '';
  var srcLabel = src === 'ai' ? _T("app.c4.srcAiGenerated")
    : src === 'default' ? _T("app.c4.srcDefault")
    : src === 'no_data' ? _T("app.c4.srcNoData")
    : src;
  return when ? (srcLabel + ' · ' + when) : srcLabel;
}

function previsitReload() {
  var listEl = document.getElementById('pv-checklist-list');
  var mobTalk = document.getElementById('mobile-pv-talk-3');
  if (listEl) listEl.innerHTML = '<li class="pv-loading"><i data-lucide="loader" class="pv-spin"></i> ' + _T("app.c4.organizing") + '</li>';
  if (mobTalk) mobTalk.innerHTML = '<div class="pv-talk-row"><div class="pv-talk-num n1"><i data-lucide="loader" class="pv-spin"></i></div><div><div class="name">' + _T("app.c4.organizing") + '</div></div></div>';
  _pvSetReportHtml('<p class="pv-loading"><i data-lucide="loader" class="pv-spin"></i> ' + _T("app.c4.writing") + '</p>');
  if (typeof lucide !== 'undefined') lucide.createIcons();
  loadPrevisitPage();
}

function previsitCopy() {
  var d = _previsitData || {};
  var days = (d.report && d.report.days) || ((typeof getReportDays === 'function') ? getReportDays() : 30);
  var lines = [];
  lines.push(_T("app.c4.copyHeader"));
  lines.push(_T("app.c4.copyGeneratedAt") + new Date().toLocaleString());
  lines.push('');
  lines.push(_T("app.c4.copyThreeThings"));
  var items = d.checklist && Array.isArray(d.checklist.checklist) ? d.checklist.checklist : [];
  if (items.length) {
    items.forEach(function(t, i) { lines.push((i + 1) + '. ' + t); });
  } else {
    lines.push(_T("app.c4.noDataParen"));
  }
  lines.push('');
  lines.push(_Tf("app.c4.copyHealthSummary", { days: days }));
  if (d.report && d.report.raw_data) {
    var r = d.report.raw_data;
    lines.push(_Tf("app.c4.copyCounts", { s: (r.symptom_count || 0), e: (r.emotion_count || 0), m: (r.medication_count || 0), v: (r.visit_count || 0) }));
    lines.push('');
  }
  lines.push((d.report && d.report.report) || _T("app.c4.noDataParen"));

  var text = lines.join('\n');
  if (navigator.clipboard && navigator.clipboard.writeText) {
    navigator.clipboard.writeText(text).then(function() {
      if (typeof showToast === 'function') showToast(_T("app.c4.copiedAnywhere"), 'success');
    }, function() {
      previsitFallbackCopy(text);
    });
  } else {
    previsitFallbackCopy(text);
  }
}

function previsitFallbackCopy(text) {
  var ta = document.createElement('textarea');
  ta.value = text;
  ta.style.position = 'fixed';
  ta.style.opacity = '0';
  document.body.appendChild(ta);
  ta.select();
  try { document.execCommand('copy'); } catch (e) {}
  document.body.removeChild(ta);
  if (typeof showToast === 'function') showToast(_T("app.c4.copied"), 'success');
}

// 固定免責聲明（兩版 PDF 結尾都印這段，不交給 LLM 生成）
var PREVISIT_DISCLAIMER_HTML = ''
