// ── v6 整合摘要 markdown 後處理 ────────────────────────────
//
// LLM 輸出的醫師版 markdown 含四段（一句話摘要 / 需注意事項·紅旗 / 關鍵指標趨勢 /
// 結構化摘要）與 inline tag 【紀錄】/【AI 摘要】，但 markdownToHtml 預設只渲染成普通
// h3 + 文字。這個函式把：
//   1. 【紀錄】/【AI 摘要】 inline 文字 → 有色 badge
//   2. 一句話摘要段（h3 起，吃到下一個 h3）→ 橘色醒目方塊 .highlights
//   3. 需注意事項 / 紅旗段（h3 起，吃到下一個 h3）→ 紅色方塊 .red-flags
// 失敗時（pattern 沒命中）原樣回傳，不阻塞 PDF 產出。

function previsitProcessIntegratedSummaryHTML(html) {
  if (!html || typeof html !== 'string') return html;

  // 1) 把【紀錄】/【AI 摘要】tag 轉成 badge
  html = html.replace(/【(紀錄|AI 摘要)】/g, function(_m, tag) {
    var cls = tag === '紀錄' ? 'badge-record' : 'badge-ai';
    return '<span class="' + cls + '">【' + tag + '】</span>';
  });

  // markdownToHtml 把「## 標題」渲染成 <h3>（非 <h2>），且 list 是裸 <li> 沒有 <ul> 外框。
  // 因此這裡以 <h3 ...>標題 為錨點，吃到下一個 <h3 或文件結尾，整段包起來。

  // 2) 一句話摘要 — 包進 .highlights 橘色方塊
  html = html.replace(
    /(<h3[^>]*>\s*一句話摘要[\s\S]*?)(?=<h3|$)/,
    '<div class="highlights">$1</div>'
  );

  // 3) 需注意事項 / 紅旗 — 包進 .red-flags 紅色方塊
  html = html.replace(
    /(<h3[^>]*>\s*需注意事項[\s\S]*?)(?=<h3|$)/,
    '<div class="red-flags">$1</div>'
  );

  return html;
}


// ── 本期間紀錄一覽 ────────────────────────────────────────────
// 從 backend raw_records（雲端紀錄）+ localStorage vitals 組出
// 完整的「醫師看了知道病人這段期間記了什麼」資料表。
// 此區塊純 JS／不過 LLM；醫師需要看到 raw data 而非只看 AI 摘要。

function _pvFmtDate(s) {
  if (!s) return '';
  return String(s).slice(0, 10);
}
function _pvFmtDateTime(s) {
  if (!s) return '';
  var v = String(s);
  if (v.length >= 16) return v.slice(0, 10) + ' ' + v.slice(11, 16);
  return v.slice(0, 10);
}

function _pvRecBlock(title, count, bodyHtml, emptyMsg) {
  var head = '<h3>' + escapeHtml(title)
    + (count != null ? '<span class="rec-count">' + _Tf("app.d6.countItems", { n: count }) + '</span>' : '')
    + '</h3>';
  if (!count) return head + '<div class="rec-empty">' + escapeHtml(emptyMsg || _T("app.c4.noRecordsThisPeriod")) + '</div>';
  return head + bodyHtml;
}

function _pvSymptomsTable(arr) {
  var rows = arr.map(function(s) {
    var syms = s.symptoms;
    if (Array.isArray(syms)) syms = syms.join('、');
    return '<tr><td>' + escapeHtml(_pvFmtDateTime(s.created_at)) + '</td>'
      + '<td>' + escapeHtml(syms || '') + '</td>'
      + '<td>' + escapeHtml(s.intensity != null ? String(s.intensity) : '') + '</td>'
      + '<td>' + escapeHtml(s.note || '') + '</td></tr>';
  }).join('');
  return '<table class="rec"><thead><tr><th>' + _T("app.c4.colTime") + '</th><th>' + _T("app.c4.colSymptom") + '</th><th>' + _T("app.c4.colIntensity") + '</th><th>' + _T("app.c4.colNote") + '</th></tr></thead><tbody>' + rows + '</tbody></table>';
}

function _pvEmotionsTable(arr) {
  var rows = arr.map(function(e) {
    return '<tr><td>' + escapeHtml(_pvFmtDateTime(e.created_at)) + '</td>'
      + '<td>' + escapeHtml(e.score != null ? String(e.score) + ' / 5' : '') + '</td>'
      + '<td>' + escapeHtml(e.note || '') + '</td></tr>';
  }).join('');
  return '<table class="rec"><thead><tr><th>' + _T("app.c4.colTime") + '</th><th>' + _T("app.c4.colScore") + '</th><th>' + _T("app.c4.colNote") + '</th></tr></thead><tbody>' + rows + '</tbody></table>';
}

function _pvMedsTable(meds, logs) {
  // 服藥率：以每藥 medication_id 在 logs 中的 taken / total 計算
  var stats = {};
  (logs || []).forEach(function(l) {
    var mid = l.medication_id;
    if (!mid) return;
    if (!stats[mid]) stats[mid] = { total: 0, taken: 0 };
    stats[mid].total += 1;
    if (l.taken) stats[mid].taken += 1;
  });
  var rows = meds.map(function(m) {
    var s = stats[m.id];
    var rate = s && s.total ? Math.round(s.taken / s.total * 100) + '%' : '—';
    return '<tr><td>' + escapeHtml(m.name || '') + '</td>'
      + '<td>' + escapeHtml(m.dosage || '') + '</td>'
      + '<td>' + escapeHtml(m.frequency || '') + '</td>'
      + '<td>' + escapeHtml(rate) + (s ? ' <span style="color:#888;font-size:11px">(' + s.taken + '/' + s.total + ')</span>' : '') + '</td></tr>';
  }).join('');
  return '<table class="rec"><thead><tr><th>' + _T("app.c4.colMedName") + '</th><th>' + _T("app.c4.colDosage") + '</th><th>' + _T("app.c4.colFrequency") + '</th><th>' + _T("app.c4.colAdherence") + '</th></tr></thead><tbody>' + rows + '</tbody></table>';
}

function _pvEffectsTable(arr, meds) {
  var byId = {};
  (meds || []).forEach(function(m) { byId[m.id] = m.name; });
  var rows = arr.map(function(e) {
    return '<tr><td>' + escapeHtml(_pvFmtDate(e.recorded_at)) + '</td>'
      + '<td>' + escapeHtml(byId[e.medication_id] || _T("app.c4.unknownMed")) + '</td>'
      + '<td>' + escapeHtml(e.effectiveness != null ? e.effectiveness + ' / 5' : '') + '</td>'
      + '<td>' + escapeHtml(e.side_effects || '') + '</td>'
      + '<td>' + escapeHtml(e.symptom_changes || '') + '</td></tr>';
  }).join('');
  return '<table class="rec"><thead><tr><th>' + _T("app.c4.colDate") + '</th><th>' + _T("app.c4.colMedName") + '</th><th>' + _T("app.c4.colEfficacy") + '</th><th>' + _T("app.c4.colSideEffect") + '</th><th>' + _T("app.c4.colSymptomChange") + '</th></tr></thead><tbody>' + rows + '</tbody></table>';
}

