function loadAccountPage() {
  const fileInput = document.getElementById('acct-avatar-file');
  if (fileInput) fileInput.addEventListener('change', onAccountAvatarPicked);
  // 反映目前是否已設定安全問題（不顯示題目內容，只標示狀態）
  const u = getCurrentUser();
  if (u && u.id) {
    apiFetch(`${API}/auth/user/${u.id}`).then(r => r.ok ? r.json() : null).then(data => {
      if (!data) return;
      const status = document.getElementById('acct-recovery-status');
      const qInput = document.getElementById('acct-recovery-question');
      if (data.has_recovery) {
        if (status) status.textContent = _T('app.c6.securityQuestionSetUpdatable');
        if (qInput && data.recovery_question) qInput.value = data.recovery_question;
      }
    }).catch(() => {});
  }
  const colorInput = document.getElementById('acct-color');
  if (colorInput) {
    colorInput.addEventListener('input', () => {
      const fb = document.querySelector('#acct-avatar .acct-avatar-fallback');
      if (fb) {
        fb.style.background = colorInput.value + '22';
        fb.style.color = colorInput.value;
        fb.style.borderColor = colorInput.value;
      }
    });
  }
}

async function onAccountAvatarPicked(e) {
  const file = e.target.files && e.target.files[0];
  if (!file) return;
  const input = e.target;
  const u = getCurrentUser();
  if (!u) return;
  if (file.type && file.type.indexOf('image/') !== 0) {
    if (typeof showToast === 'function') showToast(_T("app.c5.pickImageFile"), 'warning');
    try { input.value = ''; } catch (_) {}
    return;
  }
  try {
    if (typeof showToast === 'function') showToast(_T('app.c6.processingAvatar'), 'info');
    const dataUrl = await prepareAvatarDataUrl(file);
    const res = await apiFetch(`${API}/auth/user/${u.id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ avatar_url: dataUrl })
    });
    if (!res.ok) {
      let detail = '';
      try { detail = (await res.json()).detail || ''; } catch (_) {}
      if (res.status === 413) throw new Error(_T('app.c6.avatarTooLarge'));
      throw new Error(detail || _Tf('app.c6.avatarUpdateFailHttp', { status: res.status }));
    }
    const updated = await res.json();
    setCurrentUser({ ...u, ...updated });
    if (typeof showToast === 'function') showToast(_T('app.c6.avatarUpdated'), 'success');
    showPage('account');
  } catch (err) {
    console.warn('[avatar] account update failed', err);
    try { input.value = ''; } catch (_) {}
    const msg = err && err.message ? err.message : _T('app.c6.avatarUpdateFail');
    if (typeof showToast === 'function') showToast(msg, 'error');
    showAccountMsg('acct-profile-msg', msg, true);
  }
}

async function saveProfile() {
  const u = getCurrentUser();
  if (!u) return;
  const nickname = document.getElementById('acct-nickname').value.trim();
  const avatar_color = document.getElementById('acct-color').value;
  const emailEl = document.getElementById('acct-email');
  const email = emailEl ? emailEl.value.trim() : '';
  if (!nickname) return;
  if (email && !/^[^@\s]+@[^@\s.]+(\.[^@\s.]+)+$/.test(email)) {
    showAccountMsg('acct-profile-msg', _T('app.c6.emailInvalid'), true);
    return;
  }
  try {
    const res = await apiFetch(`${API}/auth/user/${u.id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ nickname, email, avatar_color })
    });
    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      throw new Error(err.detail || _T('app.c6.updateFail'));
    }
    const updated = await res.json();
    setCurrentUser({ ...u, ...updated });
    showAccountMsg('acct-profile-msg', _T('app.c6.saved'), false);
  } catch (e) {
    showAccountMsg('acct-profile-msg', e.message, true);
  }
}

async function savePassword() {
  const u = getCurrentUser();
  if (!u) return;
  const cur = document.getElementById('acct-pw-current').value;
  const next = document.getElementById('acct-pw-new').value;
  const next2 = document.getElementById('acct-pw-new2').value;
  if (next !== next2) {
    showAccountMsg('acct-pw-msg', _T('app.c6.passwordMismatch'), true);
    return;
  }
  const pwErr = validateClientPassword(next, u.username);
  if (pwErr) {
    showAccountMsg('acct-pw-msg', pwErr, true);
    return;
  }
  try {
    const res = await apiFetch(`${API}/auth/user/${u.id}/password`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ current_password: cur, new_password: next })
    });
    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      throw new Error(err.detail || _T('app.c6.updatePasswordFail'));
    }
    document.getElementById('acct-pw-current').value = '';
    document.getElementById('acct-pw-new').value = '';
    document.getElementById('acct-pw-new2').value = '';
    showAccountMsg('acct-pw-msg', _T('app.c6.passwordUpdated'), false);
  } catch (e) {
    showAccountMsg('acct-pw-msg', e.message, true);
  }
}

async function saveRecovery() {
  const u = getCurrentUser();
  if (!u) return;
  const question = document.getElementById('acct-recovery-question').value.trim();
  const answer = document.getElementById('acct-recovery-answer').value.trim();
  if (!question || !answer) {
    showAccountMsg('acct-recovery-msg', _T('app.c6.fillSecurityQA'), true);
    return;
  }
  try {
    const res = await apiFetch(`${API}/auth/user/${u.id}/recovery`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ question, answer })
    });
    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      throw new Error(err.detail || _T('app.c6.saveFail'));
    }
    document.getElementById('acct-recovery-answer').value = '';
    showAccountMsg('acct-recovery-msg', _T('app.c6.securityQuestionSaved'), false);
    const status = document.getElementById('acct-recovery-status');
    if (status) status.textContent = _T('app.c6.securityQuestionSet');
  } catch (e) {
    showAccountMsg('acct-recovery-msg', e.message, true);
  }
}

function showAccountMsg(id, msg, isError) {
  const el = document.getElementById(id);
  if (!el) return;
  el.textContent = msg;
  el.hidden = false;
  el.classList.toggle('acct-msg-error', !!isError);
  el.classList.toggle('acct-msg-ok', !isError);
}

// ─── 首頁 ──────────────────────────────────────────────────

// i18n helpers (fallback to identity if i18n module hasn't loaded)
function _T(k) { return (window.MDPiece_i18n && window.MDPiece_i18n.t) ? window.MDPiece_i18n.t(k) : k; }
function _Tf(k, vars) { return (window.MDPiece_i18n && window.MDPiece_i18n.tf) ? window.MDPiece_i18n.tf(k, vars) : k; }

function getGreetingMessage() {
  var i = Math.floor(Math.random() * 6);
  return _T('home.calm.' + i);
}

function getHealthTip() {
  var i = Math.floor(Math.random() * 8);
  return _T('home.tip.' + i);
}

// === 下次回診（patient-set；存 localStorage，per-user）=========================
function _nextVisitKey() {
  var u = (typeof getCurrentUser === 'function') ? (getCurrentUser() || {}) : {};
  var pid = u.id_number || u.username || 'guest';
  return 'mdpiece_next_visit_' + pid;
}
function _nextVisitSessionKey() {
  var u = (typeof getCurrentUser === 'function') ? (getCurrentUser() || {}) : {};
  var pid = u.id_number || u.username || 'guest';
  return 'mdpiece_next_visit_session_' + pid;
}
function loadNextVisit() {
  try { return localStorage.getItem(_nextVisitKey()) || ''; } catch (e) { return ''; }
}
function saveNextVisit(iso) {
  try {
    if (iso) localStorage.setItem(_nextVisitKey(), iso);
    else     localStorage.removeItem(_nextVisitKey());
  } catch (e) {}
}
// 上午診 / 下午診（'am' | 'pm' | ''）。空字串代表使用者未指定診時段。
function loadNextVisitSession() {
  try { return _normalizeSession(localStorage.getItem(_nextVisitSessionKey())); }
  catch (e) { return ''; }
}
function saveNextVisitSession(s) {
  try {
    var n = _normalizeSession(s);
    if (n) localStorage.setItem(_nextVisitSessionKey(), n);
    else   localStorage.removeItem(_nextVisitSessionKey());
  } catch (e) {}
}
function _normalizeSession(s) {
  if (!s) return '';
  var v = String(s).toLowerCase();
  if (v === 'am' || v === 'morning' || v === '上午' || v === '上午診') return 'am';
  if (v === 'pm' || v === 'afternoon' || v === '下午' || v === '下午診') return 'pm';
  return '';
}
// 回傳完整中文／英文「上午診 / 下午診」標籤（沒設定回 ''）。
function sessionLabel(s) {
  var n = _normalizeSession(s);
  if (n === 'am') return _T('visit.session.am');
  if (n === 'pm') return _T('visit.session.pm');
  return '';
}
// 短版（沒「診」字），用在 chip / inline 顯示
function sessionShort(s) {
  var n = _normalizeSession(s);
  if (n === 'am') return _T('visit.session.amShort');
  if (n === 'pm') return _T('visit.session.pmShort');
  return '';
}
function _daysBetween(isoDate) {
  // 以「日」為單位差距，今日 0
  var t = new Date(isoDate + 'T00:00:00');
  var n = new Date();
  n.setHours(0,0,0,0);
  return Math.round((t - n) / 86400000);
}
function renderNextVisitChip() {
  var iso = loadNextVisit();
  if (!iso) {
    return ''
      + '<button type="button" class="home-visit-chip home-visit-chip-empty" '
      +   'onclick="openNextVisitEditor()">'
      +   '<i data-lucide="calendar-plus" style="width:14px;height:14px"></i>'
      +   '<span>' + _T('home.visit.set') + '</span>'
      + '</button>';
  }
  var d = _daysBetween(iso);
  var label;
  var cls = 'home-visit-chip';
  if (d > 0)       { label = _Tf('home.visit.daysLeft', { n: d }); }
  else if (d === 0){ label = _T('home.visit.today'); cls += ' home-visit-chip-today'; }
  else             { label = _Tf('home.visit.daysAgo', { n: (-d) }); cls += ' home-visit-chip-past'; }
  var pretty = iso.replace(/-/g, '/').slice(5); // MM/DD
  var sessShort = sessionShort(loadNextVisitSession());
  var sessTag = sessShort
    ? '<span class="home-visit-session" data-session="' + (loadNextVisitSession()) + '">' + escapeHtml(sessShort) + '</span>'
    : '';
  var doneBtn = (d === 0 || d < 0)
    ? '<button type="button" class="home-visit-done" onclick="markVisitCompleted()" title="' + _T('home.visit.doneTitle') + '">'
      +   '<i data-lucide="check-circle-2" style="width:14px;height:14px"></i>'
      +   '<span>' + _T('home.visit.done') + '</span>'
      + '</button>'
    : '<button type="button" class="home-visit-early" onclick="markVisitEarly()" title="' + _T('home.visit.earlyTitle') + '">'
      +   '<i data-lucide="calendar-x-2" style="width:14px;height:14px"></i>'
      +   '<span>' + _T('home.visit.early') + '</span>'
      + '</button>';
  return ''
    + '<button type="button" class="' + cls + '" onclick="openNextVisitEditor()" title="' + _T('home.visit.editTitle') + '">'
    +   '<i data-lucide="calendar-check-2" style="width:14px;height:14px"></i>'
    +   '<span>' + _T('home.visit.label') + ' ' + pretty + '</span>'
    +   sessTag
    +   '<span class="home-visit-countdown">' + label + '</span>'
    + '</button>'
    + doneBtn
    + '<button type="button" class="home-visit-clear" onclick="clearNextVisit()" title="' + _T('home.visit.clearTitle') + '">'
    +   '<i data-lucide="x" style="width:12px;height:12px"></i>'
    + '</button>';
}
function openNextVisitEditor() {
  // 改用自訂 modal（含上午診 / 下午診選擇），不再用原生 date input
  if (typeof openVisitDatePrompt === 'function') {
    openVisitDatePrompt({ focus: 'next' });
  }
}
function clearNextVisit() {
  saveNextVisit('');
  saveNextVisitSession('');
  // 同步把 visitDates.nextVisit / nextVisitSession 清掉，避免狀態不一致
  try {
    if (typeof getVisitDates === 'function' && typeof saveVisitDates === 'function') {
      var cur = getVisitDates() || {};
      saveVisitDates({
        lastVisit: cur.lastVisit || null,
        lastVisitSession: cur.lastVisitSession || '',
        nextVisit: '',
        nextVisitSession: '',
      });
    }
  } catch (e) {}
  refreshNextVisitChip();
}
function refreshNextVisitChip() {
  var row = document.getElementById('home-visit-row');
  if (!row) return;
  row.innerHTML = renderNextVisitChip() + renderNextAdmissionChip() + renderNextInfusionChip();
  if (typeof lucide !== 'undefined') lucide.createIcons();
  // chip 拉真實資料覆寫
  if (typeof _loadNextInfusionInfo === 'function') _loadNextInfusionInfo();
}

// 長期療程「下次打藥」chip — 給 chronic_infusion 患者用，跟回診 chip 平行。
// 初次只渲染 hidden 骨架；_loadNextInfusionInfo() 在 mount 後拉 admission_medications.next_due_date 覆寫。
// 點下不直接跳轉，先開「療程準備清單」sheet（病人可以選擇看清單或前往詳情）。
function renderNextInfusionChip() {
  return '<button type="button" class="home-infusion-chip" id="home-infusion-chip" hidden onclick="openAdmissionPrepSheet(\'infusion\')" title="' + _T('app.c6.openTreatmentPrep') + '">'
    + '<i data-lucide="syringe" style="width:14px;height:14px"></i>'
    + '<span class="home-infusion-chip-label">' + _T('app.c6.nextInfusion') + '</span>'
    + '<span class="home-infusion-chip-when" id="home-infusion-chip-when">—</span>'
    + '<span class="home-infusion-chip-count" id="home-infusion-chip-count"></span>'
    + '</button>';
}

// 即將住院（admit_date 在未來的 acute admission）chip。
function renderNextAdmissionChip() {
  return '<button type="button" class="home-admit-chip" id="home-admit-chip" hidden onclick="openAdmissionPrepSheet(\'admit\')" title="' + _T("app.c7.openAdmitChecklist") + '">'
    + '<i data-lucide="hospital" style="width:14px;height:14px"></i>'
    + '<span class="home-admit-chip-label">' + _T("app.c7.nextAdmission") + '</span>'
    + '<span class="home-admit-chip-when" id="home-admit-chip-when">—</span>'
    + '<span class="home-admit-chip-count" id="home-admit-chip-count"></span>'
    + '</button>';
}

// 拉所有 active admissions，計算兩件事：
//   1. 最早的 next_due_date (chronic_infusion 用) → hero「下次打藥」chip + Layer 03 卡 badge
//   2. 最早的 future admit_date (acute upcoming) → hero「下次住院」chip
// 30 天內才顯示；過期也顯示提醒，並 cache 給 prep sheet 使用。
var _ipUpcomingCache = { admit: null, infusion: null };
async function _loadNextInfusionInfo() {
  var pid = (typeof getStablePatientId === 'function') ? getStablePatientId() : null;
  if (!pid) return;
  try {
    var listRes = await fetch(API + '/admissions/?patient_id=' + encodeURIComponent(pid)).then(function(x){return x.json();});
    var actives = ((listRes && listRes.admissions) || []).filter(function(a) {
      return a.status === 'active';
    });
    var nowMs = Date.now();
    // 1. 未來 admit_date 的 acute admission（最早一筆）
    var nearestAdmit = null;
    actives.filter(function(a) { return a.type === 'acute' && a.admit_date; }).forEach(function(a) {
      var t = new Date(a.admit_date).getTime();
      if (isNaN(t)) return;
      if (t <= nowMs) return; // 已開始或正在進行的，這 chip 不顯示
      if (!nearestAdmit || t < new Date(nearestAdmit.admit_date).getTime()) {
        nearestAdmit = a;
      }
    });
    _ipUpcomingCache.admit = nearestAdmit;
    _fillNextAdmissionChip(nearestAdmit);

    // 2. chronic_infusion next_due_date（找最早）
    var infusionActives = actives.filter(function(a) { return a.type === 'chronic_infusion'; });
    if (!infusionActives.length) {
      _ipUpcomingCache.infusion = null;
      _fillNextInfusionChip(null);
      _fillAdmissionsCardBadge(nearestAdmit ? nearestAdmit.admit_date : null);
      return;
    }
    var details = await Promise.all(infusionActives.map(function(a) {
      return fetch(API + '/admissions/' + encodeURIComponent(a.id)).then(function(x){return x.json();}).catch(function(){return null;});
    }));
    var earliest = null;
    var earliestName = '';
    var earliestAdmId = '';
    var earliestMedId = '';
    details.forEach(function(d) {
      if (!d) return;
      (d.medications || []).forEach(function(m) {
        if (!m.next_due_date) return;
        if (!earliest || m.next_due_date < earliest) {
          earliest = m.next_due_date;
          earliestName = m.name || '';
          earliestAdmId = d.id;
          earliestMedId = m.id;
        }
      });
    });
    _ipUpcomingCache.infusion = earliest ? {
      next_due_date: earliest, name: earliestName, admission_id: earliestAdmId, medication_id: earliestMedId,
    } : null;
    _fillNextInfusionChip(earliest, earliestName);
    // Badge 優先顯示「住院」(更急)，沒有的話顯示打藥
    _fillAdmissionsCardBadge(nearestAdmit ? nearestAdmit.admit_date : earliest);
  } catch (e) {
    _ipUpcomingCache = { admit: null, infusion: null };
    _fillNextInfusionChip(null);
    _fillNextAdmissionChip(null);
    _fillAdmissionsCardBadge(null);
  }
}

function _fillNextAdmissionChip(adm) {
  var chip = document.getElementById('home-admit-chip');
  if (!chip) return;
  if (!adm || !adm.admit_date) { chip.hidden = true; return; }
  var d = _daysBetween(adm.admit_date.slice(0, 10));
  if (d > 30 || d < 0) { chip.hidden = true; return; }
  chip.hidden = false;
  var when = document.getElementById('home-admit-chip-when');
  var count = document.getElementById('home-admit-chip-count');
  var pretty = adm.admit_date.replace(/-/g, '/').slice(5, 10);
  var dx = adm.diagnosis || '';
  if (when) when.textContent = pretty + (dx ? '　' + dx.slice(0, 12) : '');
  var label, urgency;
  if (d > 0)       { label = _Tf("app.c7.daysLater", { n: d }); urgency = d <= 3 ? 'soon' : 'far'; }
  else             { label = _T("app.c7.justToday"); urgency = 'today'; }
  if (count) count.textContent = label;
  chip.dataset.urgency = urgency;
}

function _fillNextInfusionChip(iso, name) {
  var chip = document.getElementById('home-infusion-chip');
  if (!chip) return;
  if (!iso) { chip.hidden = true; return; }
  var d = _daysBetween(iso.slice(0, 10));
  // 超過 30 天才到就先不打擾使用者（卡 badge 也一樣判斷）
  if (d > 30) { chip.hidden = true; return; }
  chip.hidden = false;
  var when = document.getElementById('home-infusion-chip-when');
  var count = document.getElementById('home-infusion-chip-count');
  var pretty = iso.replace(/-/g, '/').slice(5, 10); // MM/DD
  if (when) when.textContent = pretty + (name ? '　' + name : '');
  var label, urgency;
  if (d > 0)       { label = _Tf("app.c7.daysLater", { n: d }); urgency = d <= 7 ? 'soon' : 'far'; }
  else if (d === 0){ label = _T("app.c7.justToday"); urgency = 'today'; }
  else             { label = _Tf("app.c7.overdueDays", { n: (-d) }); urgency = 'overdue'; }
  if (count) count.textContent = label;
  chip.dataset.urgency = urgency;
}

function _fillAdmissionsCardBadge(iso) {
  var badge = document.querySelector('.hsec-card[data-page="admissions"] .hsec-badge');
  if (!badge) return;
  if (!iso) { badge.hidden = true; badge.textContent = ''; return; }
  var d = _daysBetween(iso.slice(0, 10));
  if (d > 30) { badge.hidden = true; return; }
  badge.hidden = false;
  var urgency;
  if (d > 0)       { badge.textContent = _Tf("app.c7.daysLater", { n: d }); urgency = d <= 7 ? 'soon' : 'far'; }
  else if (d === 0){ badge.textContent = _T("app.c7.today");     urgency = 'today'; }
  else             { badge.textContent = _Tf("app.c7.overByDays", { n: (-d) }); urgency = 'overdue'; }
  badge.dataset.urgency = urgency;
}

// ════════════════════════════════════════════════════════════════════════════
// 「住院 / 治療準備清單」bottom sheet
// ════════════════════════════════════════════════════════════════════════════
// 兩種情境共用同一個 sheet 殼，內容由 kind 決定：
//   kind='admit'   → 即將住院（acute）— 5 區清單 + 「提前開始入院」CTA
//   kind='infusion'→ 即將打藥（chronic）— 3 區清單 + 「今日提前施打」CTA
// 勾選狀態存 localStorage 'mdpiece_prep_{kind}_{id}'，下次打開保留。
function _bld__PREP_CHECKLISTS() { return {
  admit: [
    { id: 'doc', title: _T("app.c7.documentsId"), items: [
      { id: 'd1', label: _T("app.c7.nhiCardId") },
      { id: 'd2', label: _T("app.c7.admitNoticeBooking") },
      { id: 'd3', label: _T("app.c7.doctorCertReferral") },
      { id: 'd4', label: _T("app.c7.oldRecordsImaging") },
    ]},
    { id: 'pack', title: _T("app.c7.personalItems"), items: [
      { id: 'p1', label: _T("app.c7.changeClothes") },
      { id: 'p2', label: _T("app.c7.toiletries") },
      { id: 'p3', label: _T("app.c7.phoneCharger") },
      { id: 'p4', label: _T("app.c7.earplugsMask") },
      { id: 'p5', label: _T("app.c7.coinsCard") },
    ]},
    { id: 'food', title: _T("app.c7.dietFasting"), items: [
      { id: 'f1', label: _T("app.c7.confirmFastingHours") },
      { id: 'f2', label: _T("app.c7.admitDayLightMeal") },
    ]},
    { id: 'med', title: _T("app.c7.medication"), items: [
      { id: 'm1', label: _T("app.c7.bringAllMeds") },
      { id: 'm2', label: _T("app.c7.bringMedList") },
      { id: 'm3', label: _T("app.c7.allergyRecord") },
    ]},
    { id: 'mind', title: _T("app.c7.moodCompanion"), items: [
      { id: 'x1', label: _T("app.c7.familyAccompany") },
      { id: 'x2', label: _T("app.c7.writeQuestionsMemo") },
      { id: 'x3', label: _T("app.c7.takeLeaveNotifyWork") },
    ]},
  ],
  infusion: [
    { id: 'doc', title: _T("app.c7.documentsId"), items: [
      { id: 'd1', label: _T("app.c7.nhiCardId") },
      { id: 'd2', label: _T("app.c7.bookingLastDose") },
    ]},
    { id: 'food', title: _T("app.c7.dietMedication"), items: [
      { id: 'f1', label: _T("app.c7.fastHydrateOrder") },
      { id: 'f2', label: _T("app.c7.bringAllMedsSupp") },
      { id: 'f3', label: _T("app.c7.record7DayDiscomfort") },
    ]},
    { id: 'mind', title: _T("app.c7.beforeArrival"), items: [
      { id: 'x1', label: _T("app.c7.measureBpTemp") },
      { id: 'x2', label: _T("app.c7.writeQuestionsMemo2") },
      { id: 'x3', label: _T("app.c7.reserveInfusionTime") },
    ]},
  ],
}; }
var _PREP_CHECKLISTS = _bld__PREP_CHECKLISTS();
function _prepStorageKey(kind, id) { return 'mdpiece_prep_' + kind + '_' + (id || 'default'); }
function _getPrepState(kind, id) {
  try { return JSON.parse(localStorage.getItem(_prepStorageKey(kind, id)) || '{}') || {}; }
  catch (e) { return {}; }
}
function _savePrepState(kind, id, state) {
  localStorage.setItem(_prepStorageKey(kind, id), JSON.stringify(state));
}

function openAdmissionPrepSheet(kind) {
  if (kind !== 'admit' && kind !== 'infusion') return;
  // 沒上下文時不開（chip 已是 hidden 狀態下不會被點到，這只是 safety）
  var ctx = kind === 'admit' ? _ipUpcomingCache.admit : _ipUpcomingCache.infusion;
  if (!ctx) {
    if (typeof showToast === 'function') showToast(_T("app.c7.notScheduledYet"), 'info');
    if (typeof navigateTo === 'function') navigateTo('admissions', null);
    return;
  }
  var existing = document.getElementById('ip-prep-sheet');
  if (existing) existing.remove();

  var ctxId = kind === 'admit' ? ctx.id : ctx.admission_id;
  var iso = kind === 'admit' ? ctx.admit_date : ctx.next_due_date;
  var d = _daysBetween(iso.slice(0, 10));
  var when;
  if (d > 0) when = _Tf("app.c7.daysLater", { n: d });
  else if (d === 0) when = _T("app.c7.justToday");
  else when = _Tf("app.c7.overdueDays", { n: (-d) });
  var prettyDate = iso.replace(/-/g, '/').slice(0, 10);

  var headTitle = kind === 'admit' ? _T("app.c7.admitPrepTitle") : _T("app.c7.infusionPrepTitle");
  var headSub = kind === 'admit'
    ? (ctx.diagnosis || _T("app.c7.admissionWord")) + '\u3000\u00b7\u3000' + _Tf("app.c7.scheduledDate", { date: prettyDate })
    : (ctx.name || _T("app.c7.therapyWord")) + '\u3000\u00b7\u3000' + _Tf("app.c7.scheduledDate", { date: prettyDate });
  var ctaIcon = kind === 'admit' ? 'log-in' : 'syringe';
  var ctaLabel = kind === 'admit' ? _T("app.c7.ctaStartAdmit") : _T("app.c7.ctaCompleteInfusion");
  var ctaHandler = kind === 'admit'
    ? "onAdmissionPrepActivate('admit')"
    : "onAdmissionPrepActivate('infusion')";

  var state = _getPrepState(kind, ctxId);
  var sections = _PREP_CHECKLISTS[kind];
  var doneTotal = 0, total = 0;
  sections.forEach(function(s) { s.items.forEach(function(it) { total++; if (state[it.id]) doneTotal++; }); });

  var sectionsHtml = sections.map(function(s) {
    var itemsHtml = s.items.map(function(it) {
      var checked = !!state[it.id];
      return ''
        + '<li class="ip-prep-item ' + (checked ? 'is-done' : '') + '">'
        +   '<label class="ip-prep-check">'
        +     '<input type="checkbox" ' + (checked ? 'checked' : '') + ' onchange="onPrepItemToggle(\'' + kind + '\',\'' + ctxId + '\',\'' + it.id + '\', this.checked)" />'
        +     '<span class="ip-prep-box"><i data-lucide="check" style="width:13px;height:13px"></i></span>'
        +     '<span class="ip-prep-label">' + escapeHtml(it.label) + '</span>'
        +   '</label>'
        + '</li>';
    }).join('');
    return ''
      + '<section class="ip-prep-section">'
      +   '<h4 class="ip-prep-section-title">' + escapeHtml(s.title) + '</h4>'
      +   '<ul class="ip-prep-list">' + itemsHtml + '</ul>'
      + '</section>';
  }).join('');

  var sheet = document.createElement('div');
  sheet.id = 'ip-prep-sheet';
  sheet.className = 'ip-prep-sheet';
  sheet.dataset.kind = kind;
  sheet.dataset.ctxId = ctxId;
  sheet.innerHTML = ''
    + '<div class="ip-prep-backdrop" onclick="closeAdmissionPrepSheet()"></div>'
    + '<div class="ip-prep-panel" role="dialog" aria-label="' + _T("app.c7.prepChecklist") + '" aria-modal="true" tabindex="-1">'
    +   '<div class="ip-prep-handle"></div>'
    +   '<header class="ip-prep-head">'
    +     '<div class="ip-prep-when">'
    +       '<span class="ip-prep-when-num">' + when + '</span>'
    +       '<span class="ip-prep-when-sub">' + escapeHtml(headSub) + '</span>'
    +     '</div>'
    +     '<button type="button" class="ip-prep-close" onclick="closeAdmissionPrepSheet()" aria-label="' + _T("app.c7.close") + '">'
    +       '<i data-lucide="x" style="width:18px;height:18px"></i>'
    +     '</button>'
    +   '</header>'
    +   '<h3 class="ip-prep-title">' + escapeHtml(headTitle) + '</h3>'
    +   '<div class="ip-prep-progress-row">'
    +     '<div class="ip-prep-progress-bar"><div class="ip-prep-progress-fill" id="ip-prep-progress-fill" style="width:' + (total ? Math.round(doneTotal/total*100) : 0) + '%"></div></div>'
    +     '<span class="ip-prep-progress-text" id="ip-prep-progress-text">' + doneTotal + ' / ' + total + _T("app.c7.readySuffix") + '</span>'
    +   '</div>'
    +   '<div class="ip-prep-body">' + sectionsHtml + '</div>'
    +   '<div class="ip-prep-footer">'
    +     '<button type="button" class="ip-prep-cta" onclick="' + ctaHandler + '">'
    +       '<i data-lucide="' + ctaIcon + '" style="width:16px;height:16px"></i><span>' + ctaLabel + '</span>'
    +     '</button>'
    +     '<button type="button" class="ip-prep-secondary" onclick="navigateTo(\'admissions\',null);closeAdmissionPrepSheet();">'
    +       '<i data-lucide="external-link" style="width:14px;height:14px"></i><span>' + _T("app.c7.viewTherapyDetail") + '</span>'
    +     '</button>'
    +     '<button type="button" class="ip-prep-secondary" onclick="navigateTo(\'memo\',null);closeAdmissionPrepSheet();">'
    +       '<i data-lucide="sticky-note" style="width:14px;height:14px"></i><span>' + _T("app.c7.writeMemoForDoctor") + '</span>'
    +     '</button>'
    +   '</div>'
    + '</div>';
  sheet.addEventListener('keydown', function (e) { if (e.key === 'Escape') closeAdmissionPrepSheet(); });
  document.body.appendChild(sheet);
  requestAnimationFrame(function() {
    sheet.classList.add('open');
    var panel = sheet.querySelector('.ip-prep-panel');
    if (panel) { try { panel.focus(); } catch (e) {} }
  });
  if (typeof lucide !== 'undefined') lucide.createIcons();
}
function closeAdmissionPrepSheet() {
  var sheet = document.getElementById('ip-prep-sheet');
  if (!sheet) return;
  sheet.classList.remove('open');
  setTimeout(function() { sheet.remove(); }, 220);
}
function onPrepItemToggle(kind, ctxId, itemId, checked) {
  var state = _getPrepState(kind, ctxId);
  if (checked) state[itemId] = true; else delete state[itemId];
  _savePrepState(kind, ctxId, state);
  // 更新進度條
  var sections = _PREP_CHECKLISTS[kind];
  var done = 0, total = 0;
  sections.forEach(function(s) { s.items.forEach(function(it) { total++; if (state[it.id]) done++; }); });
  var fill = document.getElementById('ip-prep-progress-fill');
  var text = document.getElementById('ip-prep-progress-text');
  if (fill) fill.style.width = (total ? Math.round(done/total*100) : 0) + '%';
  if (text) text.textContent = done + ' / ' + total + _T("app.c7.readySuffix");
  // 切換 list item 的 done class
  var li = document.querySelector('#ip-prep-sheet [onchange*="\'' + itemId + '\'"]');
  if (li) {
    var item = li.closest('.ip-prep-item');
    if (item) item.classList.toggle('is-done', checked);
  }
}

// 提前 activate — admit: PATCH admit_date = now；infusion: POST dose
function onAdmissionPrepActivate(kind) {
  if (kind === 'admit') {
    var adm = _ipUpcomingCache.admit;
    if (!adm) return;
    if (!confirm(_T("app.c7.confirmStartAdmit"))) return;
    var nowIso = new Date().toISOString().slice(0, 19);
    fetch(API + '/admissions/' + encodeURIComponent(adm.id), {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ admit_date: nowIso }),
    })
      .then(function(r) { if (!r.ok) throw new Error('HTTP ' + r.status); return r.json(); })
      .then(function() {
        if (typeof showToast === 'function') showToast(_T("app.c7.toastStartedAdmit"), 'success');
        closeAdmissionPrepSheet();
        if (typeof setCareMode === 'function') setCareMode('inpatient');
      })
      .catch(function(e) {
        if (typeof showToast === 'function') showToast(_T("app.c7.startFailed") + e.message, 'error');
      });
  } else if (kind === 'infusion') {
    var inf = _ipUpcomingCache.infusion;
    if (!inf || !inf.medication_id) return;
    if (!confirm(_T("app.c7.confirmMarkDose"))) return;
    fetch(API + '/admissions/medications/' + encodeURIComponent(inf.medication_id) + '/dose', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ admission_medication_id: inf.medication_id }),
    })
      .then(function(r) { if (!r.ok) throw new Error('HTTP ' + r.status); return r.json(); })
      .then(function() {
        if (typeof showToast === 'function') showToast(_T("app.c7.toastDoseRecorded"), 'success');
        closeAdmissionPrepSheet();
        if (typeof _loadNextInfusionInfo === 'function') _loadNextInfusionInfo();
      })
      .catch(function(e) {
        if (typeof showToast === 'function') showToast(_T("app.c7.recordFailed") + e.message, 'error');
      });
  }
}

// === 共用「如何使用這頁？」摺疊面板 =====================================
// 用法：在頁面 renderer 開頭呼叫 renderHowto('meds')
//      → 自動讀 i18n 'howto.meds.title' + 'howto.meds.s1..sN' + 'howto.meds.warn'
// 顯示為 <details> 預設摺疊；第一次造訪該頁時自動展開（localStorage 記住）
function renderHowto(key) {
  var seenKey = 'mdpiece_howto_seen_' + key;
  var seen = false;
  try { seen = localStorage.getItem(seenKey) === '1'; } catch (e) {}
  // 動態收集 s1, s2, ... 到沒下一條為止
  var steps = [];
  for (var i = 1; i <= 10; i++) {
    var t = _T('howto.' + key + '.s' + i);
    if (!t || t === ('howto.' + key + '.s' + i)) break; // i18n 拿不到就停
    steps.push(t);
  }
  if (!steps.length) return '';
  var title = _T('howto.' + key + '.title') || _T("app.c7.howToUsePage");
  var warn  = _T('howto.' + key + '.warn');
  var stepsHtml = steps.map(function(s, idx) {
    return '<li class="page-howto-step">'
      + '<span class="page-howto-step-n">' + (idx + 1) + '</span>'
      + '<span class="page-howto-step-text">' + escapeHtml(s) + '</span>'
      + '</li>';
  }).join('');
  return ''
    + '<details class="page-howto" data-key="' + key + '"' + (seen ? '' : ' open') + ' ontoggle="_howtoOnToggle(this)">'
    +   '<summary class="page-howto-summary">'
    +     '<span class="page-howto-summary-icon"><i data-lucide="help-circle"></i></span>'
    +     '<span class="page-howto-summary-text">' + escapeHtml(title) + '</span>'
    +     '<span class="page-howto-summary-chev"><i data-lucide="chevron-down"></i></span>'
    +   '</summary>'
    +   '<div class="page-howto-body">'
    +     '<ol class="page-howto-steps">' + stepsHtml + '</ol>'
    +     (warn && warn !== ('howto.' + key + '.warn')
        ? '<p class="page-howto-warn"><i data-lucide="info" style="width:13px;height:13px"></i> ' + escapeHtml(warn) + '</p>'
        : '')
    +   '</div>'
    + '</details>';
}
function _howtoOnToggle(el) {
  if (el && el.open) {
    var k = el.getAttribute('data-key');
    try { localStorage.setItem('mdpiece_howto_seen_' + k, '1'); } catch (e) {}
  }
}

// === Nav 狀態 Badge ======================================================
// 在 sidebar 各 nav-item 末端顯示「今日打卡狀態」小膠囊：
//   - 已打卡：綠色 "+N"
//   - 未打卡：橘色脈動 "!"
//   - 回診倒數：橘色脈動 "DN" (N 天)
// 來源都用既有 API / localStorage，不打額外端點。
async function refreshNavBadges() {
  var pid = (typeof getStablePatientId === 'function') ? getStablePatientId() : null;
  if (!pid) return;
  var todayISO = _localDay();

  function setBadge(key, text, tone) {
    var el = document.querySelector('[data-nav-badge="' + key + '"]');
    if (!el) return;
    if (!text) { el.textContent = ''; el.removeAttribute('data-tone'); return; }
    el.textContent = text;
    el.setAttribute('data-tone', tone || 'todo');
  }

  // 症狀：今日筆數（本地）
  try {
    var syms = (typeof getSymptomEntries === 'function') ? getSymptomEntries() : [];
    var n = syms.filter(function(e) { return _localDay(e.recordedAt) === todayISO; }).length;
    setBadge('symptoms', n > 0 ? ('+' + n) : '!', n > 0 ? 'done' : 'todo');
  } catch (e) {}

  // 藥物：今日 log 數
  try {
    var ml = await apiFetch(API + '/medications/logs?patient_id=' + pid + '&days=1').then(function(r){return r.json();}).catch(function(){return{logs:[]};});
    var nm = (ml.logs || []).filter(function(l) { return l && l.taken_at && _localDay(l.taken_at) === todayISO && l.taken !== false; }).length;
    setBadge('medications', nm > 0 ? ('+' + nm) : '!', nm > 0 ? 'done' : 'todo');
  } catch (e) {}

  // 情緒：後端 emotions/daily 的 date 用 UTC 切日，這裡保留 UTC todayKey 對齊；
  // 待後端切到本地時區後可改用 todayISO（_localDay()）。
  try {
    var em = await fetch(API + '/emotions/daily?patient_id=' + pid + '&days=1').then(function(r){return r.json();}).catch(function(){return{daily:[]};});
    var todayUTC = new Date().toISOString().slice(0, 10);
    var d = (em.daily || []).find(function(x) { return x.date === todayUTC; });
    var nc = d ? (d.count || 0) : 0;
    setBadge('emotions', nc > 0 ? ('+' + nc) : '!', nc > 0 ? 'done' : 'todo');
  } catch (e) {}

  // 生理（本地 localStorage，由 getVitalEntries() 統一讀取）
  try {
    var vList = (typeof getVitalEntries === 'function') ? getVitalEntries() : [];
    var nv = vList.filter(function(v) {
      return v && _localDay(v.recordedAt || v.date) === todayISO;
    }).length;
    setBadge('vitals', nv > 0 ? ('+' + nv) : '', nv > 0 ? 'done' : 'todo');
  } catch (e) {}

  // 回診倒數
  try {
    var iso = (typeof loadNextVisit === 'function') ? loadNextVisit() : '';
    if (iso) {
      var d2 = _daysBetween(iso);
      if (d2 >= 0 && d2 <= 7) {
        var sess = (typeof loadNextVisitSession === 'function') ? loadNextVisitSession() : '';
        var sessSuffix = sess === 'am' ? ' AM' : (sess === 'pm' ? ' PM' : '');
        setBadge('previsit', (d2 === 0 ? 'TODAY' : ('D' + d2)) + sessSuffix, 'todo');
      } else {
        setBadge('previsit', '');
      }
    } else {
      // 沒設回診日 → 清掉舊 badge，避免 stale state
      setBadge('previsit', '');
    }
  } catch (e) {}
}

// === 今日拼圖 Digest =====================================================
// 顯示「今天打了多少卡」— 症狀 / 用藥 / 情緒 / 飲食。
// 目標 = 6 個碎片（症狀＋藥＋情緒 三大類各算 1，再加 3 個彈性 slot 反映多筆紀錄）。
function renderTodayDigestCard() {
  return ''
    + '<section class="home-digest" aria-label="' + _T("app.c7.todayPuzzle") + '">'
    +   '<div class="home-digest-head">'
    +     '<span class="home-digest-eyebrow">TODAY \u00b7 ' + _T("app.c7.todayPuzzle") + '</span>'
    +     '<span class="home-digest-progress" id="home-digest-progress">' + _Tf("app.c7.piecesProgress", { n: '\u2014' }) + '</span>'
    +   '</div>'
    +   '<div class="home-digest-bar"><div class="home-digest-bar-fill" id="home-digest-bar-fill" style="width:0%"></div></div>'
    +   '<div class="home-digest-stats">'
    +     '<div class="home-digest-stat" data-cat="symptom">'
    +       '<span class="home-digest-icon"><i data-lucide="scan-search"></i></span>'
    +       '<span class="home-digest-num" id="hd-symptom">—</span>'
    +       '<span class="home-digest-label">' + _T("app.c7.symptom") + '</span>'
    +     '</div>'
    +     '<div class="home-digest-stat" data-cat="med">'
    +       '<span class="home-digest-icon"><i data-lucide="pill"></i></span>'
    +       '<span class="home-digest-num" id="hd-med">—</span>'
    +       '<span class="home-digest-label">' + _T("app.c7.medsLabel") + '</span>'
    +     '</div>'
    +     '<div class="home-digest-stat" data-cat="mood">'
    +       '<span class="home-digest-icon"><i data-lucide="battery-charging"></i></span>'
    +       '<span class="home-digest-num" id="hd-mood">—</span>'
    +       '<span class="home-digest-label">' + _T("app.c7.mood") + '</span>'
    +     '</div>'
    +   '</div>'
    + '</section>';
}
async function refreshTodayDigest() {
  var pid = (typeof getStablePatientId === 'function') ? getStablePatientId() : null;
  if (!pid) return;
  var todayISO = _localDay();

  function _todayCountFromList(list, dateField) {
    if (!Array.isArray(list)) return 0;
    return list.filter(function(item) {
      var v = item && item[dateField];
      if (!v) return false;
      return _localDay(v) === todayISO;
    }).length;
  }

  var symptomCount = 0, medCount = 0, moodCount = 0;

  // 症狀：本地 localStorage（submitSymptomLog 寫 mdpiece_symptoms，
  // 不是寫雲端 /symptoms — 後者目前是 stub，永遠回空陣列）
  try {
    var syms = (typeof getSymptomEntries === 'function') ? getSymptomEntries() : [];
    symptomCount = syms.filter(function(e) {
      return _localDay(e.recordedAt) === todayISO;
    }).length;
  } catch (e) {}

  // 用藥 log — 只算真的吃了的（taken !== false），跳過/沒吃不計入今日 KPI
  try {
    var m = await apiFetch(API + '/medications/logs?patient_id=' + pid + '&days=1').then(function(r){return r.json();});
    medCount = (m.logs || []).filter(function(l) {
      return l && l.taken !== false && _localDay(l.taken_at) === todayISO;
    }).length;
  } catch (e) {}

  // 情緒 daily 聚合 — 後端 emotions/daily 用 UTC 切日，這裡 fallback 用 UTC todayKey
  try {
    var em = await fetch(API + '/emotions/daily?patient_id=' + pid + '&days=1').then(function(r){return r.json();});
    var todayUTC = new Date().toISOString().slice(0, 10);
    var d = (em.daily || []).find(function(x) { return x.date === todayUTC; });
    moodCount = d ? (d.count || 0) : 0;
  } catch (e) {}

  // 寫入 DOM
  var setText = function(id, val) { var el = document.getElementById(id); if (el) el.textContent = val; };
  setText('hd-symptom', symptomCount);
  setText('hd-med', medCount);
  setText('hd-mood', moodCount);

  // 進度：三大類各打過至少 1 次算 1 分（上限 3），再加實際筆數封頂 3 → 共 6 分
  var hits = (symptomCount > 0 ? 1 : 0) + (medCount > 0 ? 1 : 0) + (moodCount > 0 ? 1 : 0);
  var extras = Math.min(3, (symptomCount + medCount + moodCount) - hits);
  if (extras < 0) extras = 0;
  var score = hits + extras;
  var pct = Math.min(100, Math.round((score / 6) * 100));
  setText('home-digest-progress', _Tf("app.c7.piecesProgress", { n: score }));
  var bar = document.getElementById('home-digest-bar-fill');
  if (bar) bar.style.width = pct + '%';
}

// === 今日待辦 ============================================================
// 「待辦」由兩部分組成：
//   1. 系統自動生成（auto）— 從現有資料推斷：回診倒數、活躍藥物、今天還沒打卡的事
//   2. 使用者手動加（user）— 存 localStorage，per-user
// 註：所有系統生成項目都附「以醫師說明為準」小字；既有 disclaimer 不動。
var TODO_STORE_VERSION = 1;
function _todoKey() {
  var u = (typeof getCurrentUser === 'function') ? (getCurrentUser() || {}) : {};
  var pid = u.id_number || u.username || 'guest';
  return 'mdpiece_todos_' + pid;
}
function _loadUserTodos() {
  try {
    var raw = localStorage.getItem(_todoKey());
    if (!raw) return [];
    var p = JSON.parse(raw);
    return Array.isArray(p.items) ? p.items : [];
  } catch (e) { return []; }
}
function _saveUserTodos(items) {
  try {
    localStorage.setItem(_todoKey(), JSON.stringify({ v: TODO_STORE_VERSION, items: items }));
  } catch (e) {}
}
function addUserTodo(title, desc) {
  title = String(title || '').trim().slice(0, 80);
  if (!title) return false;
  var items = _loadUserTodos();
  items.unshift({
    id: 'user-' + Date.now() + '-' + Math.random().toString(36).slice(2, 6),
    title: title,
    desc: String(desc || '').trim().slice(0, 200),
    done: false,
    createdAt: Date.now(),
    source: 'user',
  });
  _saveUserTodos(items);
  return true;
}
function toggleUserTodo(id) {
  var items = _loadUserTodos();
  var i = items.findIndex(function(t) { return t.id === id; });
  if (i < 0) return;
  items[i].done = !items[i].done;
  items[i].doneAt = items[i].done ? Date.now() : null;
  _saveUserTodos(items);
}
function removeUserTodo(id) {
  _saveUserTodos(_loadUserTodos().filter(function(t) { return t.id !== id; }));
}
async function _genAutoTodos() {
  var out = [];
  // 此函數只用 todayISO 跟後端 emotions/daily 的 date 對比；後端用 UTC 切日所以這裡保留 UTC。
  var todayISO = new Date().toISOString().slice(0, 10);
  var pid = (typeof getStablePatientId === 'function') ? getStablePatientId() : null;
  if (!pid) return out;

  // 回診倒數（7 天內）
  try {
    var visit = (typeof loadNextVisit === 'function') ? loadNextVisit() : '';
    if (visit) {
      var d = _daysBetween(visit);
      if (d >= 0 && d <= 7) {
        var visitSess = (typeof loadNextVisitSession === 'function') ? loadNextVisitSession() : '';
        var visitSessLbl = sessionLabel(visitSess);
        out.push({
          id: 'auto-visit',
          source: 'auto-visit', category: 'visit',
          title: (d === 0 ? _T("app.c7.visitToday") : _Tf("app.c7.visitCountdown", { n: d })) + (visitSessLbl ? ('\uff08' + visitSessLbl + '\uff09') : ''),
          desc: _T("app.c7.datePrefix") + visit.replace(/-/g, '/') + (visitSessLbl ? ('\u3000' + visitSessLbl) : ''),
          icon: 'calendar-check-2',
          link: null,
          warn: _T("app.c7.warnDoctorBooking"),
        });
      }
    }
  } catch (e) {}

  // 活躍藥物提醒（取前 3 個）
  try {
    var r = await apiFetch(API + '/medications/?patient_id=' + pid).then(function(x){return x.json();});
    var meds = (r.medications || []).filter(function(m) { return m.active !== 0; });
    meds.slice(0, 3).forEach(function(m) {
      out.push({
        id: 'auto-med-' + m.id,
        source: 'auto-med', category: 'med',
        title: _T("app.c7.todayTakeMed") + (m.name || ''),
        desc: m.dosage || '',
        icon: 'pill',
        link: 'medications',
        warn: _T("app.c7.warnDoctorRx"),
      });
    });
  } catch (e) {}

  // 情緒：今天還沒打卡
  try {
    var rr = await fetch(API + '/emotions/daily?patient_id=' + pid + '&days=1').then(function(x){return x.json();});
    var daily = rr.daily || [];
    var today = daily.find(function(d) { return d.date === todayISO && d.count > 0; });
    if (!today) {
      out.push({
        id: 'auto-mood',
        source: 'auto-mood', category: 'mood',
        title: _T("app.c7.moodNotLogged"),
        desc: _T("app.c7.logEnergyMinute"),
        icon: 'battery-charging',
        link: 'emotions',
        warn: null,
      });
    }
  } catch (e) {}

  return out;
}
function renderTodoCard() {
  return ''
    + '<section class="home-todo" aria-label="' + _T("app.c7.todayTodo") + '">'
    +   '<div class="home-todo-head">'
    +     '<span class="home-todo-prefix">' + _T("app.c7.todayTodo") + '</span>'
    +     '<button type="button" class="home-todo-add" onclick="openTodoComposer()" title="' + _T("app.c7.addPersonalTodo") + '">'
    +       '<i data-lucide="plus" style="width:14px;height:14px"></i>'
    +       '<span>' + _T("app.c7.add") + '</span>'
    +     '</button>'
    +   '</div>'
    +   '<div class="home-todo-note">'
    +     '<i data-lucide="info" style="width:12px;height:12px"></i>'
    +     '<span>' + _T("app.c7.todoDisclaimer") + '</span>'
    +   '</div>'
    +   '<div id="home-todo-list" class="home-todo-list">'
    +     '<div class="home-todo-loading">' + _T("app.c7.loading") + '</div>'
    +   '</div>'
    +   '<div class="home-todo-composer" id="home-todo-composer" hidden>'
    +     '<input type="text" id="home-todo-input" class="home-todo-input" maxlength="80" placeholder="' + _T("app.c7.todoPlaceholder") + '">'
    +     '<button type="button" class="home-todo-submit" onclick="submitTodoComposer()">' + _T("app.c7.addAction") + '</button>'
    +     '<button type="button" class="home-todo-cancel" onclick="closeTodoComposer()" aria-label="' + _T("app.c7.cancel") + '">\u2715</button>'
    +   '</div>'
    + '</section>';
}
async function refreshTodoList() {
  var el = document.getElementById('home-todo-list');
  if (!el) return;
  var auto, user;
  try {
    auto = await _genAutoTodos();
  } catch (e) { auto = []; }
  user = _loadUserTodos();
  // 完成 > 24h 的個人項目自動隱藏，避免堆積
  var cutoff = Date.now() - 24 * 3600 * 1000;
  user = user.filter(function(t) { return !t.done || (t.doneAt && t.doneAt > cutoff); });

  var rows = '';
  auto.forEach(function(t) {
    rows += ''
      + '<div class="todo-item todo-auto" data-cat="' + t.category + '">'
      +   '<span class="todo-icon"><i data-lucide="' + (t.icon || 'circle') + '"></i></span>'
      +   '<div class="todo-body">'
      +     '<div class="todo-title">' + escapeHtml(t.title) + '</div>'
      +     (t.desc ? '<div class="todo-desc">' + escapeHtml(t.desc) + '</div>' : '')
      +     (t.warn ? '<div class="todo-warn"><i data-lucide="alert-triangle" style="width:11px;height:11px"></i> ' + escapeHtml(t.warn) + '</div>' : '')
      +   '</div>'
      +   (t.link
          ? '<button type="button" class="todo-go" onclick="navigateTo(\'' + t.link + '\',null)" title="' + _T("app.c7.goTo") + '">\u2192</button>'
          : '<span class="todo-tag-auto">auto</span>')
      + '</div>';
  });

  if (user.length) {
    user.forEach(function(t) {
      rows += ''
        + '<div class="todo-item todo-user' + (t.done ? ' is-done' : '') + '" data-id="' + t.id + '">'
        +   '<button type="button" class="todo-check" onclick="onTodoToggle(\'' + t.id + '\')" aria-label="' + (t.done ? _T("app.c7.markUndone") : _T("app.c7.markDone")) + '">'
        +     (t.done ? '<i data-lucide="check-square" style="width:16px;height:16px"></i>' : '<i data-lucide="square" style="width:16px;height:16px"></i>')
        +   '</button>'
        +   '<div class="todo-body">'
        +     '<div class="todo-title">' + escapeHtml(t.title) + '</div>'
        +     (t.desc ? '<div class="todo-desc">' + escapeHtml(t.desc) + '</div>' : '')
        +   '</div>'
        +   '<button type="button" class="todo-del" onclick="onTodoRemove(\'' + t.id + '\')" title="' + _T("app.c7.delete") + '" aria-label="' + _T("app.c7.deleteThis") + '">'
        +     '<i data-lucide="trash-2" style="width:13px;height:13px"></i>'
        +   '</button>'
        + '</div>';
    });
  }

  if (!rows) {
    rows = '<div class="todo-empty">' + _T("app.c7.todoEmpty") + '</div>';
  }
  el.innerHTML = rows;
  if (typeof lucide !== 'undefined') lucide.createIcons();
}
function onTodoToggle(id) { toggleUserTodo(id); refreshTodoList(); }
function onTodoRemove(id) { removeUserTodo(id); refreshTodoList(); }
function openTodoComposer() {
  var c = document.getElementById('home-todo-composer');
  if (!c) return;
  c.hidden = false;
  var inp = document.getElementById('home-todo-input');
  if (inp) { inp.value = ''; setTimeout(function(){ inp.focus(); }, 30); inp.onkeydown = function(e){
    if (e.key === 'Enter') { e.preventDefault(); submitTodoComposer(); }
    else if (e.key === 'Escape') { closeTodoComposer(); }
  }; }
}
function closeTodoComposer() {
  var c = document.getElementById('home-todo-composer');
  if (c) c.hidden = true;
}
function submitTodoComposer() {
  var inp = document.getElementById('home-todo-input');
  if (!inp) return;
  if (addUserTodo(inp.value, '')) {
    closeTodoComposer();
    refreshTodoList();
    if (typeof showToast === 'function') showToast(_T("app.c7.toastTodoAdded"), 'success');
  } else {
    inp.focus();
  }
}

// 結束本期回診週期：把這段期間的紀錄整合進「我的碎片」，產出報告快照，然後清除原始紀錄。
// `early=true` 代表使用者在預定回診日之前主動結束週期（提前回診）。
function _finalizeVisit(opts) {
  opts = opts || {};
  var early = !!opts.early;

  // 1. 計算並保存快照（保留為「我的碎片」歷史，等同於提前產出 repo）
  try {
    if (typeof piecesComputeStats === 'function' && typeof piecesSaveSnapshot === 'function') {
      var s = piecesComputeStats();
      var snap = {
        savedAt: new Date().toISOString(),
        since: s.since instanceof Date ? s.since.toISOString() : s.since,
        days: s.days,
        symptomCount: s.symptomCount,
        symptomEntries: s.symptomEntries,
        avgIntensity: s.avgIntensity,
        memoCount: s.memoCount,
        memoForDoctor: s.memoForDoctor,
        vitalCount: s.vitalCount,
        topCats: s.topCats,
        timeline: s.timeline,
        completedVisit: true,
        earlyVisit: early
      };
      piecesSaveSnapshot(snap);
    }
  } catch (e) { /* 失敗也繼續清資料，避免卡住流程 */ }

  // 2. 清除原始紀錄（只清時間序列資料，保留設定/基本資料）
  try { localStorage.removeItem('mdpiece_symptoms'); } catch (e) {}
  try { localStorage.removeItem('mdpiece_memos_v1'); } catch (e) {}
  try { localStorage.removeItem('mdpiece_vitals_entries'); } catch (e) {}

  // 3. 更新回診日期：lastVisit = 今天、nextVisit = ''
  //    時段也轉移：原本「下次回診的上午/下午」變成「上次回診」的時段，下次清空
  try {
    var todayIso = _localDay();
    var curr = (typeof getVisitDates === 'function') ? (getVisitDates() || {}) : {};
    var perUserSess = (typeof loadNextVisitSession === 'function') ? loadNextVisitSession() : '';
    var inheritedSession = _normalizeSession(perUserSess || curr.nextVisitSession || '');
    if (typeof saveVisitDates === 'function') {
      saveVisitDates({
        lastVisit: todayIso,
        lastVisitSession: inheritedSession,
        nextVisit: '',
        nextVisitSession: '',
      });
    }
  } catch (e) {}
  saveNextVisit('');
  saveNextVisitSession('');
  refreshNextVisitChip();

  // 4. UI 反饋
  if (typeof showToast === 'function') {
    showToast(early ? _T('app.c8.finalizeEarlyDone') : _T('app.c8.finalizeVisitDone'), 'success');
  }
  // 5. 直接帶到「我的碎片」頁讓使用者看到結果
  setTimeout(function() {
    if (typeof navigateTo === 'function') navigateTo('pieces', null);
  }, 400);
}

// 已回診：到了或過了預定回診日才會出現的按鈕。
function markVisitCompleted() {
  var msg =
    _T('app.c8.markCompletedL1') +
    _T('app.c8.markCompletedL2') +
    _T('app.c8.markCompletedL3') +
    _T('app.c8.markCompletedL4') +
    _T('app.c8.confirmContinue');
  if (!confirm(msg)) return;
  _finalizeVisit({ early: false });
}

// 提前回診：在預定回診日之前主動結束本期週期、提前產出報告快照。
function markVisitEarly() {
  var iso = loadNextVisit();
  var d = iso ? _daysBetween(iso) : null;
  var lead = (d != null && d > 0) ? (_Tf('app.c8.earlyLead', { d: d })) : '';
  var msg =
    _T('app.c8.markEarlyL1') +
    lead +
    _T('app.c8.markEarlyL2') +
    _T('app.c8.markCompletedL3') +
    _T('app.c8.markEarlyL4') +
    _T('app.c8.confirmContinue');
  if (!confirm(msg)) return;
  _finalizeVisit({ early: true });
}

