// 7. 病情趨勢 (Trend Chips) — 7-day sparklines ─────────────────────────────
// 趨勢 chip 變成可點 — 沒紀錄時點下開「快速 log」sheet 讓使用者直接記今天的疲勞 / 心情 / 痛。
function renderInpatientTrendChips() {
  var chips = [
    { key: 'pain',    label: _T("app.c10.trendPain"), icon: 'zap',              color: 'coral'  },
    { key: 'fatigue', label: _T("app.c10.trendFatigue"), icon: 'battery-low',      color: 'sky'    },
    { key: 'mood',    label: _T("app.c10.trendMood"), icon: 'heart-handshake',  color: 'mint'   },
  ];
  var html = chips.map(function(c) {
    return ''
      + '<button type="button" class="ip-trend-chip ip-trend-' + c.color + '" data-key="' + c.key + '" onclick="openInpatientQuickLog(\'' + c.key + '\')" aria-label="' + _Tf("app.c10.trendRecordAria", { label: c.label }) + '">'
      +   '<span class="ip-trend-head">'
      +     '<i data-lucide="' + c.icon + '"></i>'
      +     '<span class="ip-trend-label">' + c.label + '</span>'
      +     '<span class="ip-trend-arrow" id="ip-trend-arrow-' + c.key + '">—</span>'
      +   '</span>'
      +   '<svg class="ip-trend-spark" viewBox="0 0 100 30" preserveAspectRatio="none" aria-hidden="true">'
      +     '<polyline id="ip-trend-line-' + c.key + '" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" points="" />'
      +   '</svg>'
      +   '<span class="ip-trend-foot" id="ip-trend-foot-' + c.key + '">' + _T("app.c10.tapToRecordToday") + '</span>'
      +   '<span class="ip-trend-explain" id="ip-trend-explain-' + c.key + '" onclick="event.stopPropagation()"></span>'
      + '</button>';
  }).join('');
  return ''
    + '<section class="ip-trends" aria-label="' + _T("app.c10.ipTrendsAria") + '">'
    +   '<header class="ip-section-head">'
    +     '<span class="ip-num">07</span>'
    +     '<h3>' + _T("app.c10.ipTrendsHead") + '</h3>'
    +     '<span class="ip-section-sub">' + _T("app.c10.ipTrendsSubHead") + '</span>'
    +   '</header>'
    +   '<div class="ip-trend-grid">' + html + '</div>'
    + '</section>';
}

// 快速 log sheet — 給 pain/fatigue/mood 三類用。1-5 級或表情點一下就送。
function openInpatientQuickLog(key) {
  var existing = document.getElementById('ip-quicklog-sheet');
  if (existing) existing.remove();
  var cfg = {
    pain:    { title: _T("app.c10.qlPainTitle"), label: _T("app.c10.qlPainLabel"),  emojis: ['😌','🙂','😣','😖','😫'], color: 'coral' },
    fatigue: { title: _T("app.c10.qlFatigueTitle"),     label: _T("app.c10.qlFatigueLabel"),  emojis: ['🔋','⚡','😴','😵','😶'], color: 'sky'   },
    mood:    { title: _T("app.c10.qlMoodTitle"),   label: _T("app.c10.qlMoodLabel"),  emojis: ['😢','😟','😐','🙂','😊'], color: 'mint'  },
  }[key];
  if (!cfg) return;
  // 按鈕：1~5 分 + emoji
  var btns = '';
  for (var i = 1; i <= 5; i++) {
    btns += '<button type="button" class="ip-ql-num ip-ql-' + cfg.color + '" data-v="' + i + '" onclick="submitInpatientQuickLog(\'' + key + '\',' + i + ')">'
         + '<span class="ip-ql-emoji">' + cfg.emojis[i-1] + '</span>'
         + '<span class="ip-ql-n">' + i + '</span>'
         + '</button>';
  }
  var sheet = document.createElement('div');
  sheet.id = 'ip-quicklog-sheet';
  sheet.className = 'ip-prep-sheet';
  sheet.innerHTML = ''
    + '<div class="ip-prep-backdrop" onclick="closeInpatientQuickLog()"></div>'
    + '<div class="ip-prep-panel ip-ql-panel" role="dialog" aria-label="快速紀錄">'
    +   '<div class="ip-prep-handle"></div>'
    +   '<header class="ip-prep-head">'
    +     '<div class="ip-prep-when">'
    +       '<span class="ip-prep-when-num">' + cfg.title + '</span>'
    +       '<span class="ip-prep-when-sub">' + cfg.label + ' · 1 = ' + _T("app.d16.mildest") + ' · 5 = ' + _T("app.d16.severest") + '</span>'
    +     '</div>'
    +     '<button type="button" class="ip-prep-close" onclick="closeInpatientQuickLog()" aria-label="' + _T("app.c10.close") + '"><i data-lucide="x" style="width:18px;height:18px"></i></button>'
    +   '</header>'
    +   '<div class="ip-ql-grid">' + btns + '</div>'
    + '</div>';
  document.body.appendChild(sheet);
  requestAnimationFrame(function() { sheet.classList.add('open'); });
  if (typeof lucide !== 'undefined') lucide.createIcons();
}
function closeInpatientQuickLog() {
  var sheet = document.getElementById('ip-quicklog-sheet');
  if (!sheet) return;
  sheet.classList.remove('open');
  setTimeout(function() { sheet.remove(); }, 220);
}
function submitInpatientQuickLog(key, value) {
  if (key === 'mood') {
    // 心情送後端 POST /emotions/（score 為 1-5 整數）；後端失敗時 fallback 存 local，趨勢線之後接後端就會帶到
    var pid = (typeof getStablePatientId === 'function') ? getStablePatientId() : null;
    if (pid) {
      fetch(API + '/emotions/', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'X-User-Id': pid },
        body: JSON.stringify({ patient_id: pid, score: value, note: '住院模式快速紀錄' }),
      }).catch(function() {});
    }
    // 同時寫 local 一筆讓 sparkline 立刻有反應
    _ipLocalMoodPush(value);
  } else {
    // pain/fatigue 走 saveSymptomEntry (跟 SOS 同流)
    if (typeof saveSymptomEntry === 'function') {
      saveSymptomEntry({
        id: 'ql_' + Date.now().toString(36),
        categoryId: key === 'pain' ? 'headache' : 'fatigue',
        intensity: value,
        frequency: 1,
        notes: '住院模式快速紀錄',
        recordedAt: new Date().toISOString(),
      });
    }
  }
  if (typeof showToast === 'function') showToast(_Tf("app.c10.qlRecordedToast", { what: (key==='pain'?_T("app.c10.trendPain"):key==='fatigue'?_T("app.c10.trendFatigue"):_T("app.c10.trendMood")) }), 'success');
  closeInpatientQuickLog();
  loadInpatientTrendSparklines();
}

// 本地心情快取（給 sparkline）— 後端來資料時會被覆蓋
function _ipLocalMoodPush(value) {
  try {
    var key = 'mdpiece_inpatient_mood_local';
    var list = JSON.parse(localStorage.getItem(key) || '[]') || [];
    list.push({ value: value, at: new Date().toISOString() });
    // 留 30 天
    var cutoff = Date.now() - 30 * 86400000;
    list = list.filter(function(x) { return new Date(x.at).getTime() > cutoff; });
    localStorage.setItem(key, JSON.stringify(list));
  } catch (e) {}
}
function _ipLocalMoodDaily() {
  try {
    var list = JSON.parse(localStorage.getItem('mdpiece_inpatient_mood_local') || '[]') || [];
    var bucket = {};
    var today = new Date();
    for (var i = 6; i >= 0; i--) {
      var d = new Date(today); d.setDate(d.getDate() - i);
      bucket[d.toISOString().slice(0,10)] = { sum: 0, n: 0 };
    }
    list.forEach(function(e) {
      var k = String(e.at).slice(0,10);
      if (bucket[k]) { bucket[k].sum += e.value; bucket[k].n += 1; }
    });
    return Object.keys(bucket).sort().map(function(k) {
      var b = bucket[k];
      return b.n ? b.sum / b.n * 2 : null; // value 1-5 → 0-10 scale to match emotions API
    });
  } catch (e) { return []; }
}

// 8. 出院進度 (Discharge Stepper) ──────────────────────────────────────────
// 出院進度 — 4 步：入院日期 / 感覺好一點 / 排定出院 / 出院（已出院）。
// step 0 (入院日期) ：由 admit_date 自動完成
// step 1 (感覺好一點)：病人自己點「我感覺好一點了」推進；存 localStorage per admission
// step 2 (排定出院)  ：由 discharge_date 出現自動完成（病人也可以點「排定出院」開 prompt 設日期）
// step 3 (出院)      ：到了 discharge_date 或病人點「已出院」 → PUT status=discharged
function renderInpatientDischargeStepper() {
  var steps = [
    { id: 'admit',    label: _T("app.c10.stepAdmit"), icon: 'log-in' },
    { id: 'feeling',  label: _T("app.c10.stepFeeling"), icon: 'heart' },
    { id: 'planned',  label: _T("app.c10.stepPlanned"), icon: 'calendar-check-2' },
    { id: 'done',     label: _T("app.c10.stepDone"),     icon: 'log-out' },
  ];
  var html = steps.map(function(s, i) {
    return ''
      + '<li class="ip-step" data-step="' + i + '" data-step-id="' + s.id + '">'
      +   '<button type="button" class="ip-step-dot" onclick="onInpatientStepClick(\'' + s.id + '\')" aria-label="' + s.label + '">'
      +     '<i data-lucide="' + s.icon + '" style="width:14px;height:14px"></i>'
      +     '<i data-lucide="check" style="width:14px;height:14px" class="ip-step-check"></i>'
      +   '</button>'
      +   '<span class="ip-step-label">' + s.label + '</span>'
      +   '<span class="ip-step-sub" id="ip-step-sub-' + s.id + '"></span>'
      + '</li>';
  }).join('');
  return ''
    + '<section class="ip-discharge" aria-label="' + _T("app.c10.ipDischargeProgress") + '">'
    +   '<header class="ip-section-head">'
    +     '<span class="ip-num">08</span>'
    +     '<h3>' + _T("app.c10.ipDischargeProgress") + '</h3>'
    +     '<span class="ip-section-sub" id="ip-discharge-eta">—</span>'
    +   '</header>'
    +   '<ol class="ip-steps" id="ip-steps">' + html + '</ol>'
    +   '<div class="ip-discharge-feeling-explain" id="ip-discharge-feeling-explain"></div>'
    +   '<p class="ip-discharge-hint" id="ip-discharge-hint">' + _T("app.c10.ipDischargeHint") + '</p>'
    + '</section>';
}

// 由 Q07「這幾天的變化」評估「感覺好一點」— 設計憲法 #2 (可解釋 AI) + #5 (Decision Aid)
// 把 pain / fatigue / mood 三條 7 天 series 丟進來，回傳 { verdict, metrics, why, confidence? }
// verdict: 'better' | 'worse' | 'flat' | 'insufficient'
//   better  = ≥2 指標好轉 且 0 指標惡化（門檻 ±0.2，同 _drawSparkline 邏輯）
//   worse   = ≥2 指標惡化 且 0 指標好轉
//   flat    = 其餘有資料的情況
//   insufficient = 有資料的指標不足 2 個
function _ipFeelingAssessment(painSeries, fatigueSeries, moodSeries) {
  function evalOne(series, isGoodMetric) {
    var clean = (series || []).filter(function(v) { return v != null; });
    if (clean.length < 2) return { ok: false, n: clean.length };
    var half = Math.floor(clean.length / 2) || 1;
    var early = clean.slice(0, half).reduce(function(s,v){return s+v;},0) / half;
    var late = clean.slice(-half).reduce(function(s,v){return s+v;},0) / half;
    var delta = late - early;
    var improving = isGoodMetric ? (delta > 0.2) : (delta < -0.2);
    var worsening = isGoodMetric ? (delta < -0.2) : (delta > 0.2);
    return { ok: true, n: clean.length, early: early, late: late, delta: delta, improving: improving, worsening: worsening };
  }
  var m = {
    pain:    evalOne(painSeries,    false),
    fatigue: evalOne(fatigueSeries, false),
    mood:    evalOne(moodSeries,    true),
  };
  var labels = { pain: _T("app.c10.trendPain"), fatigue: _T("app.c10.trendFatigue"), mood: _T("app.c10.trendMood") };
  var have = ['pain','fatigue','mood'].filter(function(k){ return m[k].ok; });
  if (have.length < 2) {
    return { verdict: 'insufficient', metrics: m, have: have, why: [_T("app.c10.feelInsufficientWhy")] };
  }
  var imp = have.filter(function(k){ return m[k].improving; }).length;
  var wor = have.filter(function(k){ return m[k].worsening; }).length;
  var totalN = have.reduce(function(s,k){ return s + m[k].n; }, 0);
  var why = have.map(function(k) {
    var x = m[k]; var dir = x.improving ? _T("app.c10.feelDirBetter") : x.worsening ? _T("app.c10.feelDirWorse") : _T("app.c10.feelDirFlat");
    var goodHint = (k === 'mood') ? _T("app.c10.feelHigherBetter") : _T("app.c10.feelLowerBetter");
    return labels[k] + goodHint + _Tf("app.c10.feelHalfCompare", { early: x.early.toFixed(1), late: x.late.toFixed(1) }) + ' ' + dir;
  });
  why.push(_Tf("app.c10.feelTotalNote", { n: totalN }));
  why.push(_Tf("app.c10.feelThresholdNote", { total: have.length }));
  if (imp >= 2 && wor === 0) {
    return {
      verdict: 'better',
      metrics: m, have: have,
      confidence: Math.min(0.9, 0.4 + totalN * 0.05),
      why: why,
    };
  }
  if (wor >= 2 && imp === 0) {
    return { verdict: 'worse', metrics: m, have: have, why: why };
  }
  return { verdict: 'flat', metrics: m, have: have, why: why };
}

// 後端拉到的 mood daily series (0..10)，由 loadInpatientTrendSparklines 更新；沒拉到就維持 null
var _ipMoodSeriesBackend = null;
var _ipLatestFeelingAssessment = null;

// 取得當下要餵給評估的 3 條 series（資料源與 loadInpatientTrendSparklines 一致）
function _ipComputeTrendSeriesForAssessment() {
  var syms = (typeof getSymptomEntries === 'function') ? getSymptomEntries() : [];
  var painCats = ['headache','joint','muscle','neuralgia','chest','dizziness','vertigo'];
  return {
    pain:    _aggDaily(syms, function(e) { return painCats.indexOf(e.categoryId) !== -1 ? (e.intensity || 0) : null; }),
    fatigue: _aggDaily(syms, function(e) { return e.categoryId === 'fatigue' ? (e.intensity || 0) : null; }),
    mood:    (_ipMoodSeriesBackend && _ipMoodSeriesBackend.length) ? _ipMoodSeriesBackend : _ipLocalMoodDaily(),
  };
}

// 重新計算評估、套到出院 step 的 feeling 區塊
function _ipRefreshFeelingHint() {
  var s = _ipComputeTrendSeriesForAssessment();
  var assess = _ipFeelingAssessment(s.pain, s.fatigue, s.mood);
  _ipLatestFeelingAssessment = assess;
  _ipApplyFeelingHintToStep(assess);
}

// 只動 feeling step 的 sub-text 與 suggested 視覺、加上 aiExplain 卡。不影響其他 step 與點擊行為。
function _ipApplyFeelingHintToStep(assess) {
  var li = document.querySelector('.ip-step[data-step-id="feeling"]');
  var hint = document.getElementById('ip-discharge-feeling-explain');
  if (!li) return;
  var sub = li.querySelector('.ip-step-sub');
  // 已手動標 done：保留日期顯示，不畫 suggested，不放 explainer
  if (li.classList.contains('done')) {
    li.classList.remove('suggested');
    if (hint) hint.innerHTML = '';
    return;
  }
  if (!assess || assess.verdict === 'insufficient') {
    li.classList.remove('suggested');
    if (sub) sub.textContent = _T("app.c10.feelTapWhenBetter");
    if (hint) hint.innerHTML = '';
    return;
  }
  if (assess.verdict === 'better') {
    li.classList.add('suggested');
    if (sub) sub.textContent = _T("app.c10.feelAiBetter");
    if (hint) hint.innerHTML = aiExplain({
      summary: _T("app.c10.feelWhyBetterSummary"),
      why: assess.why,
      confidence: assess.confidence,
    });
  } else {
    li.classList.remove('suggested');
    if (sub) sub.textContent = assess.verdict === 'worse' ? _T("app.c10.feelAiWorse") : _T("app.c10.feelTapWhenBetter");
    if (hint) hint.innerHTML = aiExplain({
      summary: _T("app.c10.feelTrendSummary"),
      why: assess.why,
    });
  }
  if (typeof lucide !== 'undefined') lucide.createIcons();
}

// 感覺好一點 — local 每個 admission 獨立
function _ipFeelingKey(admId) { return 'mdpiece_inpatient_feeling_' + (admId || 'default'); }
function _ipGetFeelingState(admId) {
  try { return JSON.parse(localStorage.getItem(_ipFeelingKey(admId)) || 'null'); }
  catch (e) { return null; }
}
function _ipSetFeelingState(admId, state) {
  if (state) localStorage.setItem(_ipFeelingKey(admId), JSON.stringify(state));
  else localStorage.removeItem(_ipFeelingKey(admId));
}

// 推進入「感覺好一點」step
function onInpatientStepClick(stepId) {
  var admId = _ipActiveAdmissionId;
  if (!admId) {
    if (typeof showToast === 'function') showToast(_T("app.c10.noActiveAdmission"), 'info');
    return;
  }
  if (stepId === 'admit') {
    if (typeof showToast === 'function') showToast(_T("app.c10.admitAutoFilled"), 'info');
    return;
  }
  if (stepId === 'feeling') {
    var cur = _ipGetFeelingState(admId);
    if (cur && cur.at) {
      if (!confirm(_Tf("app.c10.feelAlreadyMarkedConfirm", { date: cur.at.slice(0, 10) }))) return;
      _ipSetFeelingState(admId, null);
      if (typeof showToast === 'function') showToast(_T("app.c10.markCancelled"), 'success');
    } else {
      _ipSetFeelingState(admId, { at: new Date().toISOString() });
      if (typeof showToast === 'function') showToast(_T("app.c10.feelingNoted"), 'success');
    }
    loadInpatientActiveAdmission();
    return;
  }
  if (stepId === 'planned') {
    var iso = prompt(_T("app.c10.dischargeDatePrompt"), _localDay());
    if (!iso) return;
    if (!/^\d{4}-\d{2}-\d{2}$/.test(iso.trim())) { if (typeof showToast === 'function') showToast(_T("app.c10.badFormat"), 'error'); return; }
    fetch(API + '/admissions/' + encodeURIComponent(admId), {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ discharge_date: iso.trim() + 'T10:00' }),
    })
      .then(function(r) { if (!r.ok) throw new Error('HTTP ' + r.status); return r.json(); })
      .then(function() {
        if (typeof showToast === 'function') showToast(_Tf("app.c10.dischargeScheduled", { date: iso }), 'success');
        loadInpatientActiveAdmission();
      })
      .catch(function(e) { if (typeof showToast === 'function') showToast(_Tf("app.c10.updateFailed", { msg: e.message }), 'error'); });
    return;
  }
  if (stepId === 'done') {
    if (!confirm(_T("app.c10.dischargeConfirm"))) return;
    fetch(API + '/admissions/' + encodeURIComponent(admId), {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status: 'discharged', discharge_date: new Date().toISOString().slice(0, 19) }),
    })
      .then(function(r) { if (!r.ok) throw new Error('HTTP ' + r.status); return r.json(); })
      .then(function() {
        if (typeof showToast === 'function') showToast(_T("app.c10.dischargedToast"), 'success');
        loadInpatientActiveAdmission();
      })
      .catch(function(e) { if (typeof showToast === 'function') showToast(_T('app.c11.closeCaseFailed') + e.message, 'error'); });
  }
}

