function _renderTimelineFilters(active) {
  var all = '<button type="button" class="tl-filter ' + (active === 'all' ? 'is-active' : '') + '" onclick="filterTimeline(\'all\')">' + _T('app.c12.filterAll') + '</button>';
  var others = _TIMELINE_KINDS.map(function(k) {
    var act = active === k.id ? ' is-active' : '';
    return '<button type="button" class="tl-filter tl-filter-' + k.color + act + '" onclick="filterTimeline(\'' + k.id + '\')">'
      + '<i data-lucide="' + k.icon + '" style="width:13px;height:13px"></i>'
      + '<span>' + k.label + '</span>'
      + '</button>';
  }).join('');
  return all + others;
}

var _tlFilter = 'all';
function filterTimeline(kind) {
  _tlFilter = kind;
  var el = document.getElementById('tl-filters');
  if (el) el.innerHTML = _renderTimelineFilters(kind);
  loadTimelinePage();
}

function loadTimelinePage() {
  var box = document.getElementById('tl-list');
  if (!box) return;
  // 先嘗試從後端拉 server 端時間軸（場景 C：跨次就診整合）。
  // 失敗或 DB offline 時，沉著退回 localStorage 既有資料。
  loadServerTimeline().then(function(serverOk) {
    if (serverOk) return;       // 已成功渲染 Bento Grid，跳過 local
    _renderLocalTimeline(box);   // 否則用既有 .tl-list 流程
  }).catch(function() {
    _renderLocalTimeline(box);
  });
}

function _renderLocalTimeline(box) {
  var entries = _getTimelineEntries();
  if (_tlFilter !== 'all') entries = entries.filter(function(e) { return e.kind === _tlFilter; });
  entries.sort(function(a, b) { return a.date < b.date ? 1 : -1; });
  if (!entries.length) {
    if (_tlFilter === 'all') {
      _renderTimelineOnboarding(box);
    } else {
      _setTimelineBoxMode(box, 'tl-list');
      box.innerHTML = '<p class="tl-empty">' + _T("app.c13.categoryNoRecords") + '</p>';
      if (typeof lucide !== 'undefined') lucide.createIcons();
    }
    return;
  }
  _setTimelineBoxMode(box, 'tl-list');
  box.innerHTML = entries.map(function(e) {
    var k = _TIMELINE_KINDS.find(function(x) { return x.id === e.kind; }) || _TIMELINE_KINDS[3];
    return ''
      + '<article class="tl-card tl-card-' + k.color + '" data-id="' + e.id + '">'
      +   '<header class="tl-card-head">'
      +     '<span class="tl-card-icon"><i data-lucide="' + k.icon + '"></i></span>'
      +     '<div class="tl-card-meta">'
      +       '<span class="tl-card-kind">' + k.label + '</span>'
      +       '<span class="tl-card-date">' + escapeHtml(e.date) + '</span>'
      +     '</div>'
      +     '<button type="button" class="tl-card-del" onclick="onTimelineDelete(\'' + e.id + '\')" aria-label="' + _T("app.c13.delete") + '">'
      +       '<i data-lucide="trash-2" style="width:13px;height:13px"></i>'
      +     '</button>'
      +   '</header>'
      +   '<h3 class="tl-card-title">' + escapeHtml(e.title || _T("app.c13.untitled")) + '</h3>'
      +   (e.summary ? '<p class="tl-card-summary">' + escapeHtml(e.summary) + '</p>' : '')
      +   (e.ocr ? '<details class="tl-card-details"><summary>' + _Tf("app.c13.viewFullOcr", { n: e.ocr.length }) + '</summary><pre class="tl-card-ocr">' + escapeHtml(e.ocr) + '</pre></details>' : '')
      +   (e.thumb ? '<img class="tl-card-thumb" src="' + e.thumb + '" alt="' + _T("app.c13.attachmentThumb") + '" />' : '')
      + '</article>';
  }).join('');
  if (typeof lucide !== 'undefined') lucide.createIcons();
}

