        var outline = ''
          + '<g fill="#FFFFFF" stroke="#1F3D58" stroke-width="2.2" stroke-linejoin="round" stroke-linecap="round" pointer-events="none">'
          +   '<ellipse cx="55" cy="22" rx="13" ry="15"/>'
