function loadRecordsPage() {
  if (typeof lucide !== 'undefined') lucide.createIcons();
  if (typeof updateDetectedDiseases === 'function') updateDetectedDiseases();
  // Issue #131：拉後端最新個人檔案、必要時做一次性 migration。
  // 拉完直接寫到欄位（避免 showPage 重渲整頁造成迴圈）。
  if (typeof migrateBasicInfoIfNeeded === 'function') {
    var before = JSON.stringify(getBasicInfo());
    migrateBasicInfoIfNeeded().then(function() {
      return fetchBasicInfoFromServer();
    }).then(function(remote) {
      if (!remote) return;
      if (JSON.stringify(getBasicInfo()) === before) return; // 沒變化
      _applyBasicInfoToForm(remote);
      if (typeof updateDetectedDiseases === 'function') updateDetectedDiseases();
    });
  }
}

// 把 info 物件套到 records 頁面上的表單欄位（不重渲整頁）
function _applyBasicInfoToForm(info) {
  var map = {
    'bi-gender': 'gender', 'bi-birthday': 'birthday', 'bi-blood': 'blood',
    'bi-height': 'height', 'bi-weight': 'weight',
    'bi-allergies': 'allergies', 'bi-conditions': 'conditions',
    'bi-current-disease': 'current_disease', 'bi-meds': 'meds',
    'bi-doctor-name': 'doctor_name', 'bi-hospital': 'hospital',
    'bi-emergency-name': 'emergency_name', 'bi-emergency-phone': 'emergency_phone',
  };
  Object.keys(map).forEach(function(elId) {
    var el = document.getElementById(elId);
    if (el) el.value = info[map[elId]] || '';
  });
  // 觸發顯示「年齡」與「BMI」這類派生欄位
  var ageDisp = document.getElementById('bi-age-display');
  if (ageDisp && info.birthday) ageDisp.textContent = calcAge(info.birthday);
  var bmiDisp = document.getElementById('bi-bmi-display');
  if (bmiDisp && info.height && info.weight) {
    var bmi = calcBMI(info.height, info.weight);
    bmiDisp.textContent = bmi ? 'BMI ' + bmi : '';
  }
}

// 從基本資料三個自由文字欄位即時辨識疾病，並把易讀名稱顯示成 pill
function updateDetectedDiseases() {
  var pillsEl = document.getElementById('bi-detected-diseases');
  if (!pillsEl) return;
  var current = document.getElementById('bi-current-disease');
  var conditions = document.getElementById('bi-conditions');
  var allergies = document.getElementById('bi-allergies');
  var combined = [
    current && current.value,
    conditions && conditions.value,
    allergies && allergies.value
  ].filter(Boolean).join('\n');
  var codes = (typeof detectIcd10FromText === 'function') ? detectIcd10FromText(combined) : [];
  if (!codes.length) {
    pillsEl.innerHTML = '<span style="color:var(--text-dim)">' + _T("app.c18.detectHint") + '</span>';
    return;
  }
  pillsEl.innerHTML = '<i data-lucide="sparkles" style="width:12px;height:12px;vertical-align:middle"></i> ' + _T("app.c18.autoDetected") +
    codes.map(function(c) {
      var name = (typeof bestNameForIcd10 === 'function') ? bestNameForIcd10(c) : c;
      return '<span style="display:inline-block;margin:2px 4px 2px 0;padding:2px 10px;border-radius:10px;background:var(--bg-soft);color:var(--text);font-size:.78rem">' +
             escapeHtml(name) + '</span>';
    }).join('');
  if (typeof lucide !== 'undefined') lucide.createIcons();
}

function saveBasicInfo() {
  const info = {
    gender: document.getElementById('bi-gender').value,
    birthday: document.getElementById('bi-birthday').value,
    blood: document.getElementById('bi-blood').value,
    height: document.getElementById('bi-height').value,
    weight: document.getElementById('bi-weight').value,
    allergies: document.getElementById('bi-allergies').value.trim(),
    conditions: document.getElementById('bi-conditions').value.trim(),
    current_disease: document.getElementById('bi-current-disease').value.trim(),
    meds: document.getElementById('bi-meds').value.trim(),
    doctor_name: document.getElementById('bi-doctor-name').value.trim(),
    hospital: document.getElementById('bi-hospital').value.trim(),
    emergency_name: document.getElementById('bi-emergency-name').value.trim(),
    emergency_phone: document.getElementById('bi-emergency-phone').value.trim(),
  };
  setBasicInfo(info);
  // 同步到後端 — Issue #131：不再只存 localStorage。失敗不擋 UI（本地已存）。
  syncBasicInfoToServer(info).then(function(ok) {
    if (!ok) showToast && showToast(_T('app.c6.savedLocalSyncFail'), 'warning');
  });

  // 自動辨識疾病 → user.icd10_codes，衛教頁的「我的疾病書架」就會出現
  if (typeof detectIcd10FromText === 'function') {
    var combined = [info.current_disease, info.conditions, info.allergies].filter(Boolean).join('\n');
    var codes = detectIcd10FromText(combined);
    var u = getCurrentUser();
    // 只在真的有登入帳號時才寫回 user 物件，避免造出 id-less 假 user
    // 干擾 /auth/user/{id} 等帳號 API。Guest/demo 的書架還是會走
    // resolvePatientIcd10Codes 的 basicInfo fallback，所以不會壞掉。
    if (u && u.id) {
      u.icd10_codes = codes;
      setCurrentUser(u);
    }
  }

  // 慢病（高血壓 / 糖尿病）自動建立定時量測提醒
  try { ensureChronicMeasurementReminders(info); } catch (e) {}

  const msg = document.getElementById('bi-msg');
  if (msg) {
    msg.textContent = _T('rec.msg.savedLocal');
    msg.hidden = false;
    setTimeout(() => { msg.hidden = true; }, 2000);
  }
  showToast && showToast(_T('rec.toast.saved'), 'success');
}

// 根據疾病自動建立每日量測 reminder（高血壓 → 早晚量血壓；糖尿病 → 早餐前血糖）。
// 用 localStorage 標記避免重複建立；移除疾病後不會刪除既有 reminder（使用者可手動關）。
const _CHRONIC_RULES = [
  { keywords: ['高血壓', 'hypertension'], slots: [
    { kind: 'bp', time: '07:30', label: '早上量血壓' },
    { kind: 'bp', time: '21:00', label: '晚上量血壓' },
  ]},
  { keywords: ['糖尿病', 'diabetes'], slots: [
    { kind: 'glucose', time: '06:30', label: '空腹血糖' },
  ]},
];

function ensureChronicMeasurementReminders(info) {
  const text = [info.conditions || '', info.current_disease || ''].join(' ').toLowerCase();
  const pid = getStablePatientId();
  if (!pid) return;
  const seenKey = 'mdpiece_chronic_rem_' + pid;
  let seen;
  try { seen = JSON.parse(localStorage.getItem(seenKey) || '{}'); } catch (e) { seen = {}; }

  _CHRONIC_RULES.forEach(rule => {
    const hit = rule.keywords.some(k => text.indexOf(k.toLowerCase()) >= 0);
    if (!hit) return;
    rule.slots.forEach(slot => {
      const tag = rule.keywords[0] + '|' + slot.kind + '|' + slot.time;
      if (seen[tag]) return;
      const [hh, mm] = slot.time.split(':').map(Number);
      const next = new Date();
      next.setHours(hh, mm, 0, 0);
      if (next.getTime() <= Date.now()) next.setDate(next.getDate() + 1);
      const measureLabel = { bp: '血壓', glucose: '血糖' }[slot.kind] || slot.kind;
      fetch(`${API}/reminders/`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          patient_id: pid,
          reminder_type: 'measurement',
          title: slot.label,
          body: `每天記得量一下${measureLabel}，幫醫師掌握你的狀況。`,
          frequency: 'daily',
          time_of_day: slot.time,
          scheduled_at: next.toISOString(),
          source: 'auto',
          priority: 'normal',
        }),
      }).then(r => {
        if (r.ok) { seen[tag] = Date.now(); localStorage.setItem(seenKey, JSON.stringify(seen)); }
      }).catch(() => {});
    });
  });
}

function copyBasicInfo() {
  const info = getBasicInfo();
  const u = getCurrentUser() || {};
  const lines = [_T('rec.copy.header')];
  if (u.nickname) lines.push(_T('rec.copy.name') + u.nickname);
  const genderMap = { male: _T('rec.opt.male'), female: _T('rec.opt.female'), other: _T('rec.opt.other') };
  if (info.gender) lines.push(_T('rec.copy.gender') + (genderMap[info.gender] || info.gender));
  if (info.birthday) {
    const age = calcAge(info.birthday);
    lines.push(_T('rec.copy.birthday') + info.birthday + (age ? '（' + age + '）' : ''));
  }
  if (info.blood) lines.push(_T('rec.copy.blood') + info.blood);
  if (info.height) lines.push(_T('rec.copy.height') + info.height + ' cm');
  if (info.weight) lines.push(_T('rec.copy.weight') + info.weight + ' kg');
  const bmi = calcBMI(info.height, info.weight);
  if (bmi) lines.push('BMI：' + bmi);
  if (info.allergies) lines.push(_T('rec.copy.allergies') + info.allergies);
  if (info.conditions) lines.push(_T('rec.copy.conditions') + info.conditions);
  if (info.current_disease) lines.push(_T('rec.copy.currentDisease') + info.current_disease);
  if (info.meds) lines.push(_T('rec.copy.meds') + info.meds);
  if (info.doctor_name || info.hospital) {
    lines.push(_T('rec.copy.doctorName') + [info.doctor_name, info.hospital].filter(Boolean).join('｜'));
  }
  if (info.emergency_name || info.emergency_phone) {
    lines.push(_T('rec.copy.emergency') + [info.emergency_name, info.emergency_phone].filter(Boolean).join(' '));
  }
  if (lines.length === 1) {
    showToast && showToast(_T('rec.toast.empty'), 'warning');
    return;
  }
  const text = lines.join('\n');
  if (navigator.clipboard && navigator.clipboard.writeText) {
    navigator.clipboard.writeText(text).then(
      () => showToast && showToast(_T('rec.toast.copied'), 'success'),
      () => showToast && showToast(_T('rec.toast.copyFail'), 'warning')
    );
  } else {
    const ta = document.createElement('textarea');
    ta.value = text;
    document.body.appendChild(ta);
    ta.select();
    try { document.execCommand('copy'); showToast && showToast(_T('rec.toast.copied'), 'success'); }
    catch { showToast && showToast(_T('rec.toast.copyFail'), 'warning'); }
    document.body.removeChild(ta);
  }
}

// ─── Toast 通知 ──────────────────────────────────────────

function showToast(msg, type) {
  type = type || "info";
  var existing = document.getElementById("toast-container");
  if (!existing) {
    existing = document.createElement("div");
    existing.id = "toast-container";
    // 位置由 CSS #toast-container 控制（手機改底部置中，見 style.css media query）
    document.body.appendChild(existing);
  }
  // Dedupe：同訊息若還在畫面上，就更新計數而不疊新的。
  var key = type + '|' + msg;
  var dupe = existing.querySelector('[data-toast-key="' + CSS.escape(key) + '"]');
  if (dupe) {
    var count = (parseInt(dupe.dataset.count, 10) || 1) + 1;
    dupe.dataset.count = count;
    var dmsg = dupe.querySelector('.toast-msg');
    if (dmsg) dmsg.textContent = msg + ' ×' + count;
    dupe.style.opacity = "1";
    clearTimeout(dupe._fadeTimer);
    dupe._fadeTimer = setTimeout(function() { _toastDismiss(dupe); }, 3000);
    return;
  }
  // 淡色底 + 左側色條 + 深色字 + 圓形圖示，與全站 .pill / warm 風格一致
  var palette = {
    success: { bg: "#E7F8F2", bar: "#00C29A", fg: "#0A6E5C", icon: "M20 6L9 17l-5-5" },
    error:   { bg: "#FCEDEC", bar: "#D94D4D", fg: "#9A2B2B", icon: "M18 6L6 18M6 6l12 12" },
    info:    { bg: "#EAF0FE", bar: "#2B5CE6", fg: "#1E3FA0", icon: "M12 16v-4M12 8h.01" },
    warning: { bg: "#FDF3E3", bar: "#E8A84B", fg: "#8A5A12", icon: "M12 9v4M12 17h.01" },
  };
  var c = palette[type] || palette.info;
  var toast = document.createElement("div");
  toast.dataset.toastKey = key;
  toast.dataset.count = '1';
  toast.style.cssText = "pointer-events:auto;display:flex;align-items:center;gap:10px;padding:12px 16px;border-radius:12px;border-left:4px solid " + c.bar + ";background:" + c.bg + ";color:" + c.fg + ";font-size:0.9rem;font-weight:500;box-shadow:0 6px 20px rgba(20,40,60,0.14);max-width:360px;opacity:0;transform:translateX(16px);transition:opacity 0.28s ease,transform 0.28s ease";
  // 圖示（固定 SVG path，非使用者資料，無 XSS 風險）
  var iconWrap = document.createElement("div");
  iconWrap.style.cssText = "flex:none;width:22px;height:22px;border-radius:50%;display:flex;align-items:center;justify-content:center;background:" + c.bar;
  iconWrap.innerHTML = '<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><path d="' + c.icon + '"/></svg>';
  var msgEl = document.createElement("span");
  msgEl.className = "toast-msg";
  msgEl.textContent = msg;
  toast.appendChild(iconWrap);
  toast.appendChild(msgEl);
  existing.appendChild(toast);
  // 進場：下一幀滑入
  requestAnimationFrame(function() { toast.style.opacity = "1"; toast.style.transform = "translateX(0)"; });
  toast._fadeTimer = setTimeout(function() { _toastDismiss(toast); }, 3000);
}

function _toastDismiss(el) {
  el.style.opacity = "0";
  el.style.transform = "translateX(16px)";
  setTimeout(function() { el.remove(); }, 300);
}

// ─── 記憶尋回 toast（design-language.md §12）──────────────────────
// 絕不用「成就解鎖」：用「記憶回來了」的語氣＋斜體英文副標、貝殼/書/羅盤插圖。
// 與一般 showToast 分開的置中容器，視覺上更像故事書的提示（sea-restore 進場）。
var _MEM_SUB = {
  'mem.toast.clue': 'A sea breeze carries a new clue',
  'mem.toast.story': 'A lost story resurfaces',
  'mem.toast.journey': 'Your journey grows more whole',
};
var _MEM_ICON = { 'mem.toast.clue': 'shell', 'mem.toast.story': 'book-open', 'mem.toast.journey': 'compass' };

function showMemoryToast(key) {
  var box = document.getElementById('mem-toast-container');
  if (!box) {
    box = document.createElement('div');
    box.id = 'mem-toast-container';
    document.body.appendChild(box);
  }
  var el = document.createElement('div');
  el.className = 'mem-toast';
  el.innerHTML = ''
    + '<span class="mem-toast-seal"><i data-lucide="' + (_MEM_ICON[key] || 'shell') + '"></i></span>'
    + '<span class="mem-toast-body">'
    +   '<span class="mem-toast-title">' + escapeHtml(_T(key)) + '</span>'
    +   '<span class="mem-toast-sub">' + escapeHtml(_MEM_SUB[key] || '') + '</span>'
    + '</span>';
  box.appendChild(el);
  if (typeof lucide !== 'undefined') lucide.createIcons();
  setTimeout(function () {
    el.classList.add('leaving');
    setTimeout(function () { el.remove(); }, 500);
  }, 4200);
}

// 比對「這次看到的拼圖狀態」與上次記住的，偵測是否有新碎片／新章節回來 →
// 觸發記憶 toast。純確定性比對（規則 5），首次載入只記住、不打擾。
function _maybeMemoryToast(puzzle) {
  if (!puzzle || !puzzle.board) return;
  var board = puzzle.board;
  var ym = board.year_month || '';
  var unlocked = board.unlocked_count || 0;
  var doneScenes = _journeyDoneScenes(puzzle.collection);
  var chapters = Object.keys(doneScenes).sort().join(',');
  var STORE = 'mdpiece_pz_seen';
  var prev = null;
  try { prev = JSON.parse(localStorage.getItem(STORE) || 'null'); } catch (e) {}
  try { localStorage.setItem(STORE, JSON.stringify({ ym: ym, unlocked: unlocked, chapters: chapters })); } catch (e) {}
  if (!prev) return;  // 首次：只記住、不打擾
  var prevCh = (prev.chapters ? prev.chapters.split(',') : []).filter(Boolean).length;
  var curCh = (chapters ? chapters.split(',') : []).filter(Boolean).length;
  if (curCh > prevCh) {
    // 完成新章節：第一章用「故事重新浮現」，之後用「旅程更完整」（確定性、非隨機）
    showMemoryToast(curCh >= 2 ? 'mem.toast.journey' : 'mem.toast.story');
  } else if (ym === prev.ym && unlocked > (prev.unlocked || 0)) {
    showMemoryToast('mem.toast.clue');  // 本月又尋回一塊碎片
  }
}

// 把 fetch response 翻成人話：優先用 backend 的 JSON `detail`（中文），fallback 才用 HTTP code
// FastAPI 422 的 detail 是 [{loc, msg, type}, ...] 陣列，要展開成可讀文字，不能 String() 變 [object Object]
async function _parseApiError(r) {
  var status = r.status;
  try {
    var data = await r.json();
    if (data && data.detail) return _formatErrorDetail(data.detail);
    if (data && data.error) return _formatErrorDetail(data.error);
  } catch (_) { /* not JSON */ }
  if (status === 404) return _T('app.c19.err404');
  if (status === 401 || status === 403) return _Tf('app.c19.errNoPerm', { status: status });
  if (status === 503) return _T('app.c19.err503');
  if (status >= 500) return _Tf('app.c19.err500', { status: status });
  return _Tf('app.c19.errGeneric', { status: status });
}

function _formatErrorDetail(detail) {
  if (typeof detail === 'string') return detail;
  if (Array.isArray(detail)) {
    return detail.map(_formatErrorDetail).filter(Boolean).join('；');
  }
  if (detail && typeof detail === 'object') {
    // FastAPI 422: {loc:[...], msg:"...", type:"..."}
    if (detail.msg) {
      var loc = Array.isArray(detail.loc) ? detail.loc.slice(1).join('.') : '';
      return loc ? (loc + '：' + detail.msg) : detail.msg;
    }
    return JSON.stringify(detail);
  }
  return String(detail);
}

