// 把醫療分類映射成淺顯的「功能」說明 — 患者不一定看得懂藥袋上的英文分類，
// 所以提供一個保底文案；若藥物本身有 purpose，仍以 purpose 為主。
function _bld_MED_CATEGORY_FUNCTION() { return {
  '降血壓': _T("app.d32.funcBloodPressure"),
  '高血壓': _T("app.d32.funcBloodPressure"),
  '降血糖': _T("app.d32.funcBloodSugar"),
  '糖尿病': _T("app.d32.funcBloodSugar"),
  '降血脂': _T("app.d32.funcBloodLipid"),
  '高血脂': _T("app.d32.funcBloodLipid"),
  '心血管': _T("app.d32.funcCardiovascular"),
  '抗凝血': _T("app.d32.funcAnticoagulant"),
  '利尿劑': _T("app.d32.funcDiuretic"),
  '止痛': _T("app.d32.funcPainkiller"),
  '消炎': _T("app.d32.funcAntiInflammatory"),
  '抗生素': _T("app.d32.funcAntibiotic"),
  '抗組織胺': _T("app.d32.funcAntihistamine"),
  '腸胃': _T("app.d32.funcGastro"),
  '制酸劑': _T("app.d32.funcAntacid"),
  '助眠': _T("app.d32.funcSleepAid"),
  '安眠': _T("app.d32.funcSleepAid"),
  '抗焦慮': _T("app.d32.funcAntiAnxiety"),
  '抗憂鬱': _T("app.d32.funcAntidepressant"),
  '甲狀腺': _T("app.d32.funcThyroid"),
  '骨質疏鬆': _T("app.d32.funcOsteoporosis"),
  '氣喘': _T("app.d32.funcAsthma"),
  '止咳': _T("app.d32.funcCoughSuppressant"),
  '化痰': _T("app.d32.funcExpectorant"),
}; }
var MED_CATEGORY_FUNCTION = _bld_MED_CATEGORY_FUNCTION();

function _medCategoryFunction(med) {
  if (med && med.purpose) return String(med.purpose).trim();
  var cat = (med && med.category) ? String(med.category).trim() : '';
  if (!cat) return '';
  if (MED_CATEGORY_FUNCTION[cat]) return MED_CATEGORY_FUNCTION[cat];
  var keys = Object.keys(MED_CATEGORY_FUNCTION);
  for (var i = 0; i < keys.length; i++) {
    if (cat.indexOf(keys[i]) !== -1) return MED_CATEGORY_FUNCTION[keys[i]];
  }
  return '';
}

function _medUseCase(med) {
  if (med && med.instructions) {
    var ins = String(med.instructions).trim();
    if (ins) return ins;
  }
  if (med && med.category) return String(med.category).trim();
  return '';
}

function _renderMedTypesFilterBar(meds) {
  var bar = document.getElementById('mtl-filterbar');
  if (!bar) return;
  var counts = { __all__: meds.length };
  meds.forEach(function(m) {
    var c = (m.category || _T('meds.types.uncategorized')).trim();
    counts[c] = (counts[c] || 0) + 1;
  });
  var cats = Object.keys(counts).filter(function(k){ return k !== '__all__'; }).sort(function(a, b){
    return counts[b] - counts[a];
  });
  var chips = [{ key: '__all__', label: _T('meds.types.filter.all'), count: counts.__all__ }];
  cats.forEach(function(c) { chips.push({ key: c, label: c, count: counts[c] }); });

  bar.innerHTML = chips.map(function(c) {
    var active = c.key === _medTypesFilter ? ' mtl-chip-active' : '';
    return '<button type="button" class="mtl-chip' + active + '"'
      + ' data-key="' + escapeHtml(c.key) + '"'
      + ' onclick="_setMedTypesFilter(this.dataset.key)"'
      + ' aria-pressed="' + (c.key === _medTypesFilter) + '">'
      + escapeHtml(c.label) + '<span class="mtl-chip-num">' + c.count + '</span>'
      + '</button>';
  }).join('');
}

function _setMedTypesFilter(key) {
  _medTypesFilter = key || '__all__';
  var meds = (_medsList || []).filter(function(m){ return m.active !== 0; });
  _renderMedTypesFilterBar(meds);
  _renderMedTypesList(meds);
}

function _renderMedTypesList(meds) {
  var body = document.getElementById('mtl-body');
  if (!body) return;

  var perMedStats = {};
  if (_medsLastStats && Array.isArray(_medsLastStats.medications)) {
    _medsLastStats.medications.forEach(function(m) {
      perMedStats[String(m.id)] = m;
    });
  }

  var filtered = _medTypesFilter === '__all__'
    ? meds.slice()
    : meds.filter(function(m) {
        var c = (m.category || _T('meds.types.uncategorized')).trim();
        return c === _medTypesFilter;
      });

  if (!filtered.length) {
    body.innerHTML = '<div class="mtl-empty"><i data-lucide="inbox" style="width:22px;height:22px"></i>'
      + '<p>' + _T('meds.types.filterEmpty') + '</p></div>';
    if (typeof lucide !== 'undefined') lucide.createIcons();
    return;
  }

  var cardsHtml = filtered.map(function(med, idx) {
    var stats = perMedStats[String(med.id)] || {};
    var name = escapeHtml(med.name || _T('meds.card.unnamed'));
    var dosage = med.dosage ? ' <span class="mtl-card-dose">' + escapeHtml(med.dosage) + '</span>' : '';
    var category = med.category ? '<span class="mtl-card-tag">' + escapeHtml(med.category) + '</span>' : '';

    var fn = _medCategoryFunction(med);
    var fnRow = fn
      ? '<div class="mtl-row mtl-row-fn"><span class="mtl-row-ico">🎯</span><div><div class="mtl-row-lbl">' + _T('meds.types.row.fn') + '</div><div class="mtl-row-val">' + escapeHtml(fn) + '</div></div></div>'
      : '<div class="mtl-row mtl-row-fn mtl-row-muted"><span class="mtl-row-ico">🎯</span><div><div class="mtl-row-lbl">' + _T('meds.types.row.fn') + '</div><div class="mtl-row-val">' + _T('meds.types.row.fnMissing') + '</div></div></div>';

    var use = _medUseCase(med);
    var useRow = use
      ? '<div class="mtl-row"><span class="mtl-row-ico">📌</span><div><div class="mtl-row-lbl">' + _T('meds.types.row.use') + '</div><div class="mtl-row-val">' + escapeHtml(use) + '</div></div></div>'
      : '';

    var freqText = '';
    if (med.frequency) freqText += med.frequency;
    if (med.usage) freqText += (freqText ? '　·　' : '') + med.usage;
    if (med.duration) freqText += (freqText ? '　·　' : '') + med.duration;
    var freqRow = freqText
      ? '<div class="mtl-row"><span class="mtl-row-ico">⏱</span><div><div class="mtl-row-lbl">' + _T('meds.types.row.freq') + '</div><div class="mtl-row-val">' + escapeHtml(freqText) + '</div></div></div>'
      : '';

    var rate = stats.adherence_rate != null ? Number(stats.adherence_rate) : null;
    var rateClass = rate == null ? 'na' : (rate >= 80 ? 'ok' : (rate >= 50 ? 'warn' : 'low'));
    var rateText = rate == null ? '—' : rate + '%';
    var eff = stats.avg_effectiveness != null ? Number(stats.avg_effectiveness).toFixed(1) + ' / 5' : '—';
    var doses = stats.total_logs != null ? stats.total_logs : 0;

    var metrics = ''
      + '<div class="mtl-metrics">'
      +   '<div class="mtl-metric"><div class="mtl-metric-lbl">' + _T('meds.types.metric.adherence') + '</div>'
      +     '<div class="mtl-metric-bar"><div class="mtl-metric-fill mtl-metric-fill-' + rateClass + '" style="width:' + (rate == null ? 0 : Math.max(2, Math.min(100, rate))) + '%"></div></div>'
      +     '<div class="mtl-metric-val mtl-metric-val-' + rateClass + '">' + rateText + '</div>'
      +   '</div>'
      +   '<div class="mtl-metric mtl-metric-sm"><div class="mtl-metric-lbl">' + _T('meds.types.metric.eff') + '</div><div class="mtl-metric-val">' + eff + '</div></div>'
      +   '<div class="mtl-metric mtl-metric-sm"><div class="mtl-metric-lbl">' + _T('meds.types.metric.logs') + '</div><div class="mtl-metric-val">' + doses + '</div></div>'
      + '</div>';

    var actions = ''
      + '<div class="mtl-actions">'
      +   '<button type="button" class="mtl-action mtl-action-primary" data-id="' + escapeHtml(med.id) + '" onclick="closeMedTypesSheet(); openMedDetail(this.dataset.id)">'
      +     '<i data-lucide="bar-chart-3" style="width:13px;height:13px"></i> ' + _T('meds.types.action.detail')
      +   '</button>'
      +   '<button type="button" class="mtl-action" data-name="' + escapeHtml(med.name || '') + '" onclick="openDrugSearchFor(this.dataset.name)">'
      +     '<i data-lucide="book-open" style="width:13px;height:13px"></i> ' + _T('meds.types.action.encyclopedia')
      +   '</button>'
      +   '<button type="button" class="mtl-action" data-id="' + escapeHtml(med.id) + '" data-name="' + escapeHtml(med.name || '') + '" onclick="showEffectForm(this.dataset.id, this.dataset.name); closeMedTypesSheet();">'
      +     '<i data-lucide="star" style="width:13px;height:13px"></i> ' + _T('meds.types.action.effect')
      +   '</button>'
      + '</div>';

    return ''
      + '<article class="mtl-card">'
      +   '<header class="mtl-card-head">'
      +     '<span class="mtl-card-idx">' + (idx + 1) + '</span>'
      +     '<div class="mtl-card-title-wrap">'
      +       '<div class="mtl-card-title">' + name + dosage + '</div>'
      +       (category ? '<div class="mtl-card-meta">' + category + '</div>' : '')
      +     '</div>'
      +   '</header>'
      +   '<div class="mtl-card-body">'
      +     fnRow + useRow + freqRow
      +     metrics
      +     actions
      +   '</div>'
      + '</article>';
  }).join('');

  body.innerHTML = cardsHtml;
  if (typeof lucide !== 'undefined') lucide.createIcons();
}
async function _loadMedDetail(medId, med) {
  var pid = _medsPatientId || (typeof getStablePatientId === 'function' ? getStablePatientId() : null);
  if (!pid) return;
  // 三筆 fetch 同時起跑（30 天 logs / 全部 effects / 整體 stats）
  var pLogs = apiFetch(API + '/medications/logs?patient_id=' + pid + '&medication_id=' + medId + '&days=30')
    .then(function(r){return r.json();}).catch(function(){ return { logs: [] }; });
  var pEffects = apiFetch(API + '/medications/effects?patient_id=' + pid + '&medication_id=' + medId)
    .then(function(r){return r.json();}).catch(function(){ return { effects: [] }; });
  var pStats = apiFetch(API + '/medications/stats?patient_id=' + pid + '&days=30')
    .then(function(r){return r.json();}).catch(function(){ return { medications: [] }; });

  var arr;
  try { arr = await Promise.all([pLogs, pEffects, pStats]); }
  catch (e) { arr = [{logs:[]}, {effects:[]}, {medications:[]}]; }

  var logs    = (arr[0] && arr[0].logs)    || [];
  var effects = (arr[1] && arr[1].effects) || [];
  var perMedStats = ((arr[2] && arr[2].medications) || []).find(function(m){ return String(m.id) === String(medId); }) || {};

  // 統計（最近 30 天 — 但只計算「藥物加入後」的活躍日數，避免新藥被
  // 當成過去 30 天都沒吃而扣分；adherence 分母 = expectedPerDay * activeDays）
  var taken   = logs.filter(function(l){ return l && l.taken !== false; }).length;
  var skipped = logs.filter(function(l){ return l && l.taken === false; }).length;
  var expectedPerDay = (med.is_other ? 0 : (med.slots && med.slots.length ? med.slots.length : 1));
  var activeDays = 30;
  if (med.created_at) {
    var startMs = new Date(med.created_at).getTime();
    if (!isNaN(startMs)) {
      var elapsedDays = Math.floor((Date.now() - startMs) / 86400000) + 1; // 含今日
      activeDays = Math.max(1, Math.min(30, elapsedDays));
    }
  }
  var expectedTotal = expectedPerDay * activeDays;
  var missed = Math.max(0, expectedTotal - taken - skipped);
  var rate = expectedTotal > 0 ? Math.round(taken / expectedTotal * 100) : 0;
  var avgEffect = perMedStats.avg_effectiveness != null
    ? Number(perMedStats.avg_effectiveness).toFixed(1)
    : (effects.length
        ? (effects.reduce(function(s,e){return s + (e.effectiveness || 0);}, 0) / effects.length).toFixed(1)
        : '—');

  // 日曆熱區（30 天）
  var calCells = [];
  var today = new Date(); today.setHours(0,0,0,0);
  var byDay = {};
  logs.forEach(function(l) {
    var d = (l.taken_at || '').slice(0, 10);
    if (!d) return;
    if (!byDay[d]) byDay[d] = { taken: 0, skipped: 0 };
    if (l.taken === false) byDay[d].skipped++; else byDay[d].taken++;
  });
  for (var i = 29; i >= 0; i--) {
    var d = new Date(today); d.setDate(d.getDate() - i);
    var key = d.toISOString().slice(0,10);
    var st = byDay[key];
    var label, tone;
    if (!st) { tone = 'none'; label = _T('app.c21.noRecord'); }
    else if (expectedPerDay && st.taken >= expectedPerDay) { tone = 'ok'; label = _T('app.c21.done'); }
    else if (st.taken > 0) { tone = 'partial'; label = _T('app.c21.partial'); }
    else if (st.skipped > 0) { tone = 'miss'; label = _T('app.c21.missedOrSkipped'); }
    else { tone = 'none'; label = _T('app.c21.noRecord'); }
    calCells.push('<div class="mdm-cal-cell mdm-cal-' + tone + '" title="' + (d.getMonth()+1) + '/' + d.getDate() + '：' + label + '"></div>');
  }

  // 副作用 tag cloud（彙整出現次數）
  var sideMap = {};
  effects.forEach(function(e) {
    var raw = (e.side_effects || '').trim();
    if (!raw) return;
    raw.split(/[,，、;；\s]+/).forEach(function(t) {
      t = t.trim(); if (!t) return;
      sideMap[t] = (sideMap[t] || 0) + 1;
    });
  });
  var sideEntries = Object.keys(sideMap).map(function(k){return [k, sideMap[k]];}).sort(function(a,b){return b[1]-a[1];}).slice(0, 8);
  var sideHtml = sideEntries.length
    ? sideEntries.map(function(p){ return '<span class="mdm-side-tag">' + escapeHtml(p[0]) + ' <small>×' + p[1] + '</small></span>'; }).join('')
    : '<p class="mdm-empty">' + _T('app.c21.noSideEffectYet') + '</p>';

  // 療效走勢（迷你折線）
  var effectChart = _renderMedEffectChart(effects);

  // 近期 8 筆紀錄
  var recentMerged = logs.slice(0, 8).map(function(l) {
    var t = new Date(l.taken_at || l.created_at);
    var mm = (t.getMonth()+1) + '/' + t.getDate();
    var hh = String(t.getHours()).padStart(2,'0') + ':' + String(t.getMinutes()).padStart(2,'0');
    var status = l.taken === false ? '<span class="mdm-rec-skip">' + _T('app.c21.skip') + '</span>' : '<span class="mdm-rec-ok">' + _T('app.c21.taken') + '</span>';
    return '<li class="mdm-rec-item"><span class="mdm-rec-when">' + mm + '　' + hh + '</span>' + status + '</li>';
  }).join('');

  var body = document.getElementById('mdm-body');
  if (!body) return;
  body.innerHTML = ''
    // 頂端 hero — 大字服藥率 + 4 個 stat
    + '<section class="mdm-section mdm-hero">'
    +   '<div class="mdm-hero-ring">'
    +     '<svg viewBox="0 0 100 100" width="110" height="110">'
    +       '<circle cx="50" cy="50" r="42" fill="none" stroke="rgba(31,61,88,0.08)" stroke-width="9"/>'
    +       '<circle cx="50" cy="50" r="42" fill="none" stroke="var(--accent)" stroke-width="9" stroke-linecap="round" '
    +         'stroke-dasharray="264" stroke-dashoffset="' + (264 - 264 * rate / 100) + '" transform="rotate(-90 50 50)"/>'
    +     '</svg>'
    +     '<div class="mdm-hero-ring-num"><span>' + rate + '</span><small>%</small></div>'
    +   '</div>'
    +   '<div class="mdm-hero-side">'
    +     '<div class="mdm-hero-label">' + _Tf('app.c21.last30Status', { n: activeDays }) + '</div>'
    +     '<div class="mdm-stat-grid">'
    +       '<div class="mdm-stat"><span class="mdm-stat-num">' + taken + '</span><span class="mdm-stat-lbl">' + _T('app.c21.taken') + '</span></div>'
    +       '<div class="mdm-stat"><span class="mdm-stat-num">' + missed + '</span><span class="mdm-stat-lbl">' + _T('app.c21.missed') + '</span></div>'
    +       '<div class="mdm-stat"><span class="mdm-stat-num">' + skipped + '</span><span class="mdm-stat-lbl">' + _T('app.c21.skip') + '</span></div>'
    +       '<div class="mdm-stat"><span class="mdm-stat-num">' + avgEffect + '</span><span class="mdm-stat-lbl">' + _T('app.c21.avgEffect') + '</span></div>'
    +     '</div>'
    +   '</div>'
    + '</section>'

    + '<section class="mdm-section">'
    +   '<h4 class="mdm-section-title">' + _T('app.c21.dailyStatus') + '</h4>'
    +   '<div class="mdm-cal">' + calCells.join('') + '</div>'
    +   '<div class="mdm-cal-legend">'
    +     '<span><i class="mdm-dot mdm-cal-ok"></i> ' + _T('app.c21.done') + '</span>'
    +     '<span><i class="mdm-dot mdm-cal-partial"></i> ' + _T('app.c21.partial') + '</span>'
    +     '<span><i class="mdm-dot mdm-cal-miss"></i> ' + _T('app.c21.missedOrSkipped') + '</span>'
    +     '<span><i class="mdm-dot mdm-cal-none"></i> ' + _T('app.c21.noRecord') + '</span>'
    +   '</div>'
    + '</section>'

    + '<section class="mdm-section">'
    +   '<h4 class="mdm-section-title">' + _T('app.c21.effectTrend') + '</h4>'
    +   effectChart
    + '</section>'

    + '<section class="mdm-section">'
    +   '<h4 class="mdm-section-title">' + _T('app.c21.recordedSideEffects') + '</h4>'
    +   '<div class="mdm-side-cloud">' + sideHtml + '</div>'
    + '</section>'

    + '<section class="mdm-section">'
    +   '<h4 class="mdm-section-title">' + _T('app.c21.recentRecords') + '</h4>'
    +   (recentMerged ? '<ul class="mdm-rec-list">' + recentMerged + '</ul>' : '<p class="mdm-empty">' + _T('app.c21.no30DayRecord') + '</p>')
    + '</section>'
    + '<p class="mdm-foot-warn"><i data-lucide="info" style="width:11px;height:11px"></i> ' + _T('app.c21.footWarn') + '</p>';
  if (typeof lucide !== 'undefined') lucide.createIcons();
}

// 療效走勢迷你折線（最近 14 筆評分）
function _renderMedEffectChart(effects) {
  var pts = (effects || []).slice(0, 14).reverse();
  if (!pts.length) return '<p class="mdm-empty">' + _T('app.c21.noEffectChartYet') + '</p>';
  var W = 280, H = 90, PAD = 12;
  var n = pts.length;
  var xs = function(i) { return n === 1 ? W/2 : PAD + (W - 2*PAD) * (i / (n - 1)); };
  var ys = function(v) { return H - PAD - (H - 2*PAD) * ((v - 1) / 4); };
  var path = pts.map(function(p, i){ return (i === 0 ? 'M ' : 'L ') + xs(i).toFixed(1) + ' ' + ys(p.effectiveness || 1).toFixed(1); }).join(' ');
  var dots = pts.map(function(p, i){
    return '<circle cx="' + xs(i).toFixed(1) + '" cy="' + ys(p.effectiveness || 1).toFixed(1) + '" r="3.2" fill="var(--accent)"/>';
  }).join('');
  return '<svg class="mdm-effect-chart" viewBox="0 0 ' + W + ' ' + H + '" width="100%" height="' + H + '">'
    + '<line x1="' + PAD + '" y1="' + ys(1) + '" x2="' + (W-PAD) + '" y2="' + ys(1) + '" stroke="rgba(31,61,88,0.08)"/>'
    + '<line x1="' + PAD + '" y1="' + ys(3) + '" x2="' + (W-PAD) + '" y2="' + ys(3) + '" stroke="rgba(31,61,88,0.06)" stroke-dasharray="2 3"/>'
    + '<line x1="' + PAD + '" y1="' + ys(5) + '" x2="' + (W-PAD) + '" y2="' + ys(5) + '" stroke="rgba(31,61,88,0.08)"/>'
    + '<text x="2" y="' + (ys(5)+3) + '" font-size="9" fill="var(--text-muted)">★5</text>'
    + '<text x="2" y="' + (ys(1)+3) + '" font-size="9" fill="var(--text-muted)">★1</text>'
    + '<path d="' + path + '" fill="none" stroke="var(--accent)" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>'
    + dots
    + '</svg>'
    + '<p class="mdm-effect-hint">' + _Tf('app.c21.lastNRatings', { n: n }) + '</p>';
}

// 點卡片即打卡：固定時段藥（早/中/晚）直接寫入；
// 「其他」型藥（每 X 小時 / PRN）也走同一條 POST /log，
// 後端會在劑量間隔未到時回 409 dose_too_soon，由 logMedTaken 攔下並彈警告。
function tapMedTake(medId, slotKey) {
  logMedTaken(medId, true);
}

// 把藥袋／藥單照片預處理：
//   1) EXIF 自動轉正（手機直拍常帶 rotation flag）
//   2) 直接縮到 2400px 長邊內、JPEG 0.9（避開 12MP 全尺寸 canvas 在手機上 OOM）
// 之前 v53 加的「裁黑邊」需要在 12MP canvas 上跑 getImageData（48MB Uint8 array），
// 舊一點的手機會 OOM 導致整段 fallback 走 raw 檔，原檔太大（5-10MB）就過不了
// Vercel 4.5MB 上傳上限 → 使用者看到「沒辦法上傳」。
// 裁黑邊功能先拿掉，等之後改用 worker / 在縮圖後再裁。
function _compressMedPhoto(file) {
  function loadBitmap(blob) {
    if (typeof createImageBitmap !== "function") {
      return Promise.reject(new Error("createImageBitmap not supported"));
    }
    try {
      // imageOrientation: 'from-image' 會自動套 EXIF rotation
      return createImageBitmap(blob, { imageOrientation: "from-image" });
    } catch (_) {
      return createImageBitmap(blob);
    }
  }

  function loadImage(blob) {
    return new Promise(function(resolve, reject) {
      var url = URL.createObjectURL(blob);
      var img = new Image();
      img.onload = function() {
        URL.revokeObjectURL(url);
        resolve(img);
      };
      img.onerror = function() {
        URL.revokeObjectURL(url);
        reject(new Error("Image load failed"));
      };
      img.src = url;
    });
  }

  function drawAndExport(source, srcW, srcH) {
    var maxEdge = 2400;
    var w = srcW, h = srcH;
    if (Math.max(w, h) > maxEdge) {
      var scale = maxEdge / Math.max(w, h);
      w = Math.round(w * scale);
      h = Math.round(h * scale);
    }
    var canvas = document.createElement("canvas");
    canvas.width = w; canvas.height = h;
    var ctx = canvas.getContext("2d");
    ctx.fillStyle = "#fff";  // 白底 — 處理透明 PNG / JPEG 黑底
    ctx.fillRect(0, 0, w, h);
    ctx.drawImage(source, 0, 0, w, h);
    return canvas.toDataURL("image/jpeg", 0.9);
  }

  return new Promise(function(resolve) {
    function fallbackRawFile() {
      // 最後手段：直接送原檔（檔案太大時 server 會回 413，前端顯示「上傳失敗」）
      var reader = new FileReader();
      reader.onload = function(e) { resolve({ dataUrl: e.target.result, mediaType: file.type || "image/jpeg" }); };
      reader.onerror = function() { resolve(null); };
      reader.readAsDataURL(file);
    }

    loadBitmap(file)
      .then(function(bm) {
        try {
          var dataUrl = drawAndExport(bm, bm.width, bm.height);
          resolve({ dataUrl: dataUrl, mediaType: "image/jpeg" });
        } catch (e) {
          fallbackRawFile();
        }
      })
      .catch(function() {
        // createImageBitmap 不支援 → 退回 Image element（現代瀏覽器都會自動套 EXIF）
        loadImage(file)
          .then(function(img) {
            try {
              var dataUrl = drawAndExport(img, img.width, img.height);
              resolve({ dataUrl: dataUrl, mediaType: "image/jpeg" });
            } catch (e) {
              fallbackRawFile();
            }
          })
          .catch(fallbackRawFile);
      });
  });
}

// 把照片轉指定角度（順時針 deg），回傳新的 dataUrl
function _rotateMedPhoto(dataUrl, deg) {
  return new Promise(function(resolve, reject) {
    var img = new Image();
    img.onload = function() {
      var w = img.naturalWidth, h = img.naturalHeight;
      var rad = (deg % 360) * Math.PI / 180;
      var swap = (deg % 180) !== 0;
      var canvas = document.createElement("canvas");
      canvas.width = swap ? h : w;
      canvas.height = swap ? w : h;
      var ctx = canvas.getContext("2d");
      ctx.fillStyle = "#fff";
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.translate(canvas.width / 2, canvas.height / 2);
      ctx.rotate(rad);
      ctx.drawImage(img, -w / 2, -h / 2);
      resolve(canvas.toDataURL("image/jpeg", 0.9));
    };
    img.onerror = function() { reject(new Error("rotate load failed")); };
    img.src = dataUrl;
  });
}

// 拿目前預覽的 dataUrl 旋轉 90° 後重跑辨識
window.rotateMedPreview = function() {
  var img = document.querySelector("#med-photo-preview img");
  if (!img || !img.src) return;
  var src = img.src;
  _rotateMedPhoto(src, 90).then(function(rotated) {
    _renderMedPreviewAndRecognize(rotated, "image/jpeg");
  }).catch(function() {
    showToast(_T('app.c21.rotateFailed'), "error");
  });
};

// 在瀏覽器跑 Tesseract.js OCR — 中文（繁）+ 英文，支援藥單上的中英並列藥名
// 失敗 / Tesseract 沒載入時 resolve("")，由 backend fallback 走原本 LLM vision
// onProgress(msg) 會在每個階段呼叫，方便 UI 顯示進度
function _runClientOcr(dataUrl, onProgress) {
  return new Promise(function(resolve) {
    function fail(reason) {
      console.warn("Tesseract OCR skipped:", reason);
      resolve("");
    }
    if (typeof Tesseract === "undefined" || !Tesseract.recognize) {
      // tesseract.js 載入失敗（網路 / CDN 擋）— 直接退回 backend OCR
      return fail("Tesseract not loaded");
    }
    if (onProgress) onProgress(_T('app.d33.ocrDownloadEngine'));
    try {
      Tesseract.recognize(dataUrl, "chi_tra+eng", {
        logger: function(m) {
          if (!onProgress) return;
          if (m.status === "loading tesseract core") onProgress(_T('app.d33.ocrLoadEngine'));
          else if (m.status === "loading language traineddata") onProgress(_T('app.d33.ocrDownloadLangPack'));
          else if (m.status === "initializing api" || m.status === "initialized api") onProgress(_T('app.d33.ocrInitEngine'));
          else if (m.status === "recognizing text") {
            var pct = Math.round((m.progress || 0) * 100);
            onProgress(_Tf('app.d33.ocrRecognizingText', { pct: pct }));
          }
        },
      })
        .then(function(result) {
          var text = (result && result.data && result.data.text) || "";
          // 若 OCR 出來太少字（< 20 char）視為失敗，讓 backend 用 vision LLM 救
          resolve(text.trim().length >= 20 ? text.trim() : "");
        })
        .catch(function(e) { fail("Tesseract.recognize error: " + (e && e.message)); });
    } catch (e) {
      fail("Tesseract sync error: " + (e && e.message));
    }
  });
}


function _renderMedPreviewAndRecognize(dataUrl, mediaType) {
  var base64Data = dataUrl.split(",")[1];

  document.getElementById("med-photo-preview").innerHTML =
    '<img src="' + dataUrl + '" style="max-width:100%;max-height:240px;border-radius:var(--radius-sm);border:1px solid var(--border-glass)" />' +
    '<div style="display:flex;gap:8px;align-items:center;margin-top:6px;flex-wrap:wrap">' +
    '<button type="button" class="secondary" onclick="rotateMedPreview()" style="padding:4px 10px;font-size:0.8rem">' +
    '<i data-lucide="rotate-cw" style="width:12px;height:12px;vertical-align:middle"></i> ' + _T('app.c21.rotate90') + '</button>' +
    '<span style="font-size:0.75rem;color:var(--text-muted)">' +
    _Tf('app.c21.compressedTo', { kb: (Math.round(base64Data.length * 0.75 / 1024)) }) +
    _T('app.c21.rotateHint') + '</span>' +
    '</div>';
  if (window.lucide && lucide.createIcons) { try { lucide.createIcons(); } catch (_) {} }

  document.getElementById("med-recognize-result").innerHTML =
    '<div style="text-align:center;padding:16px;color:var(--text-muted)" id="med-rec-status">' +
    '<div class="loading-spinner"></div>' +
    '<p style="margin-top:8px">' + _T('app.c21.preparingRecognize') + '</p>' +
    '<p style="margin-top:4px;font-size:0.75rem;opacity:0.7">' + _T('app.c21.firstRecognizeSlow') + '</p>' +
    '</div>';

  return _runClientOcr(dataUrl, function(progressMsg) {
    var s = document.getElementById("med-rec-status");
    if (s) {
      s.innerHTML =
        '<div class="loading-spinner"></div>' +
        '<p style="margin-top:8px">' + escapeHtml(progressMsg) + '</p>' +
        '<p style="margin-top:4px;font-size:0.75rem;opacity:0.7">' + _T('app.c21.scanning') + '</p>';
    }
  }).then(function(ocrText) {
    var s2 = document.getElementById("med-rec-status");
    if (s2) {
      s2.innerHTML =
        '<div class="loading-spinner"></div>' +
        '<p style="margin-top:8px">' + _T('app.c21.organizingFields') + '</p>';
    }
    var body = { patient_id: _medsPatientId, image_base64: base64Data, media_type: mediaType };
    if (ocrText && ocrText.length >= 20) body.ocr_text = ocrText;
    return apiFetch(API + "/medications/recognize", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(body)
    });
  })
    .then(function(r) {
      return r.text().then(function(t) {
        var parsed; try { parsed = JSON.parse(t); } catch (e) { parsed = { detail: t }; }
        return { ok: r.ok, status: r.status, data: parsed };
      });
    })
    .then(function(res) {
      if (!res.ok) {
        var msg = (res.data && (res.data.detail || res.data.message)) || ("HTTP " + res.status);
        if (typeof msg !== "string") msg = JSON.stringify(msg);
        renderManualMedForm("", _Tf('app.c21.recognizeFailed', { msg: msg }));
        return;
      }
      var data = res.data || {};
      var parsed = data.parsed || [];

      if (parsed.length > 0) {
        renderRecognizedEditable(parsed, [], data.raw_text || "", []);
        return;
      }

      var providerNote = "";
      if (data.errors && data.errors.length) {
        var lines = data.errors.map(function(e) {
          return "• " + (e.provider || "?") + "：" + (e.error || _T('app.d34.unknownError'));
        }).join("\n");
        providerNote = "\n\n" + _T('app.c21.triedServices') + "\n" + lines;
      }
      renderManualMedForm(
        (data.raw_text || "") + providerNote,
        _T('app.c21.cannotRecognize')
      );
    })
    .catch(function(err) {
      renderManualMedForm(
        "",
        _Tf('app.c21.recognizeConnFailed', { err: (err && err.message || _T('app.c21.networkError')) })
      );
    });
}

function handleMedPhoto(input) {
  if (!input.files || !input.files[0]) return;
  var file = input.files[0];

  document.getElementById("med-photo-preview").innerHTML =
    '<div style="text-align:center;padding:8px;color:var(--text-muted);font-size:0.85rem">' + _T('app.c21.compressingUpload') + '</div>';
  document.getElementById("med-recognize-result").innerHTML = "";

  _compressMedPhoto(file).then(function(prepared) {
    if (!prepared) {
      renderManualMedForm("", _T('app.d34.photoReadFailed'));
      return;
    }
    _renderMedPreviewAndRecognize(prepared.dataUrl, prepared.mediaType);
  });

  input.value = "";
}

function escapeHtml(s) {
  return String(s == null ? "" : s)
    .replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;").replace(/'/g, "&#39;");
}

// 辨識成功但寫入失敗 / 部分失敗 → 提供逐筆可編輯卡片
function renderRecognizedEditable(parsed, errors, rawText, alreadySaved) {
  var errMap = {};
  (errors || []).forEach(function(e) { errMap[e.name] = e.error; });
  var savedNames = {};
  (alreadySaved || []).forEach(function(m) { savedNames[m.name] = true; });

  var SLOT_LABEL = { morning: _T('app.d34.slotMorning'), noon: _T('app.d34.slotNoon'), evening: _T('app.d34.slotEvening'), other: _T('app.d34.slotOtherLabel') };
  var inputStyle = "padding:6px;border-radius:4px;border:1px solid var(--border-glass);background:var(--bg-glass);color:var(--text)";
  var rows = parsed.map(function(m, i) {
    var isSaved = savedNames[m.name];
    var errMsg = errMap[m.name];
    var bgTint = isSaved ? "rgba(85,184,138,0.08)" : (errMsg ? "rgba(220,80,80,0.08)" : "var(--bg-glass)");
    var borderTint = isSaved ? "var(--success)" : (errMsg ? "var(--danger)" : "var(--border-glass)");
    var sched = m.schedule || {};
    var slotTags = "";
    if (sched.is_other) {
      var bits = [];
      if (sched.interval_hours) bits.push(_Tf('app.c21.everyNHours', { n: sched.interval_hours }));
      if (sched.is_prn) bits.push(_T('app.c21.prn'));
      slotTags = '<span class="rec-slot-tag rec-slot-other">' + _T('app.c21.slotOther') + (bits.length ? "・" + bits.join("・") : "") + '</span>';
    } else if (sched.slots && sched.slots.length) {
      slotTags = sched.slots.map(function(s) {
        return '<span class="rec-slot-tag rec-slot-' + s + '">' + (SLOT_LABEL[s] || s) + '</span>';
      }).join("");
    }
    return (
      '<div class="rec-med-card" data-idx="' + i + '" style="padding:10px;background:' + bgTint + ';border:1px solid ' + borderTint + ';border-radius:var(--radius-sm);display:grid;gap:6px">' +
        (isSaved ? '<div style="color:var(--success);font-size:0.8rem">' + _T('app.c21.savedCheck') + '</div>' :
         errMsg ? '<div style="color:var(--danger);font-size:0.8rem">' + _T('app.c21.saveFailedPrefix') + escapeHtml(errMsg) + '</div>' : '') +
        (slotTags ? '<div class="rec-slot-tags">' + _T('app.c21.plannedSlot') + slotTags + '</div>' : '') +
        '<input class="rec-name" type="text" value="' + escapeHtml(m.name) + '" placeholder="' + _T('app.c21.phName') + '" style="' + inputStyle + '" />' +
        '<div style="display:grid;grid-template-columns:1fr 1fr;gap:6px">' +
          '<input class="rec-dosage" type="text" value="' + escapeHtml(m.dosage) + '" placeholder="' + _T('app.c21.phDosage') + '" style="' + inputStyle + '" />' +
          '<input class="rec-frequency" type="text" value="' + escapeHtml(m.frequency) + '" placeholder="' + _T('app.c21.phFrequency') + '" style="' + inputStyle + '" />' +
        '</div>' +
        '<div style="display:grid;grid-template-columns:1fr 1fr;gap:6px">' +
          '<input class="rec-usage" type="text" value="' + escapeHtml(m.usage) + '" placeholder="' + _T('app.c21.phUsage') + '" style="' + inputStyle + '" />' +
          '<input class="rec-duration" type="text" value="' + escapeHtml(m.duration) + '" placeholder="' + _T('app.c21.phDuration') + '" style="' + inputStyle + '" />' +
        '</div>' +
        '<div style="display:grid;grid-template-columns:1fr 1fr;gap:6px">' +
          '<input class="rec-category" type="text" value="' + escapeHtml(m.category) + '" placeholder="' + _T('app.c21.phCategory') + '" style="' + inputStyle + '" />' +
          '<input class="rec-purpose" type="text" value="' + escapeHtml(m.purpose) + '" placeholder="' + _T('app.c21.phPurpose') + '" style="' + inputStyle + '" />' +
        '</div>' +
        '<div style="display:grid;grid-template-columns:1fr 1fr;gap:6px">' +
          '<input class="rec-hospital" type="text" value="' + escapeHtml(m.hospital) + '" placeholder="' + _T('app.c21.phHospital') + '" style="' + inputStyle + '" />' +
          '<input class="rec-prescribed-date" type="text" value="' + escapeHtml(m.prescribed_date) + '" placeholder="' + _T('app.c21.phPrescribedDate') + '" style="' + inputStyle + '" />' +
        '</div>' +
        '<textarea class="rec-instructions" rows="2" placeholder="' + _T('app.c21.phNotes') + '" style="' + inputStyle + ';resize:vertical">' + escapeHtml(m.instructions) + '</textarea>' +
        (isSaved ? '' : '<button class="primary" onclick="submitRecognizedOne(this)" style="padding:6px 10px;font-size:0.85rem">' + _T('app.c21.addThisToMyMeds') + '</button>') +
      '</div>'
    );
  }).join("");

  var header = errors && errors.length
    ? '<p style="color:var(--warning);margin:0 0 8px">' + _T('app.c21.recognizePartialFail') + '</p>'
    : '<p style="color:var(--text-dim);margin:0 0 8px">' + _T('app.c21.recognizeSuccess') + '</p>';

  var html =
    '<div style="padding:12px;background:rgba(160,140,220,0.06);border-radius:var(--radius-sm);border:1px solid var(--border-glass)">' +
      header +
      (rawText ? '<details style="margin-bottom:8px"><summary style="font-size:0.85rem;color:var(--text-muted);cursor:pointer">' + _T('app.c21.rawRecognizeText') + '</summary><pre style="font-size:0.8rem;white-space:pre-wrap;margin-top:4px;max-height:120px;overflow:auto">' + escapeHtml(rawText) + '</pre></details>' : '') +
      '<div id="rec-med-cards" style="display:grid;gap:10px">' + rows + '</div>' +
      '<div style="display:flex;gap:8px;margin-top:12px">' +
        '<button class="primary" onclick="submitAllRecognized()">' + _T('app.c21.addAllToMyMeds') + '</button>' +
        '<button class="secondary" onclick="document.getElementById(\'med-recognize-result\').innerHTML=\'\'">' + _T('app.c21.cancel') + '</button>' +
      '</div>' +
    '</div>';
  document.getElementById("med-recognize-result").innerHTML = html;
}

function _collectRecCard(card) {
  var val = function(sel) { var el = card.querySelector(sel); return el ? (el.value || "").trim() : ""; };
  // 資料庫目前只有 dosage/frequency/category/purpose/instructions 欄位，
  // 新增的 usage/duration/hospital/prescribed_date 先合併到 frequency / instructions
  // 以保留資訊又不用改 schema
  var frequency = val(".rec-frequency");
  var usage = val(".rec-usage");
  var freqCombined = [frequency, usage].filter(Boolean).join("・");

  var instructions = val(".rec-instructions");
  var duration = val(".rec-duration");
  var hospital = val(".rec-hospital");
  var pdate = val(".rec-prescribed-date");
  var extra = [];
  if (duration) extra.push("療程：" + duration);
  if (hospital) extra.push("醫院：" + hospital);
  if (pdate) extra.push("開立日期：" + pdate);
  var instCombined = [instructions, extra.join("；")].filter(Boolean).join("\n");

  return {
    patient_id: _medsPatientId,
    name: val(".rec-name"),
    dosage: val(".rec-dosage") || null,
    frequency: freqCombined || null,
    category: val(".rec-category") || null,
    purpose: val(".rec-purpose") || null,
    instructions: instCombined || null,
  };
}

function submitRecognizedOne(btn) {
  var card = btn.closest(".rec-med-card");
  var body = _collectRecCard(card);
  if (!body.name) { showToast(_T('app.c21.medNameRequired'), "warning"); return; }
  btn.disabled = true; btn.textContent = _T('app.c21.adding');
  apiFetch(API + "/medications/", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body)
  })
    .then(function(r) {
      return r.text().then(function(t) {
        var p; try { p = JSON.parse(t); } catch (e) { p = { detail: t }; }
        return { ok: r.ok, status: r.status, data: p };
      });
    })
    .then(function(res) {
      if (!res.ok) {
        var msg = (res.data && (res.data.detail || res.data.message)) || ("HTTP " + res.status);
        showToast(_Tf('app.c21.addFailed', { msg: msg }), "error");
        btn.disabled = false; btn.textContent = _T('app.c21.retryAdd');
        return;
      }
      var deduped = res.data && res.data._deduped;
      card.style.background = "rgba(85,184,138,0.08)";
      card.style.borderColor = "var(--success)";
      btn.outerHTML = '<div style="color:var(--success);font-size:0.85rem;text-align:center">' + (deduped ? _T('app.c21.alreadyExistsCheck') : _T('app.c21.savedCheck')) + '</div>';
      showToast(deduped ? _Tf('app.c21.alreadyInList', { name: body.name }) : _Tf('app.c21.addedMed', { name: body.name }), deduped ? "info" : "success");
      loadMedicationsPage();
    })
    .catch(function(err) {
      showToast(_Tf('app.c21.addFailed', { msg: (err && err.message || _T('app.c21.networkError')) }), "error");
      btn.disabled = false; btn.textContent = _T('app.c21.retryAdd');
    });
}

function submitAllRecognized() {
  var cards = document.querySelectorAll("#rec-med-cards .rec-med-card");
  var pending = [];
  cards.forEach(function(c) {
    var hasSaveBtn = c.querySelector("button.primary");
    if (hasSaveBtn) pending.push(c);
  });
  if (!pending.length) { showToast(_T('app.c21.nothingToAdd'), "info"); return; }
  var okCount = 0, dupCount = 0, failCount = 0, done = 0;
  pending.forEach(function(card) {
    var btn = card.querySelector("button.primary");
    var body = _collectRecCard(card);
    if (!body.name) { failCount++; done++; if (done === pending.length) _afterBulkAdd(okCount, dupCount, failCount); return; }
    btn.disabled = true; btn.textContent = _T('app.c21.adding');
    apiFetch(API + "/medications/", {
      method: "POST", headers: { "Content-Type": "application/json" },
      body: JSON.stringify(body)
    })
      .then(function(r) { return r.json().then(function(d) { return { ok: r.ok, data: d }; }).catch(function() { return { ok: r.ok, data: {} }; }); })
      .then(function(res) {
        if (res.ok) {
          var deduped = res.data && res.data._deduped;
          if (deduped) dupCount++; else okCount++;
          card.style.background = "rgba(85,184,138,0.08)";
          card.style.borderColor = "var(--success)";
          btn.outerHTML = '<div style="color:var(--success);font-size:0.85rem;text-align:center">' + (deduped ? _T('app.c21.alreadyExistsCheck') : _T('app.c21.savedCheck')) + '</div>';
        } else {
          failCount++;
          btn.disabled = false; btn.textContent = _T('app.c21.retryAdd');
        }
      })
      .catch(function() { failCount++; btn.disabled = false; btn.textContent = _T('app.c21.retryAdd'); })
      .finally(function() {
        done++;
        if (done === pending.length) _afterBulkAdd(okCount, dupCount, failCount);
      });
  });
}

function _afterBulkAdd(ok, dup, fail) {
  dup = dup || 0;
  var parts = [];
  if (ok) parts.push(_Tf('app.c21.addedCount', { n: ok }));
  if (dup) parts.push(_Tf('app.c21.existCount', { n: dup }));
  if (fail) parts.push(_Tf('app.c21.failCount', { n: fail }));
  var level = fail ? (ok || dup ? "warning" : "error") : (ok ? "success" : "info");
  showToast(parts.length ? parts.join("、") + " ✓" : _T('app.c21.noChange'), level);
  if (ok || dup) loadMedicationsPage();
}

