    // 名人健康新聞（reuse 桌機 #edu-news-feed 容器 id 也行；mobile 用獨立容器）
    +   '<div id="mobile-edu-news" style="display:none">'
    +     '<div class="sec-head">'
    +       '<h3 class="sec-title"><i data-lucide="newspaper"></i> ' + _T('app.c23.healthNews') + '</h3>'
