    // 衛教書房・通用書架（不依賴個人疾病登錄，永遠看得到）
    +   '<div class="sec-head">'
    +     '<h3 class="sec-title"><i data-lucide="library"></i> ' + _T('edu.shelf.banner') + '</h3>'
