function loadFontSizePage() {
  // 確保 Lucide 圖示渲染
  if (typeof lucide !== 'undefined') lucide.createIcons();
}

function onSettingChange(group, value) {
  if (group === 'fontSize') {
    setSetting('fontSize', value);
    applyFontSize(value);
  } else if (group === 'fontFamily') {
    setSetting('fontFamily', value);
    applyFontStyle();
  } else if (group === 'theme') {
    try { localStorage.setItem(SETTINGS_KEYS.theme, value); } catch (e) {}
    applyTheme(value);
  } else if (group === 'mode') {
    setMode(value);
  } else if (group === 'density') {
    setSetting('density', value);
    applyDensity(value);
  } else if (group === 'reminderTone') {
    setReminderTone(value);
    // 重新刷新 todo / SOS history，套上新口氣
    if (typeof refreshTodoList === 'function') refreshTodoList();
  }
  // 更新該群組按鈕的 active 狀態
  document.querySelectorAll('.set-seg-btn[data-group="' + group + '"]').forEach(function(b) {
    b.classList.toggle('active', b.dataset.value === value);
  });
  if (typeof showToast === 'function') showToast(_T("app.c26.settingSaved"), 'success');
}

function onSwitchChange(key, value) {
  setSetting(key, value);
  if (key === 'motion') applyMotion(value);
  if (key === 'fontBold') applyFontStyle();
  if (typeof showToast === 'function') showToast(_T("app.c26.settingSaved"), 'success');
}

function settingsClearCache() {
  if (!confirm(_T("app.c26.clearCacheConfirm"))) return;
  try {
    if ('caches' in window) {
      caches.keys().then(keys => Promise.all(keys.map(k => caches.delete(k)))).finally(() => location.reload());
    } else {
      location.reload();
    }
  } catch (e) { location.reload(); }
}

function settingsResetCard() {
  if (!confirm(_T("app.c26.resetCardConfirm"))) return;
  try {
    localStorage.removeItem('mdpiece_user');
    localStorage.removeItem('mdpiece_demo_pid');
  } catch (e) {}
  window.location.reload();
}

function markdownToHtml(md) {
  if (!md) return "";
  return md
    .replace(/^### (.+)$/gm, '<h4 style="margin-top:16px;margin-bottom:8px;color:var(--accent)">$1</h4>')
    .replace(/^## (.+)$/gm, '<h3 style="margin-top:20px;margin-bottom:8px">$1</h3>')
    .replace(/^# (.+)$/gm, '<h2 style="margin-top:24px;margin-bottom:12px">$1</h2>')
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*(.+?)\*/g, '<em>$1</em>')
    .replace(/^- (.+)$/gm, '<li style="margin-left:20px;margin-bottom:4px">$1</li>')
    .replace(/^(\d+)\. (.+)$/gm, '<li style="margin-left:20px;margin-bottom:4px"><strong>$1.</strong> $2</li>')
    .replace(/\n\n/g, '<br><br>')
    .replace(/\n/g, '<br>');
}


// ─── 報告數值（Lab Values）─────────────────────────────────
// 隱私：紀錄只存 sessionStorage（關分頁即消失），後端 stateless 不寫 DB

const LABS_HISTORY_KEY = 'mdpiece_labs_history';
const LABS_STATUS_META = {
  low:      { label: '偏低',     emoji: '🟡', cls: 'labs-st-warn' },
  normal:   { label: '正常',     emoji: '🟢', cls: 'labs-st-ok' },
  high:     { label: '偏高',     emoji: '🟡', cls: 'labs-st-warn' },
  critical: { label: '嚴重異常', emoji: '🔴', cls: 'labs-st-bad' },
  unknown:  { label: '無法判讀', emoji: '⚪', cls: 'labs-st-unk' },
};

function labsLoadHistory() {
  try { return JSON.parse(sessionStorage.getItem(LABS_HISTORY_KEY) || '[]'); }
  catch (e) { return []; }
}

function labsSaveHistory(arr) {
  try { sessionStorage.setItem(LABS_HISTORY_KEY, JSON.stringify(arr.slice(0, 30))); }
  catch (e) { /* quota exceeded — ignore */ }
}

function loadLabsPage() {
  labsRenderHistory();
}

function labsRenderHistory() {
  const items = labsLoadHistory();
  const listEl = document.getElementById('labs-history-list');
  if (listEl) {
    if (!items.length) {
      listEl.innerHTML = '<p class="labs-empty">' + _T("app.c26.labsEmpty") + '</p>';
    } else {
      listEl.innerHTML = items.map((it, idx) => {
        const meta = LABS_STATUS_META[it.status] || LABS_STATUS_META.unknown;
        const time = new Date(it.at).toLocaleString('zh-TW', { hour12: false });
        return '' +
          '<article class="labs-history-item ' + meta.cls + '" onclick="labsShowFromHistory(' + idx + ')">' +
            '<span class="labs-history-emoji">' + meta.emoji + '</span>' +
            '<div class="labs-history-body">' +
              '<div class="labs-history-top">' +
                '<strong>' + escapeHtml(it.name) + '</strong>' +
                '<span class="labs-history-value">' + escapeHtml(it.value) +
                  (it.unit ? ' ' + escapeHtml(it.unit) : '') + '</span>' +
              '</div>' +
              '<div class="labs-history-meta">' + meta.label + ' · ' + time + '</div>' +
            '</div>' +
          '</article>';
      }).join('');
    }
  }
  // mobile mirror
  const mList = document.getElementById('mobile-labs-history');
  const mCnt = document.getElementById('mobile-labs-history-count');
  if (mCnt) mCnt.textContent = _Tf("app.c26.countItems", { n: items.length });
  if (mList) {
    if (!items.length) {
      mList.innerHTML = '<div class="list-row" style="grid-template-columns:1fr;color:var(--text-muted);font-size:11px;padding:14px;text-align:center">' + _T("app.c26.noRecords") + '</div>';
    } else {
      mList.innerHTML = items.map((it, idx) => {
        const meta = LABS_STATUS_META[it.status] || LABS_STATUS_META.unknown;
        const time = new Date(it.at).toLocaleString('zh-TW', { month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' });
        var pillCls = it.status === 'normal' ? 'pill-ok' : (it.status === 'abnormal' || it.status === 'critical' ? 'pill-rose' : 'pill-mute');
        return ''
          + '<div class="list-row" style="grid-template-columns:24px 1fr auto;padding:10px 12px;cursor:pointer" onclick="labsShowFromHistory(' + idx + ')">'
          +   '<span style="font-size:16px">' + (meta.emoji || '📊') + '</span>'
          +   '<div>'
          +     '<div class="name">' + escapeHtml(it.name) + ' <span style="color:var(--text-dim);font-weight:500;font-family:var(--font-mono,monospace);font-size:11px">' + escapeHtml(it.value) + (it.unit ? ' ' + escapeHtml(it.unit) : '') + '</span></div>'
          +     '<div style="margin-top:2px"><span class="pill ' + pillCls + '">' + meta.label + '</span> <span class="time" style="text-align:left">' + escapeHtml(time) + '</span></div>'
          +   '</div>'
          +   '<i data-lucide="chevron-right" style="width:12px;height:12px;color:var(--text-muted)"></i>'
          + '</div>';
      }).join('');
    }
  }
  if (typeof lucide !== 'undefined') lucide.createIcons();
}

function labsShowFromHistory(idx) {
  const items = labsLoadHistory();
  const it = items[idx];
  if (!it) return;
  labsRenderResult(it.result, { name: it.name, value: it.value, unit: it.unit });
}

function labsClearHistory() {
  if (!confirm(_T("app.c26.clearLabsConfirm"))) return;
  sessionStorage.removeItem(LABS_HISTORY_KEY);
  labsRenderHistory();
  const r = document.getElementById('lab-result');
  if (r) { r.style.display = 'none'; r.innerHTML = ''; }
}

async function labsCheck() {
  const name  = document.getElementById('lab-name').value.trim();
  const value = document.getElementById('lab-value').value.trim();
  const unit  = document.getElementById('lab-unit').value.trim();
  const ageS  = document.getElementById('lab-age').value.trim();
  const sex   = document.getElementById('lab-sex').value;

  if (!name || !value) {
    if (typeof showToast === 'function') showToast(_T('app.c27.enterLabItemAndValue'), 'warning');
    document.getElementById(!name ? 'lab-name' : 'lab-value').focus();
    return;
  }

  const resultEl = document.getElementById('lab-result');
  resultEl.style.display = 'block';
  resultEl.innerHTML = '<p class="labs-loading"><i data-lucide="loader" class="labs-spin"></i> ' + _T('app.c27.mdpieceInterpreting') + '</p>';
  if (typeof lucide !== 'undefined') lucide.createIcons();

  try {
    const body = { name, value };
    if (unit) body.unit = unit;
    if (ageS) body.age = parseInt(ageS, 10);
    if (sex)  body.sex = sex;

    const res = await fetch(`${API}/labs/check`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });
    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      throw new Error(err.detail || _T('app.c27.queryFailed'));
    }
    const data = await res.json();

    labsRenderResult(data, { name, value, unit });

    const hist = labsLoadHistory();
    hist.unshift({ name, value, unit, status: data.status, result: data, at: Date.now() });
    labsSaveHistory(hist);
    labsRenderHistory();
  } catch (e) {
    resultEl.innerHTML = '<p class="labs-error">' + _T('app.c27.queryFailedColon') + escapeHtml(e.message || _T('app.c27.unknownError')) + '</p>';
  }
}

// ── 拍攝整份報告，一次列出所有項目正常/異常 ───────────────
function handleLabPhoto(input) {
  if (!input.files || !input.files[0]) return;
  var file = input.files[0];
  var preview = document.getElementById('lab-scan-preview');
  var result = document.getElementById('lab-scan-result');
  var hint = document.getElementById('lab-scan-hint');
  if (preview) preview.innerHTML = '<div style="color:var(--text-muted);font-size:.85rem">' + _T('app.c27.compressingUploading') + '</div>';
  if (result) result.innerHTML = '';
  if (hint) hint.textContent = '';

  _compressMedPhoto(file).then(function(prepared) {
    if (!prepared) {
      if (preview) preview.innerHTML = '<div class="labs-error">' + _T('app.c27.readPhotoFailedManual') + '</div>';
      input.value = '';
      return;
    }
    var dataUrl = prepared.dataUrl;
    var mediaType = prepared.mediaType || 'image/jpeg';
    var base64 = (dataUrl.split(',')[1] || '');

    if (preview) {
      preview.innerHTML =
        '<img src="' + dataUrl + '" alt="' + _T('app.c27.labReportPreview') + '" ' +
        'style="max-width:100%;max-height:280px;border-radius:8px;border:1px solid var(--border)" />';
    }
    if (result) {
      result.innerHTML = '<p class="labs-loading"><i data-lucide="loader" class="labs-spin"></i> ' + _T('app.c27.mdpieceReadingWholeReport') + '</p>';
      if (typeof lucide !== 'undefined') lucide.createIcons();
    }

    fetch(API + '/labs/scan', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ image_base64: base64, media_type: mediaType })
    })
      .then(function(r) {
        return r.text().then(function(t) {
          var parsed; try { parsed = JSON.parse(t); } catch (e) { parsed = { detail: t }; }
          return { ok: r.ok, status: r.status, data: parsed };
        });
      })
      .then(function(res) {
        if (!res.ok) {
          var msg = (res.data && (res.data.detail || res.data.message)) || ('HTTP ' + res.status);
          if (typeof msg !== 'string') msg = JSON.stringify(msg);
          if (result) result.innerHTML = '<p class="labs-error">' + _T('app.c27.recognitionFailedColon') + escapeHtml(msg) + '</p>';
          return;
        }
        labsRenderScanResult(res.data || {});
        labsAppendScannedToHistory((res.data && res.data.items) || []);
      })
      .catch(function(err) {
        if (result) result.innerHTML = '<p class="labs-error">' + _T('app.c27.recognitionServiceFailedColon') + escapeHtml((err && err.message) || _T('app.c27.networkError')) + '</p>';
      });
  });
  input.value = '';
}

function labsRenderScanResult(data) {
  var resultEl = document.getElementById('lab-scan-result');
  if (!resultEl) return;
  var items = data.items || [];
  if (!items.length) {
    var note = '';
    if (data.errors && data.errors.length) {
      note = '<details style="margin-top:8px;font-size:.78rem;color:var(--text-dim)"><summary>' + _T('app.c27.viewReadFailures') + '</summary>' +
        '<ul style="margin-top:6px;padding-left:18px">' +
        data.errors.map(function(e) { return '<li>' + escapeHtml((e.provider || '?') + '：' + (e.error || '')) + '</li>'; }).join('') +
        '</ul></details>';
    }
    resultEl.innerHTML = '<p class="labs-error">' + _T('app.c27.noLabItemsFromPhoto') + '</p>' + note;
    return;
  }
  var summary = data.summary || {};
  var headLines = [
    '<strong>' + _Tf('app.c27.readNItems', { n: items.length }) + '</strong>',
  ];
  if (summary.abnormal) headLines.push('<span class="labs-st-warn" style="padding:2px 8px;border-radius:10px">' + _Tf('app.c27.abnormalNItems', { n: summary.abnormal }) + '</span>');
  if (summary.needs_doctor) headLines.push('<span class="labs-st-bad" style="padding:2px 8px;border-radius:10px">' + _T('app.c27.seeDoctorAdvised') + '</span>');

  var sortRank = { critical: 0, high: 1, low: 2, unknown: 3, normal: 4 };
  function rankOf(s) { var r = sortRank[s]; return (r === undefined) ? 9 : r; }
  items = items.slice().sort(function(a, b) { return rankOf(a.status) - rankOf(b.status); });

  var listHtml = items.map(function(it, idx) {
    var meta = LABS_STATUS_META[it.status] || LABS_STATUS_META.unknown;
    var unitTxt = it.unit ? ' ' + escapeHtml(it.unit) : '';
    var seeDoc = it.see_doctor
      ? '<span style="margin-left:6px;padding:1px 6px;border-radius:8px;background:#fee;color:#a30;font-size:.7rem">' + _T('app.c27.seeDoctorAdvised') + '</span>'
      : '';
    return '' +
      '<details class="labs-scan-item ' + meta.cls + '"' + (idx < 3 ? ' open' : '') + ' ' +
      'style="margin-top:6px;padding:8px 10px;border-radius:8px;border:1px solid var(--border);background:var(--bg-card)">' +
        '<summary style="cursor:pointer;display:flex;align-items:center;gap:8px;flex-wrap:wrap">' +
          '<span>' + meta.emoji + '</span>' +
          '<strong>' + escapeHtml(it.name) + '</strong>' +
          '<span style="color:var(--text-dim)">' + escapeHtml(it.value) + unitTxt + '</span>' +
          '<span style="margin-left:auto;font-size:.78rem;color:var(--text-dim)">' + escapeHtml(meta.label) + '</span>' +
          seeDoc +
        '</summary>' +
        '<div style="margin-top:8px;font-size:.85rem;line-height:1.6">' +
          '<div><strong>' + _T('app.c27.referenceRange') + '</strong>：' + escapeHtml(it.normal_range || '—') + '</div>' +
          (it.meaning ? '<div style="margin-top:4px"><strong>' + _T('app.c27.meaning') + '</strong>：' + escapeHtml(it.meaning) + '</div>' : '') +
          (it.advice  ? '<div style="margin-top:4px"><strong>' + _T('app.c27.advice') + '</strong>：' + escapeHtml(it.advice) + '</div>' : '') +
        '</div>' +
      '</details>';
  }).join('');

  resultEl.innerHTML =
    '<div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-top:4px">' + headLines.join(' · ') + '</div>' +
    '<div style="margin-top:8px">' + listHtml + '</div>' +
    '<p class="labs-result-disclaimer" style="margin-top:8px">' + escapeHtml(data.disclaimer || _T('app.c27.scanDisclaimer')) + '</p>';

  if (typeof lucide !== 'undefined') lucide.createIcons();
}

function labsAppendScannedToHistory(items) {
  if (!items || !items.length) return;
  var hist = labsLoadHistory();
  items.forEach(function(it) {
    hist.unshift({
      name: it.name,
      value: String(it.value || ''),
      unit: it.unit || '',
      status: it.status || 'unknown',
      result: {
        item: it.name,
        normal_range: it.normal_range || '未知',
        status: it.status || 'unknown',
        meaning: it.meaning || '',
        advice: it.advice || '',
        see_doctor: !!it.see_doctor,
        disclaimer: '本結果僅供參考，請以實際檢驗單位與醫師判讀為準',
      },
      at: Date.now(),
      from_scan: true,
    });
  });
  labsSaveHistory(hist);
  labsRenderHistory();
}

function labsRenderResult(data, input) {
  const meta = LABS_STATUS_META[data.status] || LABS_STATUS_META.unknown;
  const resultEl = document.getElementById('lab-result');
  if (resultEl) {
    resultEl.style.display = 'block';
    resultEl.className = 'card labs-result ' + meta.cls;
    resultEl.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
    resultEl.innerHTML = '' +
      '<div class="labs-result-head">' +
        '<span class="labs-result-emoji">' + meta.emoji + '</span>' +
        '<div>' +
          '<div class="labs-result-item">' + escapeHtml(data.item || input.name) + '</div>' +
          '<div class="labs-result-input">' + _T('app.c27.youEnteredColon') + escapeHtml(input.value) +
            (input.unit ? ' ' + escapeHtml(input.unit) : '') + '</div>' +
        '</div>' +
        '<span class="labs-result-status">' + meta.label + '</span>' +
      '</div>' +
      '<div class="labs-result-row"><strong>' + _T('app.c27.referenceRange') + '</strong><span>' + escapeHtml(data.normal_range || '—') + '</span></div>' +
      '<div class="labs-result-block"><strong>' + _T('app.c27.whatThisIndicatorMeans') + '</strong><p>' + escapeHtml(data.meaning || '—') + '</p></div>' +
      '<div class="labs-result-block"><strong>' + _T('app.c27.advice') + '</strong><p>' + escapeHtml(data.advice || '—') + '</p></div>' +
      (data.see_doctor
        ? '<div class="labs-result-warn"><i data-lucide="alert-triangle" style="width:16px;height:16px;vertical-align:middle"></i> ' + _T('app.c27.seeDoctorSoon') + '</div>'
        : '') +
      '<p class="labs-result-disclaimer">' + escapeHtml(data.disclaimer || _T('app.c27.resultDisclaimer')) + '</p>';
  }
  // mobile mirror
  const mResult = document.getElementById('mobile-lab-result');
  if (mResult) {
    var pillCls = data.status === 'normal' ? 'pill-ok' : (data.status === 'abnormal' || data.status === 'critical' ? 'pill-rose' : 'pill-mute');
    var bg = data.status === 'normal' ? 'puzzle-bg-blue-teal' : 'puzzle-bg-rose-amber';
    mResult.innerHTML = ''
      + '<div class="card" style="padding:14px;position:relative;overflow:hidden">'
      +   '<svg class="puzzle-bg-layer" preserveAspectRatio="xMidYMid slice" style="opacity:0.18"><use href="#' + bg + '"/></svg>'
      +   '<div style="display:flex;align-items:flex-start;gap:10px;margin-bottom:8px;position:relative;z-index:1">'
      +     '<span style="font-size:22px">' + (meta.emoji || '📊') + '</span>'
      +     '<div style="flex:1">'
      +       '<div style="font-size:13.5px;font-weight:600;color:var(--navy)">' + escapeHtml(data.item || input.name) + '</div>'
      +       '<div style="font-size:10.5px;color:var(--text-muted);font-family:var(--font-mono,monospace);margin-top:2px">' + _T('app.c27.youEnteredColon') + escapeHtml(input.value) + (input.unit ? ' ' + escapeHtml(input.unit) : '') + '</div>'
      +     '</div>'
      +     '<span class="pill ' + pillCls + '">' + meta.label + '</span>'
      +   '</div>'
      +   '<div style="font-size:11px;color:var(--text-dim);line-height:1.6;margin-bottom:6px;position:relative;z-index:1"><strong style="color:var(--navy)">' + _T('app.c27.referenceRangeColon') + '</strong>' + escapeHtml(data.normal_range || '—') + '</div>'
      +   '<div style="font-size:11.5px;color:var(--text);line-height:1.6;margin-top:6px;position:relative;z-index:1"><strong>' + _T('app.c27.whatThisIndicatorMeans') + '</strong><div style="color:var(--text-dim);margin-top:2px">' + escapeHtml(data.meaning || '—') + '</div></div>'
      +   '<div style="font-size:11.5px;color:var(--text);line-height:1.6;margin-top:6px;position:relative;z-index:1"><strong>' + _T('app.c27.advice') + '</strong><div style="color:var(--text-dim);margin-top:2px">' + escapeHtml(data.advice || '—') + '</div></div>'
      +   (data.see_doctor
        ? '<div style="margin-top:8px;padding:8px 10px;background:var(--rose-soft);color:var(--rose-deep);border-radius:8px;font-size:11.5px;font-weight:600;display:flex;align-items:center;gap:5px;position:relative;z-index:1"><i data-lucide="alert-triangle" style="width:13px;height:13px"></i>' + _T('app.c27.seeDoctorSoon') + '</div>'
        : '')
      +   '<div style="margin-top:8px;padding-top:6px;border-top:1px solid var(--border);font-size:10px;color:var(--text-muted);line-height:1.5;position:relative;z-index:1">' + escapeHtml(data.disclaimer || _T('app.c27.resultDisclaimer')) + '</div>'
      + '</div>';
  }
  if (typeof lucide !== 'undefined') lucide.createIcons();
}


// ─── 情緒紀錄 ────────────────────────────────────────────
// 五階情緒打卡 + 7 天迷你折線圖 + 自動觸發 silent-guardian 警示

var EMOTION_LEVELS = [
  { score: 5, pct: 100, emoji: '😄', label: '滿電',   color: '#86C7B8' },
  { score: 4, pct:  75, emoji: '🙂', label: '充飽中', color: '#B5D6C4' },
  { score: 3, pct:  50, emoji: '😐', label: '中等',   color: '#D6CFC2' },
  { score: 2, pct:  25, emoji: '😟', label: '低電量', color: '#E0B89A' },
  { score: 1, pct:   0, emoji: '😢', label: '沒電',   color: '#C97B7B' },
];

// 喜怒哀樂四象限 — 先選情緒類型，下方電池就變成「程度」
// 情緒輪：6 個方向（喜怒哀樂 + 焦慮 緊張）× 3 強度環 + 中心「平靜」
// 角度走 SVG 慣例：0°=右、90°=下、-90°=上。每 60° 一個情緒。
// rings 由內到外 = 弱 → 中 → 強，分別給 score 2 / 3 / 5；中心 score = 1。
var EMOTION_WHEEL = [
  { id: 'joy',     angle: -90, char: '喜', color: '#E8A93A',
    rings: [
      { score: 2, emoji: '🙂', word: '有點開心' },
      { score: 3, emoji: '😊', word: '開心' },
      { score: 5, emoji: '😄', word: '非常開心' },
    ] },
  { id: 'relax',   angle: -30, char: '樂', color: '#6FA67B',
    rings: [
      { score: 2, emoji: '😌', word: '放鬆' },
      { score: 3, emoji: '🥰', word: '愉快' },
      { score: 5, emoji: '🤩', word: '幸福' },
    ] },
  { id: 'anxiety', angle:  30, char: '焦', color: '#C098DA',
    rings: [
      { score: 2, emoji: '😟', word: '有點焦慮' },
      { score: 3, emoji: '😰', word: '焦慮' },
      { score: 5, emoji: '😱', word: '非常焦慮' },
    ] },
  { id: 'sorrow',  angle:  90, char: '哀', color: '#5A7DB0',
    rings: [
      { score: 2, emoji: '🥹', word: '委屈' },
      { score: 3, emoji: '😢', word: '難過' },
      { score: 5, emoji: '😭', word: '非常難過' },
    ] },
  { id: 'tense',   angle: 150, char: '緊', color: '#D89968',
    rings: [
      { score: 2, emoji: '😬', word: '有點緊張' },
      { score: 3, emoji: '😖', word: '緊張' },
      { score: 5, emoji: '😣', word: '非常緊繃' },
    ] },
  { id: 'anger',   angle: 210, char: '怒', color: '#D86E5E',
    rings: [
      { score: 2, emoji: '😒', word: '有點不爽' },
      { score: 3, emoji: '😠', word: '生氣' },
      { score: 5, emoji: '🤬', word: '非常憤怒' },
    ] },
];
var EMOTION_CENTER = { score: 1, emoji: '😶', word: '平靜', char: '靜', color: '#9CA8B8' };
var _selectedEmotionCell = null; // { emotion(或'center'), score, emoji, word, char }

// 為了讓 mood-ring-hero + 月曆 + 表格繼續用 _moodColor / _moodEmoji
// 同步把舊 EMOTION_TYPES 留著，但只當 fallback 用
var EMOTION_TYPES = EMOTION_WHEEL.map(function(e) {
  return { id: e.id, char: e.char, word: e.rings[1].word, emoji: e.rings[1].emoji, color: e.color };
});
function _getEmotionType(id) {
  return EMOTION_TYPES.find(function(t) { return t.id === id; }) || EMOTION_TYPES[0];
}
function emotionIntensityText(score, typeId) {
  var s = Math.max(1, Math.min(5, Math.round(score || 0)));
  if (s <= 1) return '平靜';
  var w = EMOTION_WHEEL.find(function(e) { return e.id === typeId; });
  if (!w) return '普通';
  if (s <= 2) return w.rings[0].word;
  if (s <= 3) return w.rings[1].word;
  return w.rings[2].word;
}
function selectEmotionCell(emotionId, score) {
  if (emotionId === 'center') {
    _selectedEmotionCell = { emotion: 'center', score: 1, emoji: EMOTION_CENTER.emoji, word: EMOTION_CENTER.word, char: EMOTION_CENTER.char };
  } else {
    var w = EMOTION_WHEEL.find(function(e) { return e.id === emotionId; });
    if (!w) return;
    var ring = w.rings.find(function(r) { return r.score === score; });
    if (!ring) return;
    _selectedEmotionCell = { emotion: w.id, score: ring.score, emoji: ring.emoji, word: ring.word, char: w.char };
  }
  // 同步舊 _emotionSelected（submitEmotion 走的是這個）
  _emotionSelected = _selectedEmotionCell.score;
  _selectedEmotionType = (_selectedEmotionCell.emotion === 'center') ? 'joy' : _selectedEmotionCell.emotion;
  // 高亮 SVG markers
  document.querySelectorAll('.emo-marker').forEach(function(el) {
    var emo = el.getAttribute('data-emotion');
    var s = Number(el.getAttribute('data-score'));
    el.classList.toggle('is-active', emo === _selectedEmotionCell.emotion && s === _selectedEmotionCell.score);
  });
  var readEmoji = document.getElementById('emo-readout-emoji');
  var readWord = document.getElementById('emo-readout-word');
  if (readEmoji) readEmoji.textContent = _selectedEmotionCell.emoji;
  if (readWord) readWord.textContent = _selectedEmotionCell.word;
  _updateEmotionSubmitState();
}
function _updateEmotionSubmitState() {
  var btn = document.getElementById('emotion-submit');
  if (btn) btn.disabled = (_emotionSelected == null);
}

// 舊 selectEmotionType — 保留 stub 避免外部呼叫 crash
function selectEmotionType(typeId) {
  _selectedEmotionType = typeId;
}

// 渲染情緒輪：中心圓 + 3 個強度 ring × 6 個方向，每個位置一顆 emoji
function renderEmotionWheel() {
  // SVG 拖曳版情緒輪：6 方向彩色扇形（中心淡→邊緣飽和）+ 18 顆 emoji marker
  // + 中央「平靜」 + 一顆可拖曳 thumb，下方掛水平強度條（電池視覺化）
  var SIZE = 320, CX = SIZE / 2, CY = SIZE / 2;
  var RING_R = [62, 100, 138];
  var defs = EMOTION_WHEEL.map(function(e) {
    return '<radialGradient id="emo-grad-' + e.id + '" cx="50%" cy="50%" r="80%">'
      + '<stop offset="20%" stop-color="' + e.color + '" stop-opacity="0.06"/>'
      + '<stop offset="60%" stop-color="' + e.color + '" stop-opacity="0.22"/>'
      + '<stop offset="100%" stop-color="' + e.color + '" stop-opacity="0.55"/>'
      + '</radialGradient>';
  }).join('');
  var sectors = EMOTION_WHEEL.map(function(e) {
    return '<path d="' + _emoSlicePath(CX, CY, 156, e.angle - 30, e.angle + 30)
      + '" fill="url(#emo-grad-' + e.id + ')"/>';
  }).join('');
  var rings = RING_R.map(function(r) {
    return '<circle cx="' + CX + '" cy="' + CY + '" r="' + r + '" fill="none" stroke="var(--border-glass)" stroke-width="1" stroke-dasharray="2 4"/>';
  }).join('');
  var dividers = EMOTION_WHEEL.map(function(e) {
    var mid = (e.angle - 30) * Math.PI / 180;
    var x1 = CX + 30 * Math.cos(mid), y1 = CY + 30 * Math.sin(mid);
    var x2 = CX + 152 * Math.cos(mid), y2 = CY + 152 * Math.sin(mid);
    return '<line x1="' + x1.toFixed(1) + '" y1="' + y1.toFixed(1) + '" x2="' + x2.toFixed(1) + '" y2="' + y2.toFixed(1) + '" stroke="var(--border-glass)" stroke-width="1" stroke-dasharray="2 3"/>';
  }).join('');
  var markers = '';
  EMOTION_WHEEL.forEach(function(e) {
    e.rings.forEach(function(r, idx) {
      var rad = e.angle * Math.PI / 180;
      var x = CX + RING_R[idx] * Math.cos(rad);
      var y = CY + RING_R[idx] * Math.sin(rad);
      markers += '<g class="emo-marker" data-emotion="' + e.id + '" data-score="' + r.score + '" style="color:' + e.color + '">'
        + '<circle cx="' + x + '" cy="' + y + '" r="20" fill="var(--bg-surface)" stroke="' + e.color + '" stroke-width="1.5"/>'
        + '<text x="' + x + '" y="' + (y + 1) + '" font-size="20" text-anchor="middle" dominant-baseline="central">' + r.emoji + '</text>'
        + '</g>';
    });
  });
  var centerMarker = '<g class="emo-marker" data-emotion="center" data-score="1">'
    + '<circle cx="' + CX + '" cy="' + CY + '" r="26" fill="var(--bg-surface)" stroke="var(--text-muted)" stroke-width="1.5" stroke-dasharray="3 3"/>'
    + '<text x="' + CX + '" y="' + (CY + 1) + '" font-size="22" text-anchor="middle" dominant-baseline="central">' + EMOTION_CENTER.emoji + '</text>'
    + '</g>';
  var axisLabels = EMOTION_WHEEL.map(function(e) {
    var rad = e.angle * Math.PI / 180;
    var lr = 162;
    var x = CX + lr * Math.cos(rad);
    var y = CY + lr * Math.sin(rad);
    return '<text x="' + x + '" y="' + (y + 1) + '" font-size="15" font-weight="800" text-anchor="middle" dominant-baseline="central" fill="' + e.color + '">' + e.char + '</text>';
  }).join('');
  var thumbDefs = ''
    + '<radialGradient id="emo-thumb-glow" cx="50%" cy="50%" r="50%">'
    +   '<stop offset="0%" stop-color="var(--accent)" stop-opacity="0.55"/>'
    +   '<stop offset="60%" stop-color="var(--accent)" stop-opacity="0.18"/>'
    +   '<stop offset="100%" stop-color="var(--accent)" stop-opacity="0"/>'
    + '</radialGradient>'
    + '<filter id="emo-thumb-blur" x="-50%" y="-50%" width="200%" height="200%">'
    +   '<feGaussianBlur stdDeviation="2.4"/>'
    + '</filter>';
  var thumb = '<g id="emo-thumb" pointer-events="none">'
    + '<circle class="emo-thumb-halo" cx="' + CX + '" cy="' + CY + '" r="34" fill="url(#emo-thumb-glow)"/>'
    + '<circle class="emo-thumb-ring"  cx="' + CX + '" cy="' + CY + '" r="22" fill="none" stroke="var(--accent)" stroke-opacity="0.35" stroke-width="1.5"/>'
    + '<circle class="emo-thumb-shell" cx="' + CX + '" cy="' + CY + '" r="16" fill="#FFFFFF" stroke="var(--accent)" stroke-width="3" filter="url(#emo-thumb-blur)" opacity="0.55"/>'
    + '<circle class="emo-thumb-body"  cx="' + CX + '" cy="' + CY + '" r="16" fill="#FFFFFF" stroke="var(--accent)" stroke-width="3"/>'
    + '<circle class="emo-thumb-core"  cx="' + CX + '" cy="' + CY + '" r="7"  fill="var(--accent)"/>'
    + '<circle class="emo-thumb-spark" cx="' + (CX - 2) + '" cy="' + (CY - 2) + '" r="2" fill="#FFFFFF" opacity="0.85"/>'
    + '</g>';
  return ''
    + '<div class="emo-wheel" id="emo-wheel" '
    +   'onpointerdown="emoWheelStart(event)" '
    +   'onpointermove="emoWheelDrag(event)" '
    +   'onpointerup="emoWheelEnd(event)" '
    +   'onpointercancel="emoWheelEnd(event)" '
    +   'role="slider" aria-label="' + _T('app.c27.dragToSelectEmotion') + '">'
    +   '<svg class="emo-wheel-svg" viewBox="0 0 ' + SIZE + ' ' + SIZE + '">'
    +     '<defs>' + defs + thumbDefs + '</defs>'
    +     sectors + rings + dividers + markers + centerMarker + axisLabels + thumb
    +   '</svg>'
    + '</div>'
    + '<div class="emo-strength" aria-hidden="true">'
    +   '<span class="emo-strength-label">' + _T('app.c27.calm') + '</span>'
    +   '<div class="emo-strength-track">'
    +     '<div class="emo-strength-fill" id="emo-strength-fill" style="width:0%"></div>'
    +   '</div>'
    +   '<span class="emo-strength-label">' + _T('app.c27.veryIntense') + '</span>'
    + '</div>';
}

function _emoSlicePath(cx, cy, r, startAngle, endAngle) {
  var s = startAngle * Math.PI / 180;
  var e = endAngle * Math.PI / 180;
  var x1 = cx + r * Math.cos(s), y1 = cy + r * Math.sin(s);
  var x2 = cx + r * Math.cos(e), y2 = cy + r * Math.sin(e);
  var large = (endAngle - startAngle) > 180 ? 1 : 0;
  return 'M ' + cx + ' ' + cy + ' L ' + x1.toFixed(1) + ' ' + y1.toFixed(1)
    + ' A ' + r + ' ' + r + ' 0 ' + large + ' 1 ' + x2.toFixed(1) + ' ' + y2.toFixed(1) + ' Z';
}

var _emoDragging = false;
function emoWheelStart(ev) {
  _emoDragging = true;
  try { ev.currentTarget.setPointerCapture(ev.pointerId); } catch (e) {}
  emoWheelDrag(ev);
  ev.preventDefault();
}
function emoWheelDrag(ev) {
  if (!_emoDragging) return;
  var wheel = document.getElementById('emo-wheel');
  if (!wheel) return;
  var rect = wheel.getBoundingClientRect();
  var px = (ev.clientX - rect.left) / rect.width * 320;
  var py = (ev.clientY - rect.top) / rect.height * 320;
  var dx = px - 160, dy = py - 160;
  var dist = Math.sqrt(dx * dx + dy * dy);
  if (dist < 38) {
    _emoMoveThumb(160, 160, 'var(--text-muted)');
    selectEmotionCell('center', 1);
    return;
  }
  var angle = Math.atan2(dy, dx) * 180 / Math.PI;
  var best = null, bestDiff = 999;
  EMOTION_WHEEL.forEach(function(e) {
    var diff = Math.abs(((angle - e.angle + 540) % 360) - 180);
    if (diff < bestDiff) { bestDiff = diff; best = e; }
  });
  if (!best) return;
  var ringIdx;
  if (dist < 80) ringIdx = 0;
  else if (dist < 120) ringIdx = 1;
  else ringIdx = 2;
  var ring = best.rings[ringIdx];
  var rad = best.angle * Math.PI / 180;
  var radius = [62, 100, 138][ringIdx];
  var tx = 160 + radius * Math.cos(rad);
  var ty = 160 + radius * Math.sin(rad);
  _emoMoveThumb(tx, ty, best.color);
  selectEmotionCell(best.id, ring.score);
}
function emoWheelEnd(ev) {
  _emoDragging = false;
  try { ev.currentTarget.releasePointerCapture(ev.pointerId); } catch (e) {}
}
function _emoMoveThumb(x, y, emotionColor) {
  var thumb = document.getElementById('emo-thumb');
  if (!thumb) return;
  // spark 點位置略偏左上，跟主圓微錯位營造高光
  thumb.querySelectorAll('circle').forEach(function(c) {
    if (c.classList && c.classList.contains('emo-thumb-spark')) {
      c.setAttribute('cx', x - 2);
      c.setAttribute('cy', y - 2);
    } else {
      c.setAttribute('cx', x);
      c.setAttribute('cy', y);
    }
  });
  thumb.classList.add('is-active');
  if (emotionColor) {
    thumb.style.setProperty('--emo-thumb-c', emotionColor);
  }
  // 留下淡淡軌跡的小圓點
  _emoSpawnTrail(x, y, emotionColor);
  var dx = x - 160, dy = y - 160;
  var dist = Math.sqrt(dx * dx + dy * dy);
  // 半徑 0~138 → 強度條 0~100%
  var pct = dist < 38 ? 0 : Math.min(100, Math.round((dist - 38) / 100 * 100));
  var fill = document.getElementById('emo-strength-fill');
  if (fill) {
    fill.style.width = pct + '%';
    if (emotionColor) {
      fill.style.setProperty('--emo-fill-c', emotionColor);
    }
  }
}

function _emoSpawnTrail(x, y, color) {
  var wheel = document.getElementById('emo-wheel');
  if (!wheel) return;
  var rect = wheel.getBoundingClientRect();
  var dot = document.createElement('span');
  dot.className = 'emo-trail-dot';
  dot.style.left = (x / 320 * rect.width)  + 'px';
  dot.style.top  = (y / 320 * rect.height) + 'px';
  if (color) dot.style.background = color;
  wheel.appendChild(dot);
  setTimeout(function() { if (dot.parentNode) dot.parentNode.removeChild(dot); }, 500);
}

function _moodPercent(score) {
  if (score == null) return null;
  // score 1~5 → 0%~100%（線性）
  return Math.round((Math.max(1, Math.min(5, score)) - 1) * 25);
}

function _moodColor(score) {
  if (score == null) return 'transparent';
  var rounded = Math.max(1, Math.min(5, Math.round(score)));
  var lvl = EMOTION_LEVELS.find(function(l) { return l.score === rounded; });
  return lvl ? lvl.color : '#D6CFC2';
}

function _moodEmoji(score) {
  if (score == null) return '';
  var rounded = Math.max(1, Math.min(5, Math.round(score)));
  var lvl = EMOTION_LEVELS.find(function(l) { return l.score === rounded; });
  return lvl ? lvl.emoji : '';
}

// SVG 電池圖示，依 percent 0-100 填充
function _batteryGlyph(percent, color) {
  var p = Math.max(0, Math.min(100, percent || 0));
  var fillW = 24 * (p / 100);
  return '<svg class="mood-batt" viewBox="0 0 32 18" aria-hidden="true">' +
    '<rect x="1" y="2" width="26" height="14" rx="2.5" ry="2.5" fill="none" stroke="currentColor" stroke-width="1.6"/>' +
    '<rect x="28" y="6" width="3" height="6" rx="1" fill="currentColor"/>' +
    '<rect x="2.5" y="3.5" width="' + fillW + '" height="11" rx="1.5" fill="' + (color || 'currentColor') + '"/>' +
  '</svg>';
}

